const GRAVITY = 9.81; // m/s²
const KNOTS_TO_MS = 1.94384; // Conversion factor: 1 m/s = 1.94384 knots
const TRAINER_STALL_LIMIT_KTS = 61; // Typical limit for normal category trainer certification

