interface CalculationResult {
  weightN: number;
  wingLoadingNm2: number;
  wingLoadingKgm2: number;
  wingAreaM2: number;
  stallSpeedMs: number;
  stallSpeedKts: number;
  wsClass: WingLoadingClass;
  vsClass: StallSpeedClass;
  interpretation: string;
  steps: string[];
  regulatoryWarning?: string;
  mtowWingLoadingKgm2?: number;
  landingWingLoadingKgm2?: number;
}

// ============================================================================
// PHYSICS FUNCTIONS
// ============================================================================

/**
 * Convert mass to weight
 */
function massToWeight(massKg: number): number {
  return massKg * GRAVITY;
}

/**
 * Calculate wing loading in N/m²
 */
function calculateWingLoadingNm2(weightN: number, wingAreaM2: number): number {
  if (wingAreaM2 <= 0) throw new Error("Wing area must be positive");
  return weightN / wingAreaM2;
}

/**
 * Calculate wing loading in kg/m²
 */
function calculateWingLoadingKgm2(weightN: number, wingAreaM2: number): number {
  if (wingAreaM2 <= 0) throw new Error("Wing area must be positive");
  return weightN / (GRAVITY * wingAreaM2);
}

/**
 * Calculate stall speed
 */
function calculateStallSpeed(weightN: number, wingAreaM2: number, airDensity: number, clMax: number): number {
  if (wingAreaM2 <= 0) throw new Error("Wing area must be positive");
  if (airDensity <= 0) throw new Error("Air density must be positive");
  if (clMax <= 0) throw new Error("CL,max must be positive");
  
  const term = (2 * weightN) / (airDensity * wingAreaM2 * clMax);
  if (term < 0) throw new Error("Cannot calculate stall speed: negative value under square root");
  
  return Math.sqrt(term);
}

/**
 * Convert m/s to knots
 */
function msToKnots(ms: number): number {
  return ms * KNOTS_TO_MS;
}

// ============================================================================
// CLASSIFICATION FUNCTIONS
// ============================================================================

// Helper to get mission data, using Trainer as default for 'None'
function getMissionData(missionType: MissionType): MissionParams {
  if (missionType === 'None') {
    return missionData['Trainer']; // Use Trainer as default for calculations
  }
  return missionData[missionType];
}

/**
 * Classify wing loading based on mission type
 */
function classifyWingLoading(wsKgm2: number, missionType: MissionType): WingLoadingClass {
  const params = getMissionData(missionType);
  const lowLimit = 0.8 * params.wsMinKg;
  const highLimit = 1.2 * params.wsMaxKg;
  
  if (wsKgm2 < lowLimit) return 'Very Low';
  if (wsKgm2 < params.wsMinKg) return 'Low';
  if (wsKgm2 <= params.wsMaxKg) return 'Within';
  if (wsKgm2 <= highLimit) return 'High';
  return 'Very High';
}

/**
 * Classify stall speed based on mission type
 */
function classifyStallSpeed(vsMs: number, missionType: MissionType): StallSpeedClass {
  const params = getMissionData(missionType);
  
  if (vsMs < params.vsMin) return 'Low';
  if (vsMs <= params.vsMax) return 'Nominal';
  return 'High';
}

// ============================================================================
// INTERPRETATION FUNCTION
// ============================================================================

/**
 * Generate engineering interpretation based on mission type and classifications
 */
function generateInterpretation(
  missionType: MissionType,
  wsClass: WingLoadingClass,
  vsClass: StallSpeedClass,
  wsKgm2: number,
  vsMs: number,
  vsKts: number,
  clMax: number,
  clMaxIsOverridden: boolean = false
): { interpretation: string; regulatoryWarning?: string } {
  const params = getMissionData(missionType);
  let interpretation = "";
  let regulatoryWarning: string | undefined;
  
  // Regulatory check for Trainer mission
  if (missionType === 'Trainer' && vsKts > TRAINER_STALL_LIMIT_KTS) {
    regulatoryWarning = `⚠️ Stall speed (${vsKts.toFixed(1)} kts) exceeds typical ${TRAINER_STALL_LIMIT_KTS} kt limit used for normal category trainer certification. This may be unsuitable for a basic trainer role.`;
    interpretation += regulatoryWarning + "\n\n";
  } else if (missionType === 'Trainer' && vsKts < TRAINER_STALL_LIMIT_KTS - 5) {
    interpretation += "✓ Stall speed is compatible with typical trainer certification limits. ";
  }
  
  // Check for unrealistic CLmax
  if (clMaxIsOverridden && clMax > 3.5) {
    interpretation += "⚠️ Note: The specified CL,max is very high and may be unrealistic without exceptional high-lift devices. ";
  }
  
  // Base interpretation by mission type
  switch (missionType) {
    case 'UAV':
      if (wsClass === 'Very Low' || wsClass === 'Low') {
        interpretation += "This wing loading is well-suited for surveillance and loiter operations. ";
        interpretation += "The low wing loading provides excellent low-speed maneuverability and extended endurance. ";
        interpretation += "However, cruise speeds will be limited, and the aircraft will be more sensitive to turbulence. ";
      } else if (wsClass === 'Within') {
        interpretation += "This wing loading falls within typical UAV ranges. ";
        interpretation += "It offers a balanced compromise between low-speed performance and cruise efficiency. ";
        interpretation += "Stall behavior should be manageable with appropriate control systems. ";
      } else if (wsClass === 'High' || wsClass === 'Very High') {
        interpretation += "This wing loading is more suitable for fast dash missions rather than loiter. ";
        interpretation += "Higher cruise speeds are achievable, but low-speed handling and endurance will be reduced. ";
        interpretation += "Consider this configuration for aggressive mission profiles requiring rapid transit. ";
      }
      break;
      
    case 'Trainer':
      if (wsClass === 'Within') {
        interpretation += "This wing loading is ideal for primary training aircraft. ";
        interpretation += "It provides balanced handling characteristics with forgiving stall behavior. ";
        interpretation += "Takeoff and landing distances will be reasonable, and the aircraft will be stable for student pilots. ";
      } else if (wsClass === 'Very High' || wsClass === 'High') {
        interpretation += "This wing loading is higher than typical for primary trainers. ";
        interpretation += "The aircraft will behave more like a fast tourer or light GA aircraft. ";
        interpretation += "While still flyable, it may be less forgiving for primary training, with higher approach speeds and longer landing distances. ";
      } else if (wsClass === 'Very Low' || wsClass === 'Low') {
        interpretation += "This wing loading is very forgiving but comes with reduced cruise performance. ";
        interpretation += "Excellent for initial training, but students may not experience realistic cruise flight characteristics. ";
        interpretation += "Takeoff and landing will be very short, which is beneficial for training. ";
      }
      break;
      
    case 'STOL':
      if (wsClass === 'High' || wsClass === 'Very High') {
        interpretation += "⚠️ This wing loading is much higher than typical for STOL aircraft and defeats the STOL intent unless very high CL,max and higher stall speeds are acceptable. ";
        interpretation += "STOL aircraft typically require low wing loading for short takeoff and landing distances. ";
        interpretation += "With this configuration, you'll need exceptional high-lift devices (flaps, slats) to maintain STOL performance. ";
        if (clMaxIsOverridden && clMax < 2.5) {
          interpretation += "The current CL,max may be insufficient to compensate for the high wing loading. ";
        }
      } else if (wsClass === 'Within' || wsClass === 'Low') {
        interpretation += "This wing loading is appropriate for STOL operations. ";
        interpretation += "Short takeoff and landing distances are achievable with the specified CL,max. ";
        interpretation += "The aircraft will have good low-speed handling and maneuverability. ";
      } else {
        interpretation += "Very low wing loading provides exceptional STOL performance. ";
        interpretation += "Takeoff and landing distances will be minimal, but cruise performance will be limited. ";
      }
      break;
      
    case 'Glider':
      if (wsClass === 'Within') {
        interpretation += "This wing loading is typical for club gliders. ";
        interpretation += "It provides a good balance between thermal performance and cruise efficiency. ";
        interpretation += "Sink rate will be moderate, allowing for effective thermal climbing. ";
      } else if (wsClass === 'High' && wsKgm2 <= params.wsMaxKg * 1.2) {
        interpretation += "Higher wing loading within the glider range improves cruise speed between thermals. ";
        interpretation += "However, sink rate will be higher, requiring stronger thermals for sustained flight. ";
        interpretation += "This configuration is better suited for cross-country gliding. ";
      } else if (wsClass === 'Very Low') {
        interpretation += "Very low wing loading is overly draggy and not realistic for performance gliders. ";
        interpretation += "While sink rate will be low, cruise performance will be poor. ";
        interpretation += "This configuration is more typical of training gliders. ";
      }
      break;
      
    case 'Jet':
      if (wsClass === 'Very Low') {
        interpretation += "This wing loading is unusually low for a jet aircraft. ";
        interpretation += "It's closer to turboprop or trainer regimes. ";
        interpretation += "While it provides excellent low-speed handling, it may not be optimal for typical jet mission profiles. ";
      } else if (wsClass === 'Within' || wsClass === 'High') {
        interpretation += "This wing loading is typical for jet transports and fighters. ";
        interpretation += "Higher approach speeds are normal for this class of aircraft. ";
        interpretation += "The configuration provides good cruise efficiency and smooth ride in turbulence. ";
        interpretation += "Takeoff and landing distances will be longer than lighter aircraft, which is expected. ";
      } else if (wsClass === 'Very High') {
        interpretation += "Very high wing loading is characteristic of high-performance military jets. ";
        interpretation += "This configuration prioritizes high-speed cruise and maneuverability. ";
        interpretation += "Approach speeds will be high, and the aircraft will be demanding near stall. ";
      }
      break;
  }
  
  // Add stall speed interpretation
  if (vsClass === 'Low') {
    interpretation += "\n\nStall Speed: The calculated stall speed is below typical for this mission type. ";
    interpretation += "This indicates very forgiving stall characteristics, which is beneficial for safety. ";
  } else if (vsClass === 'Nominal') {
    interpretation += "\n\nStall Speed: The calculated stall speed falls within the expected range for this mission type. ";
    interpretation += "This is appropriate for the specified wing loading and CL,max. ";
  } else if (vsClass === 'High') {
    interpretation += "\n\nStall Speed: The calculated stall speed is above typical for this mission type. ";
    interpretation += "This will result in higher approach speeds and longer landing distances. ";
    interpretation += "Pilot workload will be higher, especially during approach and landing phases. ";
  }
  
  // Add runway/field suitability
  if ((wsClass === 'Very Low' || wsClass === 'Low') && vsClass === 'Low') {
    interpretation += "\n\nRunway Suitability: This configuration suggests operations from relatively short or unprepared airstrips may be feasible (subject to detailed performance analysis). ";
  } else if ((wsClass === 'High' || wsClass === 'Very High') && vsClass === 'High') {
    interpretation += "\n\nRunway Suitability: This configuration is more suited to paved or longer runways typical of larger aerodromes. ";
  }
  
  // Add trade-offs summary
  interpretation += "\n\nTrade-offs Summary:\n";
  if (wsClass === 'Very Low' || wsClass === 'Low') {
    interpretation += "✓ Short takeoff/landing distances\n";
    interpretation += "✓ Good low-speed maneuverability\n";
    interpretation += "✓ Softer stall behavior\n";
    interpretation += "✗ Larger wing area → higher drag\n";
    interpretation += "✗ Lower cruise speed\n";
    interpretation += "✗ More sensitive to turbulence\n";
  } else if (wsClass === 'High' || wsClass === 'Very High') {
    interpretation += "✓ Smoother ride in turbulence\n";
    interpretation += "✓ Higher cruise speed for same CL\n";
    interpretation += "✗ Higher stall speed\n";
    interpretation += "✗ Longer takeoff/landing distances\n";
    interpretation += "✗ More demanding near stall\n";
  } else {
    interpretation += "✓ Balanced performance characteristics\n";
    interpretation += "✓ Reasonable takeoff/landing distances\n";
    interpretation += "✓ Moderate cruise performance\n";
  }
  
  return { interpretation, regulatoryWarning };
}

/**
 * Generate Best Use Case / Mission Fit recommendation
 */
function generateBestUseCase(
  missionType: MissionType,
  wsClass: WingLoadingClass,
  vsClass: StallSpeedClass,
  wsKgm2: number,
  vsMs: number,
  vsKts: number
): string {
  // If mission is None, provide general suggestions
  if (missionType === 'None') {
    if (wsClass === 'Very Low' || wsClass === 'Low') {
      if (vsClass === 'Low' || vsClass === 'Nominal') {
        return "This configuration is similar to STOL or slow UAV designs. Good for short takeoff/landing operations, training approach speeds, and low-speed surveillance missions.";
      } else {
        return "This configuration shows low wing loading but higher stall speed, suggesting a design optimized for low-speed operations with moderate approach speeds.";
      }
    } else if (wsClass === 'High' || wsClass === 'Very High') {
      if (vsClass === 'High') {
        return "This configuration is more suitable for Jet or high-speed cruise aircraft. Longer runway needed, typical of transport or regional jet designs.";
      } else {
        return "This configuration shows high wing loading with moderate stall speed, suggesting efficient cruise performance with reasonable approach characteristics.";
      }
    } else {
      // Within range
      if (vsClass === 'Low' || vsClass === 'Nominal') {
        return "This configuration is similar to Trainer or STOL aircraft. Balanced design suitable for training, utility, or general aviation applications.";
      } else {
        return "This configuration shows moderate wing loading with higher stall speed, typical of advanced trainers or light utility aircraft.";
      }
    }
  }
  
  // Mission-specific recommendations
  const params = getMissionData(missionType);
  const wsWithinRange = wsKgm2 >= params.wsMinKg && wsKgm2 <= params.wsMaxKg;
  const vsWithinRange = vsMs >= params.vsMin && vsMs <= params.vsMax;
  
  if (wsWithinRange && vsWithinRange) {
    return `Configuration aligns with ${missionType} standards. Wing loading and stall speed are within typical ranges for this mission type.`;
  }
  
  // Mismatch cases
  let mismatchReasons: string[] = [];
  if (!wsWithinRange) {
    if (wsKgm2 < params.wsMinKg) {
      mismatchReasons.push("wing loading is below typical range");
    } else {
      mismatchReasons.push("wing loading exceeds typical range");
    }
  }
  if (!vsWithinRange) {
    if (vsMs < params.vsMin) {
      mismatchReasons.push("stall speed is below typical range");
    } else {
      mismatchReasons.push("stall speed exceeds typical range");
    }
  }
  
  return `Not ideal for ${missionType} mission, due to ${mismatchReasons.join(' and ')}. Consider adjusting wing area, weight, or CL,max to better match ${missionType} requirements.`;
}

// ============================================================================
// MAIN COMPONENT
// ============================================================================

const WingLoadingCalculator = () => {
  const { toast } = useToast();
  const { updateToolContext, sendCalculationEvent } = useToolContext();
  const { data: designSession, updateDesignSession } = useDesignSession();
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const [lastRequestId, setLastRequestId] = useState<string | null>(null);
  
  // Required fields for this calculator
  const requiredFields = [FIELD_KEYS.massKg, FIELD_KEYS.weightN, 'missionType'];
  
  // State
  const [unitSystem, setUnitSystem] = useState<UnitSystem>('SI');
  const [calculatorMode, setCalculatorMode] = useState<CalculatorMode>('University');
  const [aircraftPreset, setAircraftPreset] = useState<AircraftPreset>('none');
  const [missionType, setMissionType] = useState<MissionType>('Trainer');
  const [weightMode, setWeightMode] = useState<WeightMode>('mass');
  const [massKg, setMassKg] = useState<string>("");
  const [weightN, setWeightN] = useState<string>("");
  const [wingAreaM2, setWingAreaM2] = useState<string>("");
  const [airDensityMode, setAirDensityMode] = useState<AirDensityMode>('preset');
  const [airDensityPreset, setAirDensityPreset] = useState<AirDensityPreset>('ISA Sea Level');
  const [airDensityAltitude, setAirDensityAltitude] = useState<string>("0");
  const [airDensityDeltaT, setAirDensityDeltaT] = useState<string>("0");
  const [airDensityCustom, setAirDensityCustom] = useState<string>("1.225");
  const [clMaxOverride, setClMaxOverride] = useState<string>("");
  const [useClMaxOverride, setUseClMaxOverride] = useState(false);
  const [mtow, setMtow] = useState<string>("");
  const [landingWeightFraction, setLandingWeightFraction] = useState<string>("0.7");
  const [result, setResult] = useState<CalculationResult | null>(null);
  const [lastPayload, setLastPayload] = useState<unknown | null>(null);
  
  // Handle return flow - redirect back after calculation if returnTo is present
  useEffect(() => {
    const returnTo = searchParams.get('returnTo');
    const referrer = searchParams.get('referrer');
    
    // Only redirect if we have a result AND returnTo param (user came from another calculator)
    if (returnTo && result && referrer && result.wingLoadingKgm2) {
      // After calculation completes and designSession is updated, redirect back
      const returnPath = `${returnTo}${returnTo.includes('?') ? '&' : '?'}importFrom=${referrer}`;
      // Small delay to ensure designSession is updated
      const timeoutId = setTimeout(() => {
        navigate(returnPath, { replace: true });
      }, 1000);
      
      return () => clearTimeout(timeoutId);
    }
  }, [result, searchParams, navigate]);
  
  // Load from localStorage
  useEffect(() => {
    const stored = localStorage.getItem("wingLoadingCalc_state");
    if (stored) {
      try {
        const state = JSON.parse(stored);
        setUnitSystem(state.unitSystem || 'SI');
        setCalculatorMode(state.calculatorMode || 'University');
        setAircraftPreset(state.aircraftPreset || 'none');
        setMissionType(state.missionType || 'Trainer');
        setWeightMode(state.weightMode || 'mass');
        setMassKg(state.massKg || "");
        setWeightN(state.weightN || "");
        setWingAreaM2(state.wingAreaM2 || "");
        setAirDensityMode(state.airDensityMode || 'preset');
        setAirDensityPreset(state.airDensityPreset || 'ISA Sea Level');
        setAirDensityAltitude(state.airDensityAltitude || "0");
        setAirDensityDeltaT(state.airDensityDeltaT || "0");
        setAirDensityCustom(state.airDensityCustom || "1.225");
        setClMaxOverride(state.clMaxOverride || "");
        setUseClMaxOverride(state.useClMaxOverride || false);
        setMtow(state.mtow || "");
        setLandingWeightFraction(state.landingWeightFraction || "0.7");
      } catch (e) {
        console.warn("Failed to load state:", e);
      }
    }
  }, []);
  
  // Save to localStorage
  useEffect(() => {
    const state = {
      unitSystem,
      calculatorMode,
      aircraftPreset,
      missionType,
      weightMode,
      massKg,
      weightN,
      wingAreaM2,
      airDensityMode,
      airDensityPreset,
      airDensityAltitude,
      airDensityDeltaT,
      airDensityCustom,
      clMaxOverride,
      useClMaxOverride,
      mtow,
      landingWeightFraction
    };
    localStorage.setItem("wingLoadingCalc_state", JSON.stringify(state));
  }, [unitSystem, calculatorMode, aircraftPreset, missionType, weightMode, massKg, weightN, wingAreaM2, airDensityMode, airDensityPreset, airDensityAltitude, airDensityDeltaT, airDensityCustom, clMaxOverride, useClMaxOverride, mtow, landingWeightFraction]);
  
  // Handle aircraft preset selection
  const handleAircraftPresetChange = (preset: AircraftPreset) => {
    setAircraftPreset(preset);
    if (preset !== 'none') {
      const aircraft = AIRCRAFT_PRESETS[preset];
      // Only auto-change mission type if it's not set to 'None (Manual)'
      if (missionType !== 'None') {
        setMissionType(aircraft.missionType);
      }
      
      // Convert to display units
      const massDisplay = convertMassFromSI(aircraft.mtowKg, unitSystem);
      const areaDisplay = convertAreaFromSI(aircraft.wingAreaM2, unitSystem);
      
      setMassKg(massDisplay.toFixed(2));
      setWeightN(""); // Clear weight if in mass mode
      setWingAreaM2(areaDisplay.toFixed(2));
    }
  };
  
  // Get current air density
  const currentAirDensity = useMemo(() => {
    if (airDensityMode === 'custom') {
      const custom = parseFloat(airDensityCustom);
      return isNaN(custom) || custom <= 0 ? 1.225 : custom;
    } else if (airDensityMode === 'altitude') {
      const altitudeM = convertAltitudeToSI(parseFloat(airDensityAltitude) || 0, unitSystem);
      const deltaT = parseFloat(airDensityDeltaT) || 0;
      try {
        return calculateISADensity(altitudeM, deltaT);
      } catch (e) {
        return 1.225; // Fallback
      }
    } else {
      // Preset mode - map to altitude
      const preset = airDensityPreset;
      const altitudeM = getPresetAltitude(preset);
      return calculateISADensity(altitudeM, 0);
    }
  }, [airDensityMode, airDensityPreset, airDensityAltitude, airDensityDeltaT, airDensityCustom, unitSystem]);
  
  // Get CL,max for current mission type
  const currentClMax = useMemo(() => {
    const missionParams = getMissionData(missionType);
    if (useClMaxOverride && clMaxOverride) {
      const override = parseFloat(clMaxOverride);
      return isNaN(override) || override <= 0 ? missionParams.clMax : override;
    }
    return missionParams.clMax;
  }, [missionType, useClMaxOverride, clMaxOverride]);
  
  const clMaxIsOverridden = useClMaxOverride && clMaxOverride && parseFloat(clMaxOverride) > 0;
  
  // Get input/output units
  const inputUnits = useMemo(() => getInputUnits(unitSystem), [unitSystem]);
  const outputUnits = useMemo(() => getOutputUnits(unitSystem), [unitSystem]);
  
  // Calculate
  const handleCalculate = async () => {
    try {
      // Validate and convert inputs to SI
      const massInput = weightMode === 'mass' ? parseFloat(massKg) : null;
      const weightInput = weightMode === 'weight' ? parseFloat(weightN) : null;
      const areaInput = parseFloat(wingAreaM2);
      
      if (weightMode === 'mass' && (isNaN(massInput!) || massInput! <= 0)) {
        toast({ title: "Invalid Input", description: "Mass must be a positive number", variant: "destructive" });
        return;
      }
      if (weightMode === 'weight' && (isNaN(weightInput!) || weightInput! <= 0)) {
        toast({ title: "Invalid Input", description: "Weight must be a positive number", variant: "destructive" });
        return;
      }
      if (isNaN(areaInput) || areaInput <= 0) {
        toast({ title: "Invalid Input", description: "Wing area must be a positive number", variant: "destructive" });
        return;
      }

      // Convert to SI
      const massKgSI = weightMode === 'mass' ? convertMassToSI(massInput!, unitSystem) : null;
      const weightNSI = weightMode === 'weight' ? convertWeightToSI(weightInput!, unitSystem) : null;
      const areaM2SI = convertAreaToSI(areaInput, unitSystem);
      
      // Calculate weight in SI
      const finalWeightN = weightMode === 'mass' ? massToWeight(massKgSI!) : weightNSI!;
      
      // Calculate wing loading (always in SI internally)
      const wsNm2 = calculateWingLoadingNm2(finalWeightN, areaM2SI);
      const wsKgm2 = calculateWingLoadingKgm2(finalWeightN, areaM2SI);
      
      // Calculate stall speed
      const vsMs = calculateStallSpeed(finalWeightN, areaM2SI, currentAirDensity, currentClMax);
      const vsKts = msToKnots(vsMs);
      
      // Calculate MTOW and landing weight wing loadings if provided
      let mtowWingLoadingKgm2: number | undefined;
      let landingWingLoadingKgm2: number | undefined;
      if (mtow) {
        const mtowSI = weightMode === 'mass' 
          ? convertMassToSI(parseFloat(mtow), unitSystem)
          : convertWeightToSI(parseFloat(mtow), unitSystem);
        const mtowWeightN = weightMode === 'mass' ? massToWeight(mtowSI) : mtowSI;
        mtowWingLoadingKgm2 = calculateWingLoadingKgm2(mtowWeightN, areaM2SI);
        
        const landingFractionParsed = parseFloat(landingWeightFraction);
        const landingFraction = isNaN(landingFractionParsed) ? 0.7 : landingFractionParsed;
        const landingWeightN = mtowWeightN * landingFraction;
        landingWingLoadingKgm2 = calculateWingLoadingKgm2(landingWeightN, areaM2SI);
      }
      
      // Classify
      const wsClass = classifyWingLoading(wsKgm2, missionType);
      const vsClass = classifyStallSpeed(vsMs, missionType);
      
      // Generate interpretation
      const { interpretation, regulatoryWarning } = generateInterpretation(
        missionType, 
        wsClass, 
        vsClass, 
        wsKgm2, 
        vsMs, 
        vsKts,
        currentClMax,
        clMaxIsOverridden
      );
      
      // Generate step-by-step solution
      const steps: string[] = [];
      let stepNum = 1;
      
      if (weightMode === 'mass') {
        steps.push(`**Step ${stepNum}: Convert mass to weight**`);
        const massDisplay = unitSystem === 'SI' ? massKgSI!.toFixed(2) : massInput!.toFixed(2);
        steps.push(`W = m × g = ${massDisplay} ${inputUnits.mass} × ${GRAVITY} m/s² = ${finalWeightN.toFixed(2)} N`);
        stepNum++;
        } else {
        const weightDisplay = unitSystem === 'SI' ? weightNSI!.toFixed(2) : weightInput!.toFixed(2);
        steps.push(`**Step ${stepNum}: Weight**`);
        steps.push(`W = ${weightDisplay} ${inputUnits.weight} = ${finalWeightN.toFixed(2)} N (converted to SI)`);
        stepNum++;
      }
      
      steps.push(`**Step ${stepNum}: Compute W/S in N/m²**`);
      const areaDisplay = unitSystem === 'SI' ? areaM2SI.toFixed(2) : areaInput.toFixed(2);
      steps.push(`(W/S)_N = W / S = ${finalWeightN.toFixed(2)} N / ${areaDisplay} ${inputUnits.area} = ${wsNm2.toFixed(2)} N/m²`);
      stepNum++;
      
      steps.push(`**Step ${stepNum}: Convert to kg/m²**`);
      steps.push(`(W/S)_kg = W / (g × S) = ${finalWeightN.toFixed(2)} N / (${GRAVITY} m/s² × ${areaM2SI.toFixed(2)} m²) = ${wsKgm2.toFixed(2)} kg/m²`);
      stepNum++;
      
      steps.push(`**Step ${stepNum}: Compute stall speed**`);
      const clMaxLabel = clMaxIsOverridden ? "User-specified CL,max" : "Mission CL,max";
      steps.push(`Using ${clMaxLabel}: ${currentClMax.toFixed(2)}`);
      steps.push(`Air density: ${currentAirDensity.toFixed(3)} kg/m³${airDensityMode === 'altitude' ? ` (from altitude ${airDensityAltitude} ${inputUnits.altitude})` : ''}`);
      steps.push(`V_s = √[2W / (ρ × S × CL,max)] = √[2 × ${finalWeightN.toFixed(2)} N / (${currentAirDensity.toFixed(3)} kg/m³ × ${areaM2SI.toFixed(2)} m² × ${currentClMax.toFixed(2)})]`);
      steps.push(`V_s = ${vsMs.toFixed(2)} m/s = ${vsKts.toFixed(2)} knots`);
      stepNum++;
      
      steps.push(`**Step ${stepNum}: Compare against mission envelope**`);
      if (missionType !== 'None') {
        const params = getMissionData(missionType);
        steps.push(`Typical ${missionType} wing loading: ${params.wsMinKg}–${params.wsMaxKg} kg/m²`);
      } else {
        steps.push(`Manual mode: No mission-specific ranges applied`);
      }
      steps.push(`Current W/S: ${wsKgm2.toFixed(2)} kg/m² → Classification: ${wsClass}`);
      if (missionType !== 'None') {
        const params = getMissionData(missionType);
        steps.push(`Typical ${missionType} stall speed: ${params.vsMin}–${params.vsMax} m/s`);
      }
      steps.push(`Current V_s: ${vsMs.toFixed(2)} m/s → Classification: ${vsClass}`);
      
      const calculationResult: CalculationResult = {
        weightN: finalWeightN,
        wingLoadingNm2: wsNm2,
        wingLoadingKgm2: wsKgm2,
        wingAreaM2: areaM2SI,
        stallSpeedMs: vsMs,
        stallSpeedKts: vsKts,
        wsClass,
        vsClass,
        interpretation,
        steps,
        regulatoryWarning,
        mtowWingLoadingKgm2,
        landingWingLoadingKgm2
      };
      
      setResult(calculationResult);
      
      // Update design session after successful calculation
      if (Number.isFinite(finalWeightN) && Number.isFinite(areaM2SI) && Number.isFinite(wsKgm2) && Number.isFinite(vsMs)) {
        const massKgValue = weightMode === 'mass' ? massKgSI! : undefined;
        updateDesignSession({
          massKg: massKgValue,
          weightN: finalWeightN,
          wingAreaM2: areaM2SI,
          wingLoadingKgm2: wsKgm2,
          missionType: missionType !== 'None' ? missionType : undefined,
          densityKgM3: currentAirDensity,
          clMaxUsed: currentClMax,
          stallSpeedMs: vsMs,
          stallSpeedKts: vsKts,
        });
      }
      
      // Send calculation event
        const toolInputs = {
          unitSystem,
        missionType,
        weightMode,
        massKg: weightMode === 'mass' ? massInput : null,
        weightN: weightMode === 'weight' ? weightInput : null,
        wingAreaM2: areaInput,
        airDensityMode,
        airDensity: currentAirDensity,
        airDensityAltitude: airDensityMode === 'altitude' ? parseFloat(airDensityAltitude) : null,
        airDensityDeltaT: airDensityMode === 'altitude' ? parseFloat(airDensityDeltaT) : null,
        clMax: currentClMax,
        clMaxOverridden: clMaxIsOverridden,
        mtow: mtow ? parseFloat(mtow) : null,
        landingWeightFraction: mtow ? parseFloat(landingWeightFraction) : null
      };
      
        const toolResults = {
        wingLoadingNm2: wsNm2,
        wingLoadingKgm2: wsKgm2,
        stallSpeedMs: vsMs,
        stallSpeedKts: vsKts,
        wsClass,
        vsClass
      };
      
        const eventResponse = await sendCalculationEvent({
          toolId: "wing-loading-calculator",
          toolName: "Wing Loading Calculator",
          inputs: toolInputs,
          results: toolResults,
        steps: steps,
          metadata: {
            approxLevel: "exact",
            confidence: "high"
        }
        });

      if (eventResponse?.requestId) {
        setLastRequestId(eventResponse.requestId);
      }
      
        setLastPayload({
          tool: "Wing Loading Calculator",
          inputs: toolInputs,
        results: toolResults
        });

        updateToolContext({
          tool: "Wing Loading Calculator",
          inputs: toolInputs,
        results: toolResults
        });

    } catch (error) {
      toast({ 
        title: "Calculation Error", 
        description: (error as Error).message, 
        variant: "destructive" 
      });
    }
  };
  
  const handleReset = () => {
    setAircraftPreset('none');
    setMassKg("");
    setWeightN("");
    setWingAreaM2("");
    setResult(null);
    setAirDensityMode('preset');
    setAirDensityPreset('ISA Sea Level');
    setAirDensityAltitude("0");
    setAirDensityDeltaT("0");
    setAirDensityCustom("1.225");
    setClMaxOverride("");
    setUseClMaxOverride(false);
    setMtow("");
    setLandingWeightFraction("0.7");
  };
  
  // Get classification color
  const getClassificationColor = (wsClass: WingLoadingClass): string => {
    switch (wsClass) {
      case 'Very Low': return 'text-blue-400';
      case 'Low': return 'text-cyan-400';
      case 'Within': return 'text-green-400';
      case 'High': return 'text-yellow-400';
      case 'Very High': return 'text-orange-400';
    }
  };
  
  // Calculate position on mission envelope bar
  const getEnvelopePosition = (): number => {
    if (!result) return 0;
    if (missionType === 'None') return 50; // Fallback for None
    const params = getMissionData(missionType);
    const extendedMin = 0.8 * params.wsMinKg;
    const extendedMax = 1.2 * params.wsMaxKg;
    const extendedRange = extendedMax - extendedMin;
    
    if (extendedRange <= 0) return 50; // Fallback
    
    // Clamp to extended range
    const clamped = Math.max(extendedMin, Math.min(extendedMax, result.wingLoadingKgm2));
    const position = ((clamped - extendedMin) / extendedRange) * 100;
    return Math.max(0, Math.min(100, position));
  };
  
  // Calculate range bar position
  const getRangeBarPosition = (): { left: number; width: number } => {
    if (missionType === 'None') return { left: 40, width: 20 }; // Fallback for None
    const params = getMissionData(missionType);
    const extendedMin = 0.8 * params.wsMinKg;
    const extendedMax = 1.2 * params.wsMaxKg;
    const extendedRange = extendedMax - extendedMin;
    
    if (extendedRange <= 0) return { left: 0, width: 100 };
    
    const rangeMin = params.wsMinKg;
    const rangeMax = params.wsMaxKg;
    const left = ((rangeMin - extendedMin) / extendedRange) * 100;
    const width = ((rangeMax - rangeMin) / extendedRange) * 100;
    
    return { left: Math.max(0, left), width: Math.max(0, Math.min(100, width)) };
  };
  
  return (
    <ToolWrapper>
      <ToolHeader
        title="Wing Loading Calculator"
        description="Calculate wing loading and stall speed with mission-specific classification and engineering interpretations"
        icon={Plane}
        actions={
          <ToolActions>
            <Select value={unitSystem} onValueChange={(v) => setUnitSystem(v as UnitSystem)}>
              <SelectTrigger className="w-32 bg-slate-900/50 border-cyan-400/30 text-cyan-400">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="SI">SI</SelectItem>
                <SelectItem value="Imperial">Imperial</SelectItem>
              </SelectContent>
            </Select>
            <AeroButton type="button" onClick={handleReset} variant="outline">
              Reset
            </AeroButton>
            {lastRequestId && lastPayload && (
              <>
                <AskAIButton
                  requestId={lastRequestId}
                  payload={buildAeroversePayload({
                    toolName: (lastPayload as { tool?: string }).tool || 'Wing Loading Calculator',
                    requestId: lastRequestId || undefined,
                    inputs: (lastPayload as { inputs?: Record<string, unknown> }).inputs,
                    results: (lastPayload as { results?: Record<string, unknown> }).results,
                  })}
                  disabled={!lastPayload}
                />
                <PDFExportButton
                  requestId={lastRequestId}
                  toolName="Wing Loading Calculator"
                  disabled={!lastRequestId}
                />
              </>
            )}
          </ToolActions>
        }
      />

      <ToolSection gridCols={2}>
        {/* LEFT COLUMN: INPUTS */}
        <div>
          <div className={spacingVertical.L}>
            {/* Row 1: Calculator Mode and Mission Type side-by-side */}
            <div className="grid grid-cols-1 gap-4 md:grid-cols-2">
              {/* Mode Selector */}
              <AeroCard
                title="Calculator Mode"
                description="Select complexity level (calculations remain identical)"
                icon={Settings2}
              >
                <AeroFormField label="Mode">
                  <Select value={calculatorMode} onValueChange={(v) => setCalculatorMode(v as CalculatorMode)}>
                    <SelectTrigger className="w-full bg-slate-900/50 border-cyan-400/30 text-cyan-400">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="Beginner">Beginner</SelectItem>
                      <SelectItem value="University">University</SelectItem>
                      <SelectItem value="Expert">Expert</SelectItem>
                    </SelectContent>
                  </Select>
                </AeroFormField>
                <div className="mt-2 p-2 bg-slate-900/50 rounded border border-cyan-400/20">
                  <p className="text-xs text-gray-300">
                    {calculatorMode === 'Beginner' && 'Simplified interface with essential features only.'}
                    {calculatorMode === 'University' && 'Standard features with full functionality.'}
                    {calculatorMode === 'Expert' && 'All features including advanced settings and ISA deviation.'}
                  </p>
                </div>
              </AeroCard>
              
              {/* Mission Type Selection */}
              <AeroCard
                title="Mission Type"
                description="Select aircraft mission type to auto-adapt CL,max and classification ranges"
                icon={Plane}
              >
                <AeroFormField label="Mission Type">
                  <Select value={missionType} onValueChange={(v) => setMissionType(v as MissionType)}>
                    <SelectTrigger className="w-full bg-slate-900/50 border-cyan-400/30 text-cyan-400">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="None">None (Manual)</SelectItem>
                      <SelectItem value="UAV">UAV</SelectItem>
                      <SelectItem value="Trainer">Trainer</SelectItem>
                      <SelectItem value="STOL">STOL</SelectItem>
                      <SelectItem value="Glider">Glider</SelectItem>
                      <SelectItem value="Jet">Jet</SelectItem>
                    </SelectContent>
                  </Select>
                </AeroFormField>
                {missionType !== 'None' && (
                  <div className="mt-4 p-3 bg-slate-900/50 rounded-lg border border-cyan-400/20">
                    <p className="text-sm text-gray-300">
                      <span className="text-cyan-400 font-semibold">CL,max:</span> {currentClMax.toFixed(2)}
                    </p>
                    <p className="text-sm text-gray-300 mt-1">
                      <span className="text-cyan-400 font-semibold">Typical W/S:</span> {getMissionData(missionType).wsMinKg}–{getMissionData(missionType).wsMaxKg} kg/m²
                    </p>
                    <p className="text-sm text-gray-300 mt-1">
                      <span className="text-cyan-400 font-semibold">Typical V_s:</span> {getMissionData(missionType).vsMin}–{getMissionData(missionType).vsMax} m/s
                    </p>
                  </div>
                )}
                {missionType === 'None' && (
                  <div className="mt-4 p-3 bg-slate-900/50 rounded-lg border border-cyan-400/20">
                    <p className="text-sm text-gray-300">
                      Mission-specific parameters will not auto-change. Use manual CL,max override if needed.
                    </p>
                  </div>
                )}
              </AeroCard>
            </div>
            
            {/* Row 2: Aircraft Preset full-width */}
            <AeroCard
              title="Aircraft Preset"
              description="Select a real-world aircraft to auto-fill mission type, mass, and wing area"
              icon={Plane}
            >
              <AeroFormField label="Aircraft Preset">
                <Select value={aircraftPreset} onValueChange={(v) => handleAircraftPresetChange(v as AircraftPreset)}>
                  <SelectTrigger className="w-full bg-slate-900/50 border-cyan-400/30 text-cyan-400">
                    <SelectValue placeholder="Select aircraft preset (optional)" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="none">None (Manual Entry)</SelectItem>
                    <SelectItem value="smallRCUAV">{AIRCRAFT_PRESETS.smallRCUAV.name}</SelectItem>
                    <SelectItem value="cessna172">{AIRCRAFT_PRESETS.cessna172.name}</SelectItem>
                    <SelectItem value="ask21">{AIRCRAFT_PRESETS.ask21.name}</SelectItem>
                    <SelectItem value="stolBush">{AIRCRAFT_PRESETS.stolBush.name}</SelectItem>
                    <SelectItem value="maleUAV">{AIRCRAFT_PRESETS.maleUAV.name}</SelectItem>
                    <SelectItem value="narrowbodyAirliner">{AIRCRAFT_PRESETS.narrowbodyAirliner.name}</SelectItem>
                    <SelectItem value="highPerfJet">{AIRCRAFT_PRESETS.highPerfJet.name}</SelectItem>
                  </SelectContent>
                </Select>
              </AeroFormField>
              {aircraftPreset !== 'none' && (
                <div className="mt-2 p-2 bg-slate-900/50 rounded border border-cyan-400/20">
                  <p className="text-xs text-gray-300">
                    {AIRCRAFT_PRESETS[aircraftPreset].description}
                  </p>
                </div>
              )}
            </AeroCard>

            {/* Weight/Mass Input */}
            <AeroCard
              title="Aircraft Weight/Mass"
              description="Enter either mass (kg) or weight (N) for the flight condition of interest"
              icon={Anchor}
            >
              <div className="flex items-center gap-3 mb-4">
                <Label className="text-sm text-gray-300">Input Mode:</Label>
                <div className="flex items-center gap-2">
                  <span className={`text-sm ${weightMode === 'mass' ? 'text-cyan-400' : 'text-gray-500'}`}>Mass (kg)</span>
                  <Switch
                    checked={weightMode === 'weight'}
                    onCheckedChange={(checked) => setWeightMode(checked ? 'weight' : 'mass')}
                  />
                  <span className={`text-sm ${weightMode === 'weight' ? 'text-cyan-400' : 'text-gray-500'}`}>Weight (N)</span>
              </div>
              </div>
              {weightMode === 'mass' ? (
                <AeroFormField 
                  label={`Aircraft Mass (${inputUnits.mass})`} 
                  helperText={`Aircraft mass for the flight condition (typically MTOW or operating weight). Mass is converted to weight using g = ${GRAVITY} m/s².`}
                >
                  <Input
                    type="number"
                    step="0.01"
                    value={massKg}
                    onChange={(e) => setMassKg(e.target.value)}
                    className="bg-slate-900/50 border-cyan-400/30"
                    placeholder={`e.g., ${unitSystem === 'SI' ? '10000' : '22046'}`}
                    min="0"
                  />
                  {massKg.trim() && (() => {
                    const val = parseFloat(massKg);
                    if (!isNaN(val) && isFinite(val)) {
                      if (val <= 0) {
                        return <p className="text-xs text-yellow-400 mt-1">Warning: Mass must be positive</p>;
                      }
                      if (val > 1e6) {
                        return <p className="text-xs text-yellow-400 mt-1">Warning: Mass value is very large</p>;
                      }
                    } else if (massKg.trim() && (isNaN(val) || !isFinite(val))) {
                      return <p className="text-xs text-yellow-400 mt-1">Warning: Invalid number</p>;
                    }
                    return null;
                  })()}
              </AeroFormField>
              ) : (
                <AeroFormField 
                  label={`Aircraft Weight (${inputUnits.weight})`} 
                  helperText={`Aircraft weight for the flight condition (typically MTOW or operating weight). Weight = mass × g, where g = ${GRAVITY} m/s² (standard gravity).`}
                >
                  <Input
                    type="number"
                    step="0.01"
                    value={weightN}
                    onChange={(e) => setWeightN(e.target.value)}
                    className="bg-slate-900/50 border-cyan-400/30"
                    placeholder={`e.g., ${unitSystem === 'SI' ? '98100' : '22046'}`}
                    min="0"
                  />
                  {weightN.trim() && (() => {
                    const val = parseFloat(weightN);
                    if (!isNaN(val) && isFinite(val)) {
                      if (val <= 0) {
                        return <p className="text-xs text-yellow-400 mt-1">Warning: Weight must be positive</p>;
                      }
                      if (val > 1e9) {
                        return <p className="text-xs text-yellow-400 mt-1">Warning: Weight value is very large</p>;
                      }
                    } else if (weightN.trim() && (isNaN(val) || !isFinite(val))) {
                      return <p className="text-xs text-yellow-400 mt-1">Warning: Invalid number</p>;
                    }
                    return null;
                  })()}
              </AeroFormField>
              )}
            </AeroCard>

            {/* Wing Area */}
            <AeroCard
              title="Wing Geometry"
              description="Enter gross wing area (total planform area)"
              icon={Gauge}
            >
              <AeroFormField 
                label={`Gross Wing Area (${inputUnits.area})`} 
                helperText={`Total wing planform area (S). Includes both wings if applicable. Typically measured from wing root to wingtip, excluding fuselage intersection. Used for wing loading calculation: W/S.`}
              >
                      <Input 
                  type="number"
                  step="0.01"
                  value={wingAreaM2}
                  onChange={(e) => setWingAreaM2(e.target.value)}
                  className="bg-slate-900/50 border-cyan-400/30"
                  placeholder={`e.g., ${unitSystem === 'SI' ? '30' : '323'}`}
                  min="0"
                />
                {wingAreaM2.trim() && (() => {
                  const val = parseFloat(wingAreaM2);
                  if (!isNaN(val) && isFinite(val)) {
                    if (val <= 0) {
                      return <p className="text-xs text-yellow-400 mt-1">Warning: Wing area must be positive</p>;
                    }
                    if (val > 1e6) {
                      return <p className="text-xs text-yellow-400 mt-1">Warning: Wing area value is very large</p>;
                    }
                  } else if (wingAreaM2.trim() && (isNaN(val) || !isFinite(val))) {
                    return <p className="text-xs text-yellow-400 mt-1">Warning: Invalid number</p>;
                  }
                  return null;
                })()}
              </AeroFormField>
            </AeroCard>
            
            {/* Air Density */}
            <AeroCard
              title="Air Density"
              description="Select mode: preset (ISA altitudes), altitude-based (ISA model), or custom density"
              icon={Wind}
            >
              <AeroFormField label="Air Density Mode">
                <Select value={airDensityMode} onValueChange={(v) => setAirDensityMode(v as AirDensityMode)}>
                  <SelectTrigger className="w-full bg-slate-900/50 border-cyan-400/30 text-cyan-400">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="preset">Preset (ISA altitudes)</SelectItem>
                    <SelectItem value="altitude">Altitude-based (ISA model)</SelectItem>
                    <SelectItem value="custom">Custom density</SelectItem>
                  </SelectContent>
                </Select>
              </AeroFormField>
              
              {airDensityMode === 'preset' && (
                <AeroFormField label="Altitude Preset">
                  <Select value={airDensityPreset} onValueChange={(v) => setAirDensityPreset(v as AirDensityPreset)}>
                    <SelectTrigger className="w-full bg-slate-900/50 border-cyan-400/30 text-cyan-400">
                      <SelectValue />
                    </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="ISA Sea Level">ISA Sea Level (0 ft)</SelectItem>
                    <SelectItem value="2000 ft">2000 ft</SelectItem>
                    <SelectItem value="5000 ft">5000 ft</SelectItem>
                    <SelectItem value="8000 ft">8000 ft</SelectItem>
                    <SelectItem value="10000 ft">10000 ft</SelectItem>
                    <SelectItem value="15000 ft">15000 ft</SelectItem>
                  </SelectContent>
                  </Select>
                  <p className="text-xs text-gray-400 mt-1">
                    ISA (International Standard Atmosphere) density at specified altitude. Used for stall speed calculation: V_s = √[2W/(ρSC_L,max)].
                  </p>
              </AeroFormField>
              )}
              
              {airDensityMode === 'altitude' && (
                <>
                  <AeroFormField 
                    label={`Flight Altitude (${inputUnits.altitude})`} 
                    helperText={`Geopotential altitude above MSL (Mean Sea Level) for ISA density calculation. Reference: ISA 1976 standard.`}
                  >
                    <Input
                      type="number"
                      step="0.01"
                      value={airDensityAltitude}
                      onChange={(e) => setAirDensityAltitude(e.target.value)}
                      className="bg-slate-900/50 border-cyan-400/30"
                      placeholder={`e.g., ${unitSystem === 'SI' ? '0' : '0'}`}
                    />
              </AeroFormField>
                  <AeroFormField 
                    label="Temperature Deviation (ΔT, K)" 
                    helperText={`Optional: Deviation from ISA temperature at this altitude. Positive = warmer than ISA, negative = colder. Used to adjust density: ρ = ρ_ISA × (T_ISA / T_actual).`}
                  >
                    <Input
                      type="number"
                      step="0.1"
                      value={airDensityDeltaT}
                      onChange={(e) => setAirDensityDeltaT(e.target.value)}
                      className="bg-slate-900/50 border-cyan-400/30"
                      placeholder="e.g., 0"
                    />
              </AeroFormField>
                </>
              )}
              
              {airDensityMode === 'custom' && (
                <AeroFormField 
                  label="Custom Air Density (kg/m³)"
                  helperText="Enter air density directly. Typical values: 1.225 kg/m³ (sea level ISA), 1.112 kg/m³ (2000 ft ISA), 0.736 kg/m³ (10000 ft ISA). Used for stall speed calculation."
                >
                      <Input 
                        type="number"
                        name="densityKgM3"
                    step="0.001"
                    value={airDensityCustom}
                    onChange={(e) => setAirDensityCustom(e.target.value)}
                    className="bg-slate-900/50 border-cyan-400/30"
                    placeholder="e.g., 1.225"
                    min="0"
                  />
                  {airDensityCustom.trim() && (() => {
                    const val = parseFloat(airDensityCustom);
                    if (!isNaN(val) && isFinite(val)) {
                      if (val <= 0) {
                        return <p className="text-xs text-yellow-400 mt-1">Warning: Air density must be positive</p>;
                      }
                      if (val < 0.01 || val > 2.0) {
                        return <p className="text-xs text-yellow-400 mt-1">Warning: Air density outside typical range (0.01-2.0 kg/m³)</p>;
                      }
                    } else if (airDensityCustom.trim() && (isNaN(val) || !isFinite(val))) {
                      return <p className="text-xs text-yellow-400 mt-1">Warning: Invalid number</p>;
                    }
                    return null;
                  })()}
                  <InlineInterlinkHint 
                    requiredFields={[FIELD_KEYS.densityKgM3]} 
                    sourceTool="atmosphere" 
                    className="mt-1" 
                    currentValue={airDensityCustom}
                    onImport={(value) => setAirDensityCustom(String(value))}
                    onUndo={(prevValue) => setAirDensityCustom(prevValue === null ? '' : String(prevValue))}
                  />
              </AeroFormField>
              )}
              
              <div className="mt-2 p-2 bg-slate-900/50 rounded border border-cyan-400/20">
                <p className="text-sm text-gray-300">
                  <span className="text-cyan-400">Current density:</span> {currentAirDensity.toFixed(3)} kg/m³
                </p>
                {airDensityMode === 'altitude' && (
                  <p className="text-xs text-gray-400 mt-1">
                    Calculated from ISA model at {parseFloat(airDensityAltitude) || 0} {inputUnits.altitude}
                    {parseFloat(airDensityDeltaT) !== 0 && ` (ΔT = ${airDensityDeltaT} K)`}
                  </p>
                )}
                    </div>
            </AeroCard>

            {/* Advanced Settings - Hidden in Beginner mode */}
            {(calculatorMode === 'University' || calculatorMode === 'Expert') && (
              <AeroCard
              title="Advanced Settings"
              description="Optional: CL,max override, MTOW, and landing weight analysis"
              icon={Info}
            >
              <Accordion type="single" collapsible className="w-full">
                <AccordionItem value="advanced" className="border-cyan-400/20">
                  <AccordionTrigger className="text-white hover:text-cyan-400 text-sm">
                    Show Advanced Settings
                  </AccordionTrigger>
                  <AccordionContent className="pt-4 space-y-4">
                    {/* CLmax Override */}
                    <div className="flex items-center gap-3">
                      <Switch
                        checked={useClMaxOverride}
                        onCheckedChange={setUseClMaxOverride}
                      />
                      <Label className="text-sm text-gray-300">Override CL,max</Label>
                    </div>
                    {useClMaxOverride && (
                      <AeroFormField 
                        label="User-specified CL,max" 
                        helperText={`Maximum lift coefficient (C_L,max) for stall speed calculation. Default: ${getMissionData(missionType).clMax.toFixed(2)}${missionType !== 'None' ? ` (${missionType} typical)` : ''}. Specify clean configuration unless otherwise noted. Typical range: 1.2-3.0 (clean: 1.2-2.0, with flaps: 2.0-3.0).`}
                      >
                      <Input 
                          type="number"
                          step="0.01"
                          value={clMaxOverride}
                          onChange={(e) => setClMaxOverride(e.target.value)}
                          className="bg-slate-900/50 border-cyan-400/30"
                          placeholder={`e.g., ${getMissionData(missionType).clMax.toFixed(2)}`}
                          min="0"
                        />
                        {clMaxOverride.trim() && (() => {
                          const val = parseFloat(clMaxOverride);
                          if (!isNaN(val) && isFinite(val)) {
                            if (val <= 0) {
                              return <p className="text-xs text-yellow-400 mt-1">Warning: CL,max must be positive</p>;
                            }
                            if (val < 0.1 || val > 5.0) {
                              return <p className="text-xs text-yellow-400 mt-1">Warning: CL,max outside reasonable range (0.1-5.0)</p>;
                            }
                          } else if (clMaxOverride.trim() && (isNaN(val) || !isFinite(val))) {
                            return <p className="text-xs text-yellow-400 mt-1">Warning: Invalid number</p>;
                          }
                          return null;
                        })()}
                      </AeroFormField>
                    )}
                    
                    {/* MTOW and Landing Weight */}
                    <div className="pt-2 border-t border-cyan-400/20">
                      <Label className="text-sm text-gray-300 mb-2 block">Weight Analysis (Optional)</Label>
                      <AeroFormField 
                        label={`MTOW (${weightMode === 'mass' ? inputUnits.mass : inputUnits.weight})`} 
                        helperText={`Maximum Takeoff Weight (MTOW) - maximum weight at which aircraft is certified for takeoff. Used to calculate wing loading at takeoff condition. Leave empty if not analyzing takeoff performance.`}
                      >
                      <Input 
                        type="number"
                          step="0.01"
                          value={mtow}
                          onChange={(e) => setMtow(e.target.value)}
                          className="bg-slate-900/50 border-cyan-400/30"
                          placeholder="Leave empty to skip"
                        />
                      </AeroFormField>
                      {mtow && calculatorMode === 'Expert' && (
                        <AeroFormField 
                          label="Landing Weight Fraction" 
                          helperText={`Landing weight as fraction of MTOW. Typical: 0.7 (70% of MTOW). Used to calculate wing loading at landing condition. Range: 0.0-1.0.`}
                        >
                          <Input
                            type="number"
                            step="0.01"
                            min="0"
                            max="1"
                            value={landingWeightFraction}
                            onChange={(e) => setLandingWeightFraction(e.target.value)}
                            className="bg-slate-900/50 border-cyan-400/30"
                            placeholder="0.7"
                          />
                          {landingWeightFraction.trim() && (() => {
                            const val = parseFloat(landingWeightFraction);
                            if (!isNaN(val) && isFinite(val)) {
                              if (val <= 0 || val > 1) {
                                return <p className="text-xs text-yellow-400 mt-1">Warning: Landing weight fraction must be between 0 and 1</p>;
                              }
                            } else if (landingWeightFraction.trim() && (isNaN(val) || !isFinite(val))) {
                              return <p className="text-xs text-yellow-400 mt-1">Warning: Invalid number</p>;
                            }
                            return null;
                          })()}
                        </AeroFormField>
                      )}
                    </div>
                  </AccordionContent>
                </AccordionItem>
              </Accordion>
            </AeroCard>
            )}
            
            {/* Calculate Button */}
            <AeroButton
              type="button"
              onClick={handleCalculate}
              variant="primary"
              icon={Gauge}
              className="w-full"
            >
              Calculate Wing Loading
            </AeroButton>
          </div>
        </div>

        {/* RIGHT COLUMN: RESULTS */}
        <div className="space-y-6">
          <div className={spacingVertical.L}>
            {result ? (
              <>
                {/* Primary Results Card */}
            <AeroCard
                  title="Primary Results"
                  icon={CheckCircle}
                >
                  <div className="space-y-4">
                    <div className="p-4 bg-gradient-to-r from-cyan-400/10 to-blue-400/10 rounded-lg border border-cyan-400/30">
                      <p className="text-sm text-gray-400 mb-1">Wing Loading (Weight)</p>
                      <p className="text-xs text-gray-500 mb-1">(W/S in N/m², weight per unit area)</p>
                      <p className="text-3xl font-bold text-cyan-400">
                        {convertWingLoadingNm2FromSI(result.wingLoadingNm2, unitSystem).toFixed(2)} {outputUnits.wingLoadingNm2}
                      </p>
                      <p className="text-sm text-gray-400 mt-1">
                        ({result.wingLoadingNm2.toFixed(2)} N/m²)
                      </p>
                      <p className="text-xs text-gray-500 mt-1">
                        Used for: structural sizing, aerodynamic loads, performance analysis
                      </p>
                    </div>
                    
                    <div className="p-4 bg-gradient-to-r from-cyan-400/10 to-blue-400/10 rounded-lg border border-cyan-400/30">
                      <p className="text-sm text-gray-400 mb-1">Wing Loading (Mass)</p>
                      <p className="text-xs text-gray-500 mb-1">(W/S in kg/m², mass per unit area)</p>
                      <p className="text-3xl font-bold text-cyan-400">
                        {convertWingLoadingKgm2FromSI(result.wingLoadingKgm2, unitSystem).toFixed(2)} {outputUnits.wingLoadingKgm2}
                    </p>
                      <p className="text-sm text-gray-400 mt-1">
                        ({result.wingLoadingKgm2.toFixed(2)} kg/m²)
                    </p>
                      <p className="text-xs text-gray-500 mt-1">
                        Common in preliminary design. Related to weight loading: (W/S)_kg = (W/S)_N / g
                    </p>
                  </div>
                    
                    <div className="p-4 bg-gradient-to-r from-green-400/10 to-cyan-400/10 rounded-lg border border-green-400/30">
                      <p className="text-sm text-gray-400 mb-1">Stall Speed</p>
                      <p className="text-xs text-gray-500 mb-1">(V_s, minimum steady flight speed at C_L,max)</p>
                      {(() => {
                        const velocity = convertVelocityFromSI(result.stallSpeedMs, unitSystem);
                        return (
                          <>
                            <p className="text-2xl font-bold text-green-400">
                              {velocity.value.toFixed(2)} {velocity.unit}
                            </p>
                            <p className="text-sm text-gray-400 mt-1">
                              ({result.stallSpeedMs.toFixed(2)} m/s, {result.stallSpeedKts.toFixed(2)} kts)
                            </p>
                            <p className="text-xs text-gray-500 mt-1">
                              Calculated using: V_s = √[2W/(ρSC_L,max)]. Reference: {currentAirDensity.toFixed(3)} kg/m³ density, C_L,max = {currentClMax.toFixed(2)}. Used for: approach speed estimation, runway length requirements, certification limits.
                            </p>
                          </>
                        );
                      })()}
                        </div>
                    
                    {result.mtowWingLoadingKgm2 !== undefined && (
                      <div className="p-4 bg-slate-900/50 rounded-lg border border-cyan-400/20">
                        <p className="text-sm text-gray-400 mb-1">Wing Loading at Takeoff</p>
                        <p className="text-xs text-gray-500 mb-1">(W/S at MTOW condition)</p>
                        <p className="text-xl font-bold text-cyan-300">
                          {convertWingLoadingKgm2FromSI(result.mtowWingLoadingKgm2, unitSystem).toFixed(2)} {outputUnits.wingLoadingKgm2}
                        </p>
                        <p className="text-xs text-gray-500 mt-1">
                          Maximum wing loading during takeoff. Critical for: takeoff distance, climb gradient, obstacle clearance.
                        </p>
                        {result.landingWingLoadingKgm2 !== undefined && (
                          <>
                            <p className="text-sm text-gray-400 mb-1 mt-3">Wing Loading at Landing</p>
                            <p className="text-xs text-gray-500 mb-1">(W/S at landing weight condition)</p>
                            <p className="text-xl font-bold text-cyan-300">
                              {convertWingLoadingKgm2FromSI(result.landingWingLoadingKgm2, unitSystem).toFixed(2)} {outputUnits.wingLoadingKgm2}
                            </p>
                            <p className="text-xs text-gray-500 mt-1">
                              Landing weight = {((isNaN(parseFloat(landingWeightFraction)) ? 0.7 : parseFloat(landingWeightFraction)) * 100).toFixed(0)}% of MTOW. Critical for: landing distance, approach speed, field length requirements.
                            </p>
                          </>
                        )}
                </div>
              )}
                    
                    <div className="p-4 bg-slate-900/50 rounded-lg border border-cyan-400/20">
                      <p className="text-sm text-gray-400 mb-1">Wing Loading Classification</p>
                      <p className="text-xs text-gray-500 mb-1">(Relative to {missionType !== 'None' ? `${missionType} mission` : 'generic'} envelope)</p>
                      <p className={`text-xl font-bold ${getClassificationColor(result.wsClass)}`}>
                        {result.wsClass}
                      </p>
                      <p className="text-xs text-gray-500 mt-1">
                        {missionType !== 'None' 
                          ? `Typical ${missionType} range: ${getMissionData(missionType).wsMinKg}–${getMissionData(missionType).wsMaxKg} kg/m²`
                          : 'Classification based on generic aircraft ranges'}
                      </p>
                </div>
              </div>
            </AeroCard>
                
                {/* Mission Envelope Card */}
                <AeroCard
                  title="Mission Envelope"
                  description={`Wing loading comparison against ${missionType !== 'None' ? `${missionType} mission` : 'generic'} typical ranges`}
                  icon={TrendingUp}
                >
                  <div className="space-y-3">
                    <p className="text-sm text-gray-300">
                      Typical <span className="text-cyan-400 font-semibold">{missionType !== 'None' ? missionType : 'generic aircraft'}</span> wing loading:{" "}
                      <span className="text-cyan-400">
                        {missionType !== 'None' ? `${getMissionData(missionType).wsMinKg}–${getMissionData(missionType).wsMaxKg} kg/m²` : 'N/A (Manual mode)'}
                      </span>
                    </p>
                    <div className="relative h-12 bg-slate-700/50 rounded border border-cyan-400/30">
                      {/* Range indicator (typical range) */}
                      {(() => {
                        const rangePos = getRangeBarPosition();
                        return (
                          <div
                            className="absolute h-full bg-cyan-400/30 border-l border-r border-cyan-400/50"
                            style={{
                              left: `${rangePos.left}%`,
                              width: `${rangePos.width}%`
                            }}
                          />
                        );
                      })()}
                      
                      {/* Example aircraft reference zones */}
                      {(() => {
                        const example = EXAMPLE_AIRCRAFT[missionType as keyof typeof EXAMPLE_AIRCRAFT];
                        if (!example) return null;
                        const params = missionData[missionType];
                        const extendedMin = 0.8 * params.wsMinKg;
                        const extendedMax = 1.2 * params.wsMaxKg;
                        const extendedRange = extendedMax - extendedMin;
                        if (extendedRange <= 0) return null;
                        
                        const left = ((example.range[0] - extendedMin) / extendedRange) * 100;
                        const width = ((example.range[1] - example.range[0]) / extendedRange) * 100;
                        
                        return (
                          <div
                            className="absolute top-0 h-full bg-blue-400/20 border-l border-r border-blue-400/40"
                            style={{
                              left: `${Math.max(0, left)}%`,
                              width: `${Math.max(0, Math.min(100, width))}%`
                            }}
                            title={example.label}
                          />
                        );
                      })()}
                      
                      {/* Current position marker */}
                      <div
                        className="absolute top-0 h-full w-1 bg-cyan-400 z-10"
                        style={{ left: `${getEnvelopePosition()}%` }}
                      />
                      
                      {/* Labels */}
                      <div
                        className="absolute -top-6 left-0 right-0 flex justify-between text-xs text-gray-400"
                      >
                        {missionType !== 'None' && (
                          <>
                            <span>{(0.8 * getMissionData(missionType).wsMinKg).toFixed(0)}</span>
                            <span>{(1.2 * getMissionData(missionType).wsMaxKg).toFixed(0)}</span>
                          </>
                        )}
            </div>
                      
                      {/* Example aircraft label */}
                      {(() => {
                        const example = EXAMPLE_AIRCRAFT[missionType as keyof typeof EXAMPLE_AIRCRAFT];
                        if (!example) return null;
                        const params = missionData[missionType];
                        const extendedMin = 0.8 * params.wsMinKg;
                        const extendedMax = 1.2 * params.wsMaxKg;
                        const extendedRange = extendedMax - extendedMin;
                        if (extendedRange <= 0) return null;
                        
                        const center = ((example.range[0] + example.range[1]) / 2 - extendedMin) / extendedRange * 100;
                        
                        return (
                          <div
                            className="absolute -bottom-5 text-xs text-blue-300/70"
                            style={{ left: `${Math.max(5, Math.min(95, center))}%`, transform: 'translateX(-50%)' }}
                          >
                            {example.label}
            </div>
                        );
                      })()}
          </div>
                    <p className="text-sm text-cyan-400 text-center">
                      Current: {result.wingLoadingKgm2.toFixed(2)} kg/m²
                    </p>
                    <p className="text-xs text-gray-500 text-center">
                      Reference condition: {airDensityMode === 'preset' 
                        ? `${airDensityPreset} (${currentAirDensity.toFixed(3)} kg/m³)`
                        : airDensityMode === 'altitude'
                        ? `Altitude ${airDensityAltitude} ${inputUnits.altitude} (${currentAirDensity.toFixed(3)} kg/m³)`
                        : `Custom density (${currentAirDensity.toFixed(3)} kg/m³)`}
                    </p>
          </div>
                </AeroCard>
                
                {/* Regulatory Warning */}
                {result.regulatoryWarning && (
                  <AeroCard
                    title="Regulatory Check"
                    icon={AlertTriangle}
                  >
                    <div className="p-4 bg-yellow-900/30 rounded-lg border border-yellow-400/30">
                      <p className="text-sm text-yellow-200 whitespace-pre-wrap leading-relaxed">
                        {result.regulatoryWarning}
                      </p>
                    </div>
                  </AeroCard>
                )}
                
                {/* Best Use Case / Mission Fit Card */}
                <AeroCard
                  title="Best Use Case / Mission Fit"
                  icon={TrendingUp}
                >
                  <div className="p-4 bg-slate-900/50 rounded-lg border border-cyan-400/20">
                    <p className="text-sm text-gray-200 whitespace-pre-wrap leading-relaxed">
                      {generateBestUseCase(
                        missionType,
                        result.wsClass,
                        result.vsClass,
                        result.wingLoadingKgm2,
                        result.stallSpeedMs,
                        result.stallSpeedKts
                      )}
                    </p>
                  </div>
                </AeroCard>
                
                {/* Interpretation Card - Hidden in Beginner mode */}
                {calculatorMode !== 'Beginner' && (
                <AeroCard
                  title="Engineering Interpretation"
                  icon={Info}
                >
                  <div className="p-4 bg-slate-900/50 rounded-lg border border-cyan-400/20">
                    <p className="text-sm text-gray-200 whitespace-pre-wrap leading-relaxed">
                      {result.interpretation}
                    </p>
                  </div>
                </AeroCard>
                )}
                
                {/* Step-by-Step Solution */}
                <AeroCard
                  title="Step-by-Step Solution"
                  icon={Info}
                >
                  <Accordion type="single" collapsible className="w-full">
                    <AccordionItem value="steps" className="border-cyan-400/20">
                      <AccordionTrigger className="text-white hover:text-cyan-400">
                        <div className="flex items-center gap-2">
                          <Info className="w-4 h-4 text-cyan-400" />
                          Show step-by-step solution
                  </div>
                      </AccordionTrigger>
                      <AccordionContent className="pt-2">
                        <CalculationSteps steps={result.steps} />
                      </AccordionContent>
                    </AccordionItem>
                  </Accordion>
                </AeroCard>
              </>
            ) : (
              <AeroCard title="Results" icon={Gauge}>
                <div className="text-center py-12">
                  <Gauge className="w-16 h-16 mx-auto mb-4 text-cyan-400/30" />
                  <p className="text-gray-400">Enter values and click Calculate to see results</p>
                </div>
              </AeroCard>
            )}
          </div>
        </div>
      </ToolSection>

      {/* Engineering Graphs - Full Width Section Below */}
      {result && (
        <div className="mt-8 px-4">
          <WingLoadingGraphs
            currentWsKgm2={result.wingLoadingKgm2}
            currentVsMs={result.stallSpeedMs}
            currentVsKts={result.stallSpeedKts}
            weightN={result.weightN}
            wingAreaM2={result.wingAreaM2}
            airDensity={currentAirDensity}
            clMax={currentClMax}
            missionType={missionType}
            missionData={missionData}
            airDensityMode={airDensityMode}
            airDensityPreset={airDensityPreset}
            airDensityAltitude={parseFloat(airDensityAltitude) || undefined}
          />
        </div>
      )}
    </ToolWrapper>
  );
};

export default WingLoadingCalculator;

"use client";

import { useState, useEffect, useMemo, useCallback } from "react";
import { MissionParameters, Stage, MissionResult } from "./types";
import {
  calculateDeltaVBreakdown,
  calculateStageResults,
  calculateTotalAchievableDeltaV,
  generateWarningsAndRecommendations,
} from "./calculations";
import { MISSION_PRESETS } from "./presets";
import { saveLastMission, loadLastMission, savePreset, loadPresets } from "./storage";
import StageEditor from "./StageEditor";
import DVBudgetTable from "./DVBudgetTable";
import DeltaVChart from "./DeltaVChart";
import MassBreakdownChart from "./MassBreakdownChart";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Button } from "@/components/ui/button";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert";
import {
  Rocket,
  Settings2,
  Database,
  AlertTriangle,
  CheckCircle,
  Info,
} from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { useToolContext } from "@/hooks/useToolContext";
import { PDFExportButton } from "@/components/tools/PDFExportButton";
import { AskAIButton } from "@/components/tools/AskAIButton";
import { ToolWrapper } from "@/components/layout/ToolWrapper";
import { ToolHeader } from "@/components/layout/ToolHeader";
import { ToolSection } from "@/components/layout/ToolSection";
import { ToolActions } from "@/components/layout/ToolActions";
import { AeroCard } from "@/components/common/AeroCard";
import { AeroFormField } from "@/components/forms/AeroFormField";
import { AeroButton } from "@/components/common/AeroButton";
import { spacingVertical } from "@/styles/spacing";
import { buildCalculationEvent } from "@/lib/events/payloadBuilder";
import type { AeroverseAIPayload } from "@/ai/schema/AerorbisPayload";
import { buildDeltaVPayload, DeltaVUnitSystem } from "./payloadBuilder";

type UnitSystem = DeltaVUnitSystem;

const DeltaVPlanner = () => {
  const { toast } = useToast();
  const { updateToolContext, sendCalculationEvent } = useToolContext();
  const [lastRequestId, setLastRequestId] = useState<string | null>(null);
  const [lastPayload, setLastPayload] = useState<AeroverseAIPayload | null>(null);
  const [unitSystem, setUnitSystem] = useState<UnitSystem>("SI");
  const [customUnitName, setCustomUnitName] = useState("Unit-Δv");
  const [customFactor, setCustomFactor] = useState("1.0");
  const [mission, setMission] = useState<MissionParameters>({
    targetOrbitAltitude: 200,
    orbitType: "LEO",
    targetInclination: 28.5,
    payloadMass: 250,
    gravityLoss: 1500,
    dragLoss: 200,
    steeringLoss: 200,
    reserveMargin: 10,
  });
  const [stages, setStages] = useState<Stage[]>([]);
  const [result, setResult] = useState<MissionResult | null>(null);
  const [isPresetDialogOpen, setIsPresetDialogOpen] = useState(false);
  const [presetName, setPresetName] = useState("");

  const getLatestStoredRequestId = useCallback((): string | null => {
    try {
      const storedKeys = Object.keys(localStorage).filter((key) => key.startsWith("calc-"));
      if (storedKeys.length === 0) return null;
      const latestKey = storedKeys.sort().reverse()[0];
      return latestKey.replace("calc-", "");
    } catch (error) {
      console.warn("Unable to read stored calculation IDs:", error);
      return null;
    }
  }, []);

  const applyToolPayload = useCallback(
    async (payload: AeroverseAIPayload) => {
      setLastPayload(payload);

      updateToolContext({
        tool: "Delta-V Budget Planner",
        inputs: payload.inputs,
        results: payload.results,
      });

      const eventPayload = buildCalculationEvent({
        toolId: "deltav-planner",
        toolName: payload.toolName,
        inputs: payload.inputs,
        results: payload.results,
        steps: payload.metadata.steps,
        metadata: {
          units: payload.metadata.unitsSystem,
          approxLevel: payload.metadata.approxLevel,
          confidence: payload.metadata.confidence,
          warnings: payload.metadata.warnings,
        },
      });

      try {
        const eventResponse = await sendCalculationEvent(eventPayload);
        const requestId = eventResponse?.requestId ?? getLatestStoredRequestId();
        setLastRequestId(requestId);
        return requestId;
      } catch (error) {
        console.warn("Failed to send calculation event:", error);
        const fallbackId = getLatestStoredRequestId();
        setLastRequestId(fallbackId);
        return fallbackId;
      }
    },
    [getLatestStoredRequestId, sendCalculationEvent, updateToolContext]
  );

  // Load last mission on mount
  useEffect(() => {
    const last = loadLastMission();
    if (last.mission && last.stages) {
      setMission(last.mission);
      setStages(last.stages);
    } else {
      // Load first preset as default
      if (MISSION_PRESETS.length > 0) {
        loadPreset(MISSION_PRESETS[0]);
      }
    }
    const storedUnitSystem = localStorage.getItem("deltavPlanner_unitSystem");
    if (storedUnitSystem) {
      setUnitSystem(storedUnitSystem as UnitSystem);
    }
    const storedCustomUnitName = localStorage.getItem("deltavPlanner_customUnitName");
    if (storedCustomUnitName) {
      setCustomUnitName(storedCustomUnitName);
    }
    const storedCustomFactor = localStorage.getItem("deltavPlanner_customFactor");
    if (storedCustomFactor) {
      setCustomFactor(storedCustomFactor);
    }
  }, []);

  // Save mission on change
  useEffect(() => {
    if (stages.length > 0) {
      saveLastMission(mission, stages);
    }
  }, [mission, stages]);

  useEffect(() => {
    localStorage.setItem("deltavPlanner_unitSystem", unitSystem);
  }, [unitSystem]);

  useEffect(() => {
    if (unitSystem === "Custom") {
      localStorage.setItem("deltavPlanner_customUnitName", customUnitName);
      localStorage.setItem("deltavPlanner_customFactor", customFactor);
    }
  }, [unitSystem, customUnitName, customFactor]);

  // Calculate results when mission or stages change
  const stageResults = useMemo(() => {
    if (stages.length === 0) return [];
    return calculateStageResults(stages, mission.payloadMass, 0);
  }, [stages, mission.payloadMass]);

  const totalAchievable = useMemo(() => {
    return calculateTotalAchievableDeltaV(stageResults);
  }, [stageResults]);

  const breakdown = useMemo(() => {
    return calculateDeltaVBreakdown(mission, totalAchievable);
  }, [mission, totalAchievable]);

  const { warnings, recommendations } = useMemo(() => {
    if (stageResults.length === 0) return { warnings: [], recommendations: [] };
    return generateWarningsAndRecommendations(breakdown, stageResults, mission.payloadMass);
  }, [breakdown, stageResults, mission.payloadMass]);

  // Format DeltaV for display
  const formatDeltaV = (value: number): string => {
    let converted = value;
    let unit = "m/s";
    
    if (unitSystem === "Imperial") {
      converted = value * 3.28084; // m/s to ft/s
      unit = "ft/s";
    } else if (unitSystem === "Custom") {
      const factor = parseFloat(customFactor);
      if (!isNaN(factor) && factor > 0) {
        converted = value / factor; // Convert from SI (m/s) to custom
      }
      unit = customUnitName || "Unit";
    }
    
    return `${converted.toFixed(1)} ${unit}`;
  };

  // Update result + AI payload when state changes
  useEffect(() => {
    if (stageResults.length === 0) {
      setResult(null);
      setLastPayload(null);
      setLastRequestId(null);
      return;
    }

    const totalLiftoffMass =
      stageResults.reduce((sum, r) => sum + r.initialMass, 0) + mission.payloadMass;

    const resultData: MissionResult = {
      mission,
      stages: stageResults,
      breakdown,
      totalLiftoffMass,
      payloadMass: mission.payloadMass,
      warnings,
      recommendations,
    };

    setResult(resultData);

    const payload = buildDeltaVPayload({
      mission,
      stages,
      stageResults,
      breakdown,
      totalLiftoffMass,
      warnings,
      recommendations,
      unitSystem,
      customUnitName,
      customFactor,
    });

    void applyToolPayload(payload);
  }, [
    applyToolPayload,
    breakdown,
    customFactor,
    customUnitName,
    mission,
    recommendations,
    stageResults,
    stages,
    unitSystem,
    warnings,
  ]);

  const loadPreset = useCallback((preset: typeof MISSION_PRESETS[0]) => {
    setMission(preset.mission);
    setStages(
      preset.stages.map((s, i) => ({
        ...s,
        id: `stage-${Date.now()}-${i}`,
      }))
    );
    toast({
      title: "Preset Loaded",
      description: `${preset.name} configuration loaded`,
    });
  }, [toast]);


  const handleSavePreset = () => {
    if (!presetName.trim()) {
      toast({
        title: "Name Required",
        description: "Please enter a name for the preset",
        variant: "destructive",
      });
      return;
    }
    savePreset(presetName, mission, stages);
    toast({
      title: "Preset Saved",
      description: `${presetName} has been saved`,
    });
    setPresetName("");
    setIsPresetDialogOpen(false);
  };

  return (
    <ToolWrapper>
      <ToolHeader
        title="Delta-V Budget Planner"
        description="Mission Δv & Staging Designer - Calculate required Δv, stage sizing, and mission feasibility"
        icon={Rocket}
        actions={
          <ToolActions>
            <Select value={unitSystem} onValueChange={(v) => setUnitSystem(v as UnitSystem)}>
              <SelectTrigger className="w-40 bg-slate-900/50 border-cyan-400/30 text-cyan-400">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="SI">SI (m/s)</SelectItem>
                <SelectItem value="Imperial">Imperial (ft/s)</SelectItem>
                <SelectItem value="Custom">Custom</SelectItem>
              </SelectContent>
            </Select>
            <AeroButton
              variant="outline"
              onClick={() => setIsPresetDialogOpen(true)}
              icon={Database}
            >
              Save Preset
            </AeroButton>
          </ToolActions>
        }
      />

      <ToolSection gridCols={3}>
        {/* Left Panel - Mission & Stage Inputs */}
        <div className="lg:col-span-2">
          <div className={spacingVertical.L}>
            {/* Mission Parameters */}
            <AeroCard
              title="Mission Parameters"
              description="Configure target orbit and mission requirements"
              icon={Rocket}
            >
              <div className="grid grid-cols-2 gap-4">
                <AeroFormField label="Orbit Type">
                  <Select
                    value={mission.orbitType}
                    onValueChange={(value: MissionParameters["orbitType"]) =>
                      setMission({ ...mission, orbitType: value })
                    }
                  >
                    <SelectTrigger className="bg-slate-900/50 border-cyan-400/30 text-white">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="LEO">LEO</SelectItem>
                      <SelectItem value="GTO">GTO</SelectItem>
                      <SelectItem value="GEO">GEO</SelectItem>
                      <SelectItem value="Escape">Escape</SelectItem>
                      <SelectItem value="Custom">Custom</SelectItem>
                    </SelectContent>
                  </Select>
                </AeroFormField>
                <AeroFormField label="Target Altitude (km)">
                  <Input
                    id="altitude"
                    type="number"
                    step="1"
                    value={mission.targetOrbitAltitude}
                    onChange={(e) =>
                      setMission({
                        ...mission,
                        targetOrbitAltitude: parseFloat(e.target.value) || 0,
                      })
                    }
                    className="bg-slate-900/50 border-cyan-400/30 text-white"
                  />
                </AeroFormField>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <AeroFormField label="Target Inclination (deg)">
                  <Input
                    id="inclination"
                    type="number"
                    step="0.1"
                    value={mission.targetInclination}
                    onChange={(e) =>
                      setMission({
                        ...mission,
                        targetInclination: parseFloat(e.target.value) || 0,
                      })
                    }
                    className="bg-slate-900/50 border-cyan-400/30 text-white"
                  />
                </AeroFormField>
                <AeroFormField label={`Payload Mass (kg)`}>
                  <Input
                    id="payload"
                    type="number"
                    step="0.1"
                    value={mission.payloadMass}
                    onChange={(e) =>
                      setMission({
                        ...mission,
                        payloadMass: parseFloat(e.target.value) || 0,
                      })
                    }
                    className="bg-slate-900/50 border-cyan-400/30 text-white"
                  />
                </AeroFormField>
              </div>
              <div className="grid grid-cols-3 gap-4">
                <AeroFormField label="Gravity Loss (m/s)">
                  <Input
                    id="gravity-loss"
                    type="number"
                    step="10"
                    value={mission.gravityLoss}
                    onChange={(e) =>
                      setMission({
                        ...mission,
                        gravityLoss: parseFloat(e.target.value) || 0,
                      })
                    }
                    className="bg-slate-900/50 border-cyan-400/30 text-white"
                  />
                </AeroFormField>
                <AeroFormField label={`Drag Loss (${unitSystem === "SI" ? "m/s" : unitSystem === "Imperial" ? "ft/s" : customUnitName || "Unit"})`}>
                  <Input
                    id="drag-loss"
                    type="number"
                    step="10"
                    value={mission.dragLoss}
                    onChange={(e) =>
                      setMission({
                        ...mission,
                        dragLoss: parseFloat(e.target.value) || 0,
                      })
                    }
                    className="bg-slate-900/50 border-cyan-400/30 text-white"
                  />
                </AeroFormField>
                <AeroFormField label={`Steering Loss (${unitSystem === "SI" ? "m/s" : unitSystem === "Imperial" ? "ft/s" : customUnitName || "Unit"})`}>
                  <Input
                    id="steering-loss"
                    type="number"
                    step="10"
                    value={mission.steeringLoss}
                    onChange={(e) =>
                      setMission({
                        ...mission,
                        steeringLoss: parseFloat(e.target.value) || 0,
                      })
                    }
                    className="bg-slate-900/50 border-cyan-400/30 text-white"
                  />
                </AeroFormField>
              </div>
              <AeroFormField label="Reserve Margin (%)">
                <Input
                  id="margin"
                  type="number"
                  step="1"
                  min="0"
                  max="100"
                  value={mission.reserveMargin}
                  onChange={(e) =>
                    setMission({
                      ...mission,
                      reserveMargin: parseFloat(e.target.value) || 0,
                    })
                  }
                  className="bg-slate-900/50 border-cyan-400/30 text-white"
                />
              </AeroFormField>
            </AeroCard>

            {/* Stage Editor */}
            <StageEditor stages={stages} onStagesChange={setStages} />

            {/* Presets */}
            <AeroCard
              title="Mission Presets"
              description="Quick-load common mission configurations"
              icon={Database}
            >
              <div className="grid grid-cols-1 md:grid-cols-2 gap-2">
                {MISSION_PRESETS.map((preset) => (
                  <AeroButton
                    key={preset.name}
                    variant="outline"
                    onClick={() => loadPreset(preset)}
                    className="justify-start"
                  >
                    <div className="text-left">
                      <p className="font-semibold">{preset.name}</p>
                      <p className="text-xs text-gray-400">{preset.description}</p>
                    </div>
                  </AeroButton>
                ))}
              </div>
            </AeroCard>
          </div>
        </div>

        {/* Right Panel - Results */}
        <div>
          <div className={spacingVertical.L}>
            {/* Summary Card */}
            {result ? (
                <AeroCard
                  title="Mission Summary"
                  headerActions={
                    result && breakdown && stageResults.length > 0 ? (
                      <div className="flex gap-2">
                        <AskAIButton
                          requestId={lastRequestId}
                          payload={lastPayload || undefined}
                          disabled={!lastPayload}
                        />
                        <PDFExportButton
                          requestId={lastRequestId}
                          toolName="Delta-V Budget Planner"
                          disabled={!lastRequestId}
                        />
                      </div>
                    ) : null
                  }
                >
                <div className="p-4 bg-gradient-to-r from-cyan-400/10 to-blue-400/10 rounded-lg border border-cyan-400/30 mb-4">
                  <p className="text-sm text-gray-400 mb-1">Total Liftoff Mass</p>
                  <p className="text-3xl font-bold text-cyan-400">
                    {(result.totalLiftoffMass / 1000).toFixed(1)} t
                  </p>
                </div>
                <div className="p-4 bg-gradient-to-r from-blue-400/10 to-purple-400/10 rounded-lg border border-blue-400/30 mb-4">
                  <p className="text-sm text-gray-400 mb-1">Total Achievable Δv</p>
                  <p className="text-3xl font-bold text-blue-400">
                    {formatDeltaV(breakdown.totalAchievable)}
                  </p>
                </div>
                <div
                  className={`p-4 rounded-lg border mb-4 ${
                    breakdown.isFeasible
                      ? "bg-gradient-to-r from-green-400/10 to-emerald-400/10 border-green-400/30"
                      : "bg-gradient-to-r from-red-400/10 to-pink-400/10 border-red-400/30"
                  }`}
                >
                  <div className="flex items-center gap-2 mb-2">
                    {breakdown.isFeasible ? (
                      <CheckCircle className="w-5 h-5 text-green-400" />
                    ) : (
                      <AlertTriangle className="w-5 h-5 text-red-400" />
                    )}
                    <p className="font-semibold text-white">
                      {breakdown.isFeasible ? "Mission Feasible" : "Mission Infeasible"}
                    </p>
                  </div>
                  <p className="text-sm text-gray-300">
                    Required: {formatDeltaV(breakdown.totalWithMargin)}
                  </p>
                </div>
              </AeroCard>
            ) : null}

            {/* Warnings */}
            {warnings.length > 0 && (
              <AeroCard
                title="Warnings"
                icon={AlertTriangle}
                className="border-yellow-400/20"
              >
                <div className="space-y-2">
                  {warnings.map((warning, i) => (
                    <Alert key={i} variant="default" className="bg-yellow-400/10 border-yellow-400/30">
                      <AlertDescription className="text-yellow-400 text-sm">
                        {warning}
                      </AlertDescription>
                    </Alert>
                  ))}
                </div>
              </AeroCard>
            )}

            {/* Recommendations */}
            {recommendations.length > 0 && (
              <AeroCard
                title="Recommendations"
                icon={Info}
              >
                <ul className="space-y-2">
                  {recommendations.map((rec, i) => (
                    <li key={i} className="text-gray-300 text-sm flex items-start gap-2">
                      <span className="text-cyan-400">•</span>
                      <span>{rec}</span>
                    </li>
                  ))}
                </ul>
              </AeroCard>
            )}

            {/* Custom Units Card */}
            {unitSystem === "Custom" && (
              <AeroCard
                title="Custom Unit Definitions"
                description="Define conversion factor to SI (m/s)"
                icon={Settings2}
              >
                <div className="p-3 bg-slate-900/50 rounded-lg border border-cyan-400/10">
                  <Label className="text-white font-semibold">Delta-V (Δv)</Label>
                  <div className="grid grid-cols-2 gap-2 mt-2">
                    <Input 
                      placeholder="Unit Name" 
                      value={customUnitName}
                      onChange={(e) => setCustomUnitName(e.target.value)}
                      className="bg-slate-800 border-cyan-400/30 text-white"
                    />
                    <Input 
                      type="number"
                      step="0.0001"
                      placeholder="SI Factor"
                      value={customFactor}
                      onChange={(e) => setCustomFactor(e.target.value)}
                      className="bg-slate-800 border-cyan-400/30 text-white"
                    />
                  </div>
                  <p className="text-xs text-gray-500 mt-1.5">
                    1 {customUnitName || "Unit"} = {customFactor || "..."} m/s
                  </p>
                </div>
              </AeroCard>
            )}
          </div>
        </div>
      </ToolSection>

      {/* Results Section */}
      {result && (
        <div className={spacingVertical.L}>
          <div className="grid lg:grid-cols-2 gap-6">
            <DVBudgetTable breakdown={breakdown} stageResults={stageResults} unitSystem={unitSystem} customUnitName={customUnitName} customFactor={customFactor} />
            <DeltaVChart breakdown={breakdown} unitSystem={unitSystem} customUnitName={customUnitName} customFactor={customFactor} />
          </div>
          {result && (
            <MassBreakdownChart stageResults={stageResults} payloadMass={mission.payloadMass} />
          )}
        </div>
      )}

      {/* Save Preset Dialog */}
      <Dialog open={isPresetDialogOpen} onOpenChange={setIsPresetDialogOpen}>
        <DialogContent className="bg-slate-800 border-cyan-400/20 text-white max-w-lg">
          <DialogHeader>
            <DialogTitle>Save Preset</DialogTitle>
            <DialogDescription className="text-gray-400">
              Save current mission configuration as a preset
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4 py-4">
            <div className="space-y-2">
              <Label htmlFor="preset-name" className="text-gray-300">
                Preset Name
              </Label>
              <Input
                id="preset-name"
                value={presetName}
                onChange={(e) => setPresetName(e.target.value)}
                className="bg-slate-900/50 border-cyan-400/30 text-white"
                placeholder="My Custom Mission"
              />
            </div>
          </div>
          <DialogFooter>
            <AeroButton
              variant="outline"
              onClick={() => setIsPresetDialogOpen(false)}
            >
              Cancel
            </AeroButton>
            <AeroButton
              onClick={handleSavePreset}
              variant="primary"
            >
              Save
            </AeroButton>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </ToolWrapper>
  );
};

export default DeltaVPlanner;

"use client";

/*
 * FIXES APPLIED:
 * - Standardized result property name (solveFor -> solvedFor) for consistency with UI
 * - Fixed chart generation loop to use standard atmospheric pressure default
 * - Added validation for physical constraints (mass flow >= 0, exit area > 0, exhaust velocity > 0)
 * - Improved error handling with clear, user-friendly messages
 * - Added physics formula comments (Thrust equation, Isp calculation)
 * - Fixed unit conversion edge cases for custom units
 * - Added test cases
 */

import { useState, useEffect, useCallback } from "react";
import { motion } from "framer-motion";
import { 
  Card, 
  CardContent, 
  CardDescription, 
  CardHeader, 
  CardTitle 
} from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Button } from "@/components/ui/button";
import { Calculator, Rocket, Info, TrendingUp, Settings2, Anchor } from "lucide-react";
import { z } from "zod";
import { useToast } from "@/hooks/use-toast";
import { useToolContext } from "@/hooks/useToolContext";
import { PDFExportButton } from "@/components/tools/PDFExportButton";
import { AskAIButton } from "@/components/tools/AskAIButton";
import { buildAeroversePayload } from "@/ai/buildPayload";
import { buildCalculationEvent } from "@/lib/events/payloadBuilder";
import type { AeroverseAIPayload } from "@/ai/schema/AerorbisPayload";
import { ToolWrapper } from "@/components/layout/ToolWrapper";
import { ToolHeader } from "@/components/layout/ToolHeader";
import { ToolSection } from "@/components/layout/ToolSection";
import { ToolActions } from "@/components/layout/ToolActions";
import { CalculationSteps } from "@/components/common/CalculationSteps";
import { AeroCard } from "@/components/common/AeroCard";
import { AeroFormField } from "@/components/forms/AeroFormField";
import { AeroButton } from "@/components/common/AeroButton";
import { ChartCard } from "@/components/charts/ChartCard";
import { AeroverseLegend, type LegendItem } from "@/components/charts/AerorbisLegend";
import { spacingVertical } from "@/styles/spacing";
import { 
  Select, 
  SelectContent, 
  SelectItem, 
  SelectTrigger, 
  SelectValue 
} from "@/components/ui/select";
import { 
  Accordion, 
  AccordionContent, 
  AccordionItem, 
  AccordionTrigger 
} from "@/components/ui/accordion";
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { 
  LineChart, 
  Line, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip as RechartsTooltip, 
  ResponsiveContainer
} from "recharts";
import { Save, FolderOpen, Trash2 } from "lucide-react";

// --- Types & Constants ---

type UnitSystem = "SI" | "Imperial" | "Custom";

interface CalculationStep {
  equation: string;
  description: string;
}

interface SavedPreset {
  name: string;
  inputs: {
    massFlowRate: string;
    exhaustVelocity: string;
    exitArea: string;
    exitPressure: string;
    ambientPressure: string;
    thrust: string;
    isp: string;
  };
  unitSystem: UnitSystem;
  timestamp: number;
}

const STORAGE_KEY_CUSTOM_PRESETS = "thrustCalculator_customPresets";

const G0_SI = 9.80665; // m/s²
const G0_IMPERIAL = 32.174; // ft/s²

const thrustSchema = z.object({
  massFlowRate: z.number().finite("Must be a valid number").optional(),
  exhaustVelocity: z.number().finite("Must be a valid number").optional(),
  exitArea: z.number().finite("Must be a valid number").optional(),
  exitPressure: z.number().finite("Must be a valid number").optional(),
  ambientPressure: z.number().finite("Must be a valid number").optional(),
  thrust: z.number().finite("Must be a valid number").optional(),
});

const performanceSchema = z.object({
  isp: z.number().finite("Must be a valid number").optional(),
  exhaustVelocity: z.number().finite("Must be a valid number").optional(),
});

// --- Main Component ---
const AdvancedThrustCalculator = () => {
  const { toast } = useToast();
  const { updateToolContext, sendCalculationEvent } = useToolContext();
  const [lastRequestId, setLastRequestId] = useState<string | null>(null);
  const [lastPayload, setLastPayload] = useState<AeroverseAIPayload | null>(null);
  const [unitSystem, setUnitSystem] = useState<UnitSystem>("SI");

  // --- State ---
  const [inputs, setInputs] = useState({
    massFlowRate: "",
    exhaustVelocity: "",
    exitArea: "",
    exitPressure: "",
    ambientPressure: "",
    thrust: "",
    isp: "",
  });

  const [customUnitNames, setCustomUnitNames] = useState({
    massFlowRate: "Unit-ṁ",
    exhaustVelocity: "Unit-Ve",
    exitArea: "Unit-Ae",
    pressure: "Unit-P",
    thrust: "Unit-F",
  });
  const [customFactors, setCustomFactors] = useState({
    massFlowRate: "1.0",
    exhaustVelocity: "1.0",
    exitArea: "1.0",
    pressure: "1.0",
    thrust: "1.0",
  });

  const [thrustResult, setThrustResult] = useState<unknown | null>(null);
  const [performanceResult, setPerformanceResult] = useState<unknown | null>(null);
  const [chartData, setChartData] = useState<unknown[]>([]);
  const [customPresets, setCustomPresets] = useState<SavedPreset[]>([]);
  const [isSaveDialogOpen, setIsSaveDialogOpen] = useState(false);
  const [isLoadDialogOpen, setIsLoadDialogOpen] = useState(false);
  const [savePresetName, setSavePresetName] = useState("");
  const getLatestStoredRequestId = useCallback((): string | null => {
    try {
      const storedKeys = Object.keys(localStorage).filter((key) => key.startsWith("calc-"));
      if (storedKeys.length === 0) return null;
      const latestKey = storedKeys.sort().reverse()[0];
      return latestKey.replace("calc-", "");
    } catch (err) {
      console.warn("Unable to read stored calculation IDs:", err);
      return null;
    }
  }, []);

  const applyToolPayload = useCallback(
    async (payload: AeroverseAIPayload) => {
      setLastPayload(payload);

      updateToolContext({
        tool: "Thrust",
        inputs: payload.inputs,
        results: payload.results,
      });

      const eventPayload = buildCalculationEvent({
        toolId: "thrust-calculator",
        toolName: payload.toolName,
        inputs: payload.inputs,
        results: payload.results,
        steps: payload.metadata.steps,
        metadata: {
          units: payload.metadata.unitsSystem,
          approxLevel: payload.metadata.approxLevel,
          confidence: payload.metadata.confidence,
          warnings: payload.metadata.warnings,
        },
      });

      try {
        const eventResponse = await sendCalculationEvent(eventPayload);
        const requestId = eventResponse?.requestId ?? getLatestStoredRequestId();
        setLastRequestId(requestId);
        return requestId;
      } catch (err) {
        console.warn("Failed to send calculation event:", err);
        const fallbackId = getLatestStoredRequestId();
        setLastRequestId(fallbackId);
        return fallbackId;
      }
    },
    [getLatestStoredRequestId, sendCalculationEvent, updateToolContext]
  );

  // --- Effects for LocalStorage ---
  useEffect(() => {
    // TODO: refine type for `setter` and `defaultValue` — changed Function/any -> unknown automatically by chore/typed-cleanup
    const loadFromStorage = (key: string, setter: (...args: unknown[]) => unknown, defaultValue: unknown) => {
      const storedValue = localStorage.getItem(key);
      if (storedValue) {
        try {
          setter(JSON.parse(storedValue));
        } catch (e) {
          if (key === "advThrustCalc_unitSystem") setter(storedValue);
          else console.warn(`Failed to parse ${key} from storage.`);
        }
      } else {
        setter(defaultValue);
      }
    };

    loadFromStorage("advThrustCalc_unitSystem", setUnitSystem, "SI");
    loadFromStorage("advThrustCalc_inputs", setInputs, { massFlowRate: "", exhaustVelocity: "", exitArea: "", exitPressure: "", ambientPressure: "", thrust: "", isp: "" });
    loadFromStorage("advThrustCalc_customNames", setCustomUnitNames, { massFlowRate: "Unit-ṁ", exhaustVelocity: "Unit-Ve", exitArea: "Unit-Ae", pressure: "Unit-P", thrust: "Unit-F" });
    loadFromStorage("advThrustCalc_customFactors", setCustomFactors, { massFlowRate: "1.0", exhaustVelocity: "1.0", exitArea: "1.0", pressure: "1.0", thrust: "1.0" });
  }, []);

  useEffect(() => {
    localStorage.setItem("advThrustCalc_unitSystem", unitSystem);
    localStorage.setItem("advThrustCalc_inputs", JSON.stringify(inputs));
    localStorage.setItem("advThrustCalc_customNames", JSON.stringify(customUnitNames));
    localStorage.setItem("advThrustCalc_customFactors", JSON.stringify(customFactors));
  }, [unitSystem, inputs, customUnitNames, customFactors]);

  // --- Unit Conversion ---
  const getUnit = (field: string): string => {
    const units: Record<string, Record<UnitSystem, string>> = {
      massFlowRate: { SI: "kg/s", Imperial: "lb/s", Custom: customUnitNames.massFlowRate },
      exhaustVelocity: { SI: "m/s", Imperial: "ft/s", Custom: customUnitNames.exhaustVelocity },
      exitArea: { SI: "m²", Imperial: "ft²", Custom: customUnitNames.exitArea },
      exitPressure: { SI: "Pa", Imperial: "psi", Custom: customUnitNames.pressure },
      ambientPressure: { SI: "Pa", Imperial: "psi", Custom: customUnitNames.pressure },
      thrust: { SI: "N", Imperial: "lbf", Custom: customUnitNames.thrust },
      isp: { SI: "s", Imperial: "s", Custom: "s" },
    };
    return units[field]?.[unitSystem] || "";
  };

  const convertToSI = (value: number, field: string): number => {
    if (unitSystem === "SI") return value;
    if (unitSystem === "Imperial") {
      switch (field) {
        case "massFlowRate": return value * 0.453592; // lb/s to kg/s
        case "exhaustVelocity": return value * 0.3048; // ft/s to m/s
        case "exitArea": return value * 0.092903; // ft² to m²
        case "exitPressure":
        case "ambientPressure": return value * 6894.76; // psi to Pa
        case "thrust": return value * 4.44822; // lbf to N
        default: return value;
      }
    }
    if (unitSystem === "Custom") {
      let factorKey = field;
      if (field === "exitPressure" || field === "ambientPressure") factorKey = "pressure";
      const factor = parseFloat(customFactors[factorKey as keyof typeof customFactors]);
      return value * ((isNaN(factor) || factor === 0) ? 1.0 : factor);
    }
    return value;
  };

  const convertFromSI = (value: number, field: string): number => {
    if (unitSystem === "SI") return value;
    if (unitSystem === "Imperial") {
      switch (field) {
        case "massFlowRate": return value / 0.453592;
        case "exhaustVelocity": return value / 0.3048;
        case "exitArea": return value / 0.092903;
        case "exitPressure":
        case "ambientPressure": return value / 6894.76;
        case "thrust": return value / 4.44822;
        default: return value;
      }
    }
    if (unitSystem === "Custom") {
      let factorKey = field;
      if (field === "exitPressure" || field === "ambientPressure") factorKey = "pressure";
      const factor = parseFloat(customFactors[factorKey as keyof typeof customFactors]);
      return value / ((isNaN(factor) || factor === 0) ? 1.0 : factor);
    }
    return value;
  };

  const getG0 = () => (unitSystem === 'Imperial' ? G0_IMPERIAL : G0_SI);

  const handleInputChange = (field: string, value: string) => {
    setInputs(prev => ({ ...prev, [field]: value }));
  };

  const handleSaveCustomPreset = () => {
    if (!savePresetName.trim()) {
      toast({ title: "Error", description: "Please enter a name for the custom preset", variant: "destructive" });
      return;
    }
    const newPreset: SavedPreset = {
      name: savePresetName.trim(),
      inputs: { ...inputs },
      unitSystem,
      timestamp: Date.now(),
    };
    setCustomPresets([...customPresets, newPreset]);
    setSavePresetName("");
    setIsSaveDialogOpen(false);
    toast({ title: "Success", description: `Custom preset "${newPreset.name}" saved!` });
  };

  const handleLoadCustomPreset = (preset: SavedPreset) => {
    setInputs(preset.inputs);
    setUnitSystem(preset.unitSystem);
    setIsLoadDialogOpen(false);
    toast({ title: "Loaded", description: `Custom preset "${preset.name}" loaded!` });
  };

  const handleDeleteCustomPreset = (index: number) => {
    const preset = customPresets[index];
    setCustomPresets(customPresets.filter((_, i) => i !== index));
    toast({ title: "Deleted", description: `Custom preset "${preset.name}" deleted!` });
  };

  // --- Calculation Functions ---

  const calculatePerformance = async () => {
    try {
      const g0 = getG0(); // Get unit-specific g0
      const rawValues = {
        isp: inputs.isp.trim() ? parseFloat(inputs.isp) : undefined,
        exhaustVelocity: inputs.exhaustVelocity.trim() ? convertToSI(parseFloat(inputs.exhaustVelocity), "exhaustVelocity") : undefined,
      };

      const emptyFields = Object.entries(rawValues).filter(([_, v]) => v === undefined);
      if (emptyFields.length !== 1) {
        toast({ title: "Invalid Inputs", description: "Fill in exactly 1 field in Part 1 to solve for the other.", variant: "destructive" });
        return;
      }

      const validated = performanceSchema.parse(rawValues);
      const solveFor = emptyFields[0][0];
      // TODO: refine type for `resultData` — changed any -> unknown automatically by chore/typed-cleanup
      let resultData: Record<string, unknown> = {};
      let steps: CalculationStep[] = [{ equation: `Ve = Isp × g₀ (where g₀ ≈ ${g0.toFixed(2)})`, description: "Performance equation" }];

      if (solveFor === "exhaustVelocity") {
        const isp = validated.isp!;
        const ve = isp * G0_SI; // Always calculate in SI
        steps.push({ equation: `Ve = ${isp.toFixed(1)} × ${G0_SI.toFixed(2)}`, description: "Substitute values" });
        resultData = { exhaustVelocity: ve, isp: isp };
        setInputs(prev => ({ ...prev, exhaustVelocity: convertFromSI(ve, "exhaustVelocity").toFixed(2) }));
      } else { // solveFor === "isp"
        const ve = validated.exhaustVelocity!;
        const isp = ve / G0_SI; // Always calculate in SI
        steps.push({ equation: `Isp = Ve / g₀ = ${ve.toFixed(2)} / ${G0_SI.toFixed(2)}`, description: "Rearrange for Isp" });
        resultData = { exhaustVelocity: ve, isp: isp };
        setInputs(prev => ({ ...prev, isp: isp.toFixed(1) }));
      }
      
      const calculationSteps = steps.map(step => `${step.description}: ${step.equation}`);

      setPerformanceResult({ ...resultData, steps, solvedFor: solveFor });
      setThrustResult(null); // Clear thrust results
      setChartData([]);
      
      const payload = buildAeroversePayload({
        toolName: "Thrust Calculator",
        inputs: {
          unitSystem,
          solveMode: "performance",
          isp_input: inputs.isp || null,
          exhaustVelocity_input: inputs.exhaustVelocity || null,
        },
        results: {
          isp_s: resultData.isp ?? null,
          exhaustVelocity_m_s: resultData.exhaustVelocity ?? null,
          solvedFor: solveFor,
        },
        units: {
          isp_s: "s",
          exhaustVelocity_m_s: "m/s",
        },
        metadata: {
          steps: calculationSteps,
          unitsSystem: unitSystem,
          approxLevel: "analytic",
          confidence: "high",
        },
      });

      await applyToolPayload(payload);

    } catch (error) {
      if (error instanceof z.ZodError) {
        toast({ title: "Invalid Input", description: error.errors[0]?.message, variant: "destructive" });
      } else {
        toast({ title: "Calculation Error", description: (error as Error).message, variant: "destructive" });
      }
    }
  };

  const calculateThrust = async () => {
    try {
      const rawValues = {
        massFlowRate: inputs.massFlowRate.trim() ? convertToSI(parseFloat(inputs.massFlowRate), "massFlowRate") : undefined,
        exhaustVelocity: inputs.exhaustVelocity.trim() ? convertToSI(parseFloat(inputs.exhaustVelocity), "exhaustVelocity") : undefined,
        exitArea: inputs.exitArea.trim() ? convertToSI(parseFloat(inputs.exitArea), "exitArea") : undefined,
        exitPressure: inputs.exitPressure.trim() ? convertToSI(parseFloat(inputs.exitPressure), "exitPressure") : undefined,
        ambientPressure: inputs.ambientPressure.trim() ? convertToSI(parseFloat(inputs.ambientPressure), "ambientPressure") : undefined,
        thrust: inputs.thrust.trim() ? convertToSI(parseFloat(inputs.thrust), "thrust") : undefined,
      };

      const emptyFields = Object.entries(rawValues).filter(([_, v]) => v === undefined);
      if (emptyFields.length !== 1) {
        toast({ title: "Invalid Inputs", description: "Fill in all but one field in Part 2 to solve.", variant: "destructive" });
        return;
      }

      const validated = thrustSchema.parse(rawValues);
      const solveFor = emptyFields[0][0];
      // TODO: refine type for `resultData` — changed any -> unknown automatically by chore/typed-cleanup
      let resultData: Record<string, unknown> = {};
      // Physics: Thrust equation F = ṁVe + (Pe - Pa)Ae
      // where ṁ = mass flow rate, Ve = exhaust velocity, Pe = exit pressure, Pa = ambient pressure, Ae = exit area
      let steps: CalculationStep[] = [{ equation: "F = ṁVe + (Pe - Pa)Ae", description: "Thrust equation" }];

      // FIXED: Add validation for physical constraints
      if (validated.massFlowRate !== undefined && validated.massFlowRate < 0) {
        throw new Error("Mass flow rate must be non-negative");
      }
      if (validated.exitArea !== undefined && validated.exitArea <= 0) {
        throw new Error("Exit area must be positive");
      }
      if (validated.exhaustVelocity !== undefined && validated.exhaustVelocity <= 0) {
        throw new Error("Exhaust velocity must be positive");
      }

      // Pre-calculate Isp if Ve is known
      // Physics: Isp = Ve / g₀ where g₀ = 9.80665 m/s²
      let isp: number | undefined = undefined;
      if (validated.exhaustVelocity) {
        isp = validated.exhaustVelocity / G0_SI;
      }

      switch (solveFor) {
        case "thrust": {
          const { massFlowRate, exhaustVelocity, exitArea, exitPressure, ambientPressure } = validated;
          const mdot = massFlowRate!;
          const ve = exhaustVelocity!;
          const ae = exitArea!;
          const pe = exitPressure!;
          const pa = ambientPressure!;
          const momentumThrust = mdot * ve;
          const pressureThrust = (pe - pa) * ae;
          const totalThrust = momentumThrust + pressureThrust;
          steps.push({ equation: `F = ${mdot.toFixed(2)}×${ve.toFixed(2)} + (${pe.toFixed(0)} - ${pa.toFixed(0)})×${ae.toFixed(4)}`, description: "Substitute values" });
          resultData = { thrust: totalThrust, momentumThrust, pressureThrust, isp };
          break;
        }
        case "massFlowRate": {
          const { thrust, exhaustVelocity, exitArea, exitPressure, ambientPressure } = validated;
          const pressureThrust = (exitPressure! - ambientPressure!) * exitArea!;
          if (exhaustVelocity === 0) throw new Error("Exhaust Velocity cannot be zero.");
          const mdot = (thrust! - pressureThrust) / exhaustVelocity!;
          steps.push({ equation: "ṁ = (F - (Pe - Pa)Ae) / Ve", description: "Rearrange for ṁ" });
          resultData = { massFlowRate: mdot, momentumThrust: mdot * exhaustVelocity!, pressureThrust, isp };
          break;
        }
        case "exhaustVelocity": {
          const { thrust, massFlowRate, exitArea, exitPressure, ambientPressure } = validated;
          const pressureThrust = (exitPressure! - ambientPressure!) * exitArea!;
          if (massFlowRate === 0) throw new Error("Mass Flow Rate cannot be zero.");
          const ve = (thrust! - pressureThrust) / massFlowRate!;
          isp = ve / G0_SI; // Calculate the resulting Isp
          steps.push({ equation: "Ve = (F - (Pe - Pa)Ae) / ṁ", description: "Rearrange for Ve" });
          resultData = { exhaustVelocity: ve, momentumThrust: massFlowRate! * ve, pressureThrust, isp };
          // Auto-populate Part 1
          setInputs(prev => ({ ...prev, isp: isp!.toFixed(1) }));
          break;
        }
        case "exitArea": {
          const { thrust, massFlowRate, exhaustVelocity, exitPressure, ambientPressure } = validated;
          const momentumThrust = massFlowRate! * exhaustVelocity!;
          const pressureDiff = exitPressure! - ambientPressure!;
          if (pressureDiff === 0) throw new Error("Pressure difference (Pe - Pa) cannot be zero.");
          const ae = (thrust! - momentumThrust) / pressureDiff;
          steps.push({ equation: "Ae = (F - ṁVe) / (Pe - Pa)", description: "Rearrange for Ae" });
          resultData = { exitArea: ae, momentumThrust, pressureThrust: (thrust! - momentumThrust), isp };
          break;
        }
        case "exitPressure": {
          const { thrust, massFlowRate, exhaustVelocity, exitArea, ambientPressure } = validated;
          const momentumThrust = massFlowRate! * exhaustVelocity!;
          if (exitArea === 0) throw new Error("Exit Area cannot be zero.");
          const pe = ambientPressure! + (thrust! - momentumThrust) / exitArea!;
          steps.push({ equation: "Pe = Pa + (F - ṁVe) / Ae", description: "Rearrange for Pe" });
          resultData = { exitPressure: pe, momentumThrust, pressureThrust: (thrust! - momentumThrust), isp };
          break;
        }
        case "ambientPressure": {
          const { thrust, massFlowRate, exhaustVelocity, exitArea, exitPressure } = validated;
          const momentumThrust = massFlowRate! * exhaustVelocity!;
          if (exitArea === 0) throw new Error("Exit Area cannot be zero.");
          const pa = exitPressure! - (thrust! - momentumThrust) / exitArea!;
          steps.push({ equation: "Pa = Pe - (F - ṁVe) / Ae", description: "Rearrange for Pa" });
          resultData = { ambientPressure: pa, momentumThrust, pressureThrust: (thrust! - momentumThrust), isp };
          break;
        }
      }

      setThrustResult({ ...resultData, steps, solvedFor: solveFor });
      setPerformanceResult(null); // Clear performance results
      
      // Prepare calculation steps for event
      const calculationSteps = steps.map(step => 
        `${step.description}: ${step.equation}`
      );
      
      const payload = buildAeroversePayload({
        toolName: "Thrust Calculator",
        inputs: {
          massFlowRate_kg_s: validated.massFlowRate ?? null,
          exhaustVelocity_m_s: validated.exhaustVelocity ?? null,
          exitArea_m2: validated.exitArea ?? null,
          exitPressure_Pa: validated.exitPressure ?? null,
          ambientPressure_Pa: validated.ambientPressure ?? null,
          thrust_N: validated.thrust ?? null,
          solvedFor: solveFor,
          unitSystem,
        },
        results: {
          ...resultData,
          solvedFor: solveFor,
        },
        units: {
          massFlowRate_kg_s: "kg/s",
          exhaustVelocity_m_s: "m/s",
          exitArea_m2: "m²",
          exitPressure_Pa: "Pa",
          ambientPressure_Pa: "Pa",
          thrust_N: "N",
          isp: "s",
        },
        charts: [
          { id: "thrust-vs-pressure", title: "Thrust vs Ambient Pressure", dataSummary: "Sweep results" },
        ],
        metadata: {
          steps: calculationSteps,
          unitsSystem: unitSystem,
          approxLevel: "analytic",
          confidence: "high",
        },
      });

      await applyToolPayload(payload);
      
      // FIXED: Generate Chart with simplified loop and proper validation
      if (validated.massFlowRate && validated.exhaustVelocity && validated.exitArea && validated.exitPressure) {
        const { massFlowRate, exhaustVelocity, exitArea, exitPressure } = validated;
        const data = [];
        // FIXED: Use standard atmospheric pressure as default if ambient not provided
        const pa_base = validated.ambientPressure ?? 101325; // Standard sea-level pressure in Pa
        const maxPa = Math.max(pa_base * 2, 202650); // Ensure reasonable range
        const stepSize = maxPa / 20;
        
        for (let pa_current = 0; pa_current <= maxPa; pa_current += stepSize) {
          // Physics: F = ṁVe + (Pe - Pa)Ae
          const f = massFlowRate! * exhaustVelocity! + (exitPressure! - pa_current) * exitArea!;
          data.push({
            ambientPressure: convertFromSI(pa_current, "ambientPressure"),
            thrust: convertFromSI(f, "thrust")
          });
        }
        setChartData(data);
      } else {
        setChartData([]);
      }

    } catch (error) {
      if (error instanceof z.ZodError) {
        toast({ title: "Invalid Input", description: error.errors[0]?.message, variant: "destructive" });
      } else {
        toast({ title: "Calculation Error", description: (error as Error).message, variant: "destructive" });
      }
    }
  };

  const resetCalculators = () => {
    setInputs({ massFlowRate: "", exhaustVelocity: "", exitArea: "", exitPressure: "", ambientPressure: "", thrust: "", isp: "" });
    setThrustResult(null);
    setPerformanceResult(null);
    setChartData([]);
  };

  // --- Render ---
  return (
    <ToolWrapper>
      <ToolHeader
        title="Advanced Rocket Thrust Calculator"
        description="Calculate engine performance (I_sp) and solve for any variable in the thrust equation"
        icon={Rocket}
        actions={
          <ToolActions>
            <Select value={unitSystem} onValueChange={(v) => setUnitSystem(v as UnitSystem)}>
              <SelectTrigger className="w-32 bg-slate-900/50 border-cyan-400/30 text-cyan-400"><SelectValue /></SelectTrigger>
              <SelectContent>
                <SelectItem value="SI">SI (Metric)</SelectItem>
                <SelectItem value="Imperial">Imperial</SelectItem>
                <SelectItem value="Custom">Custom</SelectItem>
              </SelectContent>
            </Select>
            <AeroButton type="button" onClick={resetCalculators} variant="outline">Reset All</AeroButton>
            <AeroButton
              type="button"
              onClick={() => setIsSaveDialogOpen(true)}
              variant="outline"
              icon={Save}
            >
              Save Preset
            </AeroButton>
            <AeroButton
              type="button"
              onClick={() => setIsLoadDialogOpen(true)}
              variant="outline"
              icon={FolderOpen}
              disabled={customPresets.length === 0}
            >
              Load ({customPresets.length})
            </AeroButton>
          </ToolActions>
        }
      />

      <ToolSection gridCols={2}>
        {/* --- LEFT COLUMN (INPUTS) --- */}
        <div>
          <div className={spacingVertical.L}>
            {/* --- Part 1: Performance (Isp) --- */}
            <AeroCard
              title="Part 1: Performance (Isp ↔ Ve)"
              description="Solve for I_sp or V_e. Fill 1 of 2 fields. V_e links to Part 2."
              icon={Anchor}
            >
              <AeroFormField label={`Specific Impulse (I_sp) ${getUnit("isp")}`}>
                <Input id="isp" type="number" step="0.1" value={inputs.isp} onChange={(e) => handleInputChange("isp", e.target.value)} className="bg-slate-900/50 border-cyan-400/30" placeholder="e.g., 310" />
              </AeroFormField>
              <AeroFormField label={`Exhaust Velocity (V_e) ${getUnit("exhaustVelocity")}`}>
                <Input id="exhaustVelocity" type="number" step="0.01" value={inputs.exhaustVelocity} onChange={(e) => handleInputChange("exhaustVelocity", e.target.value)} className="bg-slate-900/50 border-cyan-400/30" placeholder="e.g., 3040" />
              </AeroFormField>
              <AeroButton type="button" onClick={calculatePerformance} variant="primary" icon={Anchor} className="w-full">
                Calculate Part 1
              </AeroButton>
            </AeroCard>

            {/* --- Part 2: Thrust Solver --- */}
            <AeroCard
              title="Part 2: Thrust Solver"
              description="Solve for any 1 variable. Fill all other 5 fields."
              icon={Calculator}
            >
              <div className="grid grid-cols-2 gap-4">
                <AeroFormField label={`Thrust (F) ${getUnit("thrust")}`}>
                  <Input id="thrust" type="number" step="0.01" value={inputs.thrust} onChange={(e) => handleInputChange("thrust", e.target.value)} className="bg-slate-900/50 border-cyan-400/30" placeholder="Leave blank" />
                </AeroFormField>
                <AeroFormField label={`Mass Flow (ṁ) ${getUnit("massFlowRate")}`}>
                  <Input id="massFlowRate" type="number" step="0.01" value={inputs.massFlowRate} onChange={(e) => handleInputChange("massFlowRate", e.target.value)} className="bg-slate-900/50 border-cyan-400/30" placeholder="Leave blank" />
                </AeroFormField>
                <AeroFormField label={`Exit Area (Ae) ${getUnit("exitArea")}`}>
                  <Input id="exitArea" type="number" step="0.001" value={inputs.exitArea} onChange={(e) => handleInputChange("exitArea", e.target.value)} className="bg-slate-900/50 border-cyan-400/30" placeholder="Leave blank" />
                </AeroFormField>
                <AeroFormField label={`Exhaust Velocity (V_e) ${getUnit("exhaustVelocity")}`} helperText="From Part 1">
                  <Input id="exhaustVelocity_part2" type="number" step="0.01" value={inputs.exhaustVelocity} onChange={(e) => handleInputChange("exhaustVelocity", e.target.value)} className="bg-slate-900/50 border-cyan-400/30" placeholder="From Part 1" />
                </AeroFormField>
                <AeroFormField label={`Exit Pressure (Pe) ${getUnit("exitPressure")}`}>
                  <Input id="exitPressure" type="number" step="1" value={inputs.exitPressure} onChange={(e) => handleInputChange("exitPressure", e.target.value)} className="bg-slate-900/50 border-cyan-400/30" placeholder="Leave blank" />
                </AeroFormField>
                <AeroFormField label={`Ambient Pressure (Pa) ${getUnit("ambientPressure")}`}>
                  <Input id="ambientPressure" type="number" step="1" value={inputs.ambientPressure} onChange={(e) => handleInputChange("ambientPressure", e.target.value)} className="bg-slate-900/50 border-cyan-400/30" placeholder="Leave blank" />
                </AeroFormField>
              </div>
              <AeroButton type="button" onClick={calculateThrust} variant="primary" icon={Calculator} className="w-full">
                Calculate Thrust
              </AeroButton>
            </AeroCard>

            {/* --- Custom Units --- */}
            {unitSystem === "Custom" && (
              <AeroCard
                title="Custom Unit Definitions"
                description="Define conversion factors to SI (kg, m, s, N, Pa)"
                icon={Settings2}
              >
                {[
                  {id: 'thrust', label: 'Thrust (F)', unit: 'N'},
                  {id: 'massFlowRate', label: 'Mass Flow (ṁ)', unit: 'kg/s'},
                  {id: 'exhaustVelocity', label: 'Exhaust Velocity (Ve)', unit: 'm/s'},
                  {id: 'exitArea', label: 'Area (Ae)', unit: 'm²'},
                  {id: 'pressure', label: 'Pressure (P)', unit: 'Pa'},
                ].map(field => (
                  <div key={field.id} className="p-3 bg-slate-900/50 rounded-lg border border-cyan-400/10 mb-4">
                    <Label className="text-white font-semibold">{field.label}</Label>
                    <div className="grid grid-cols-2 gap-2 mt-2">
                      <Input 
                        placeholder="Unit Name" 
                        value={customUnitNames[field.id as keyof typeof customUnitNames]}
                        onChange={(e) => setCustomUnitNames(p => ({...p, [field.id]: e.target.value}))}
                        className="bg-slate-800 border-cyan-400/30 text-white"
                      />
                      <Input 
                        type="number"
                        placeholder="SI Factor"
                        value={customFactors[field.id as keyof typeof customFactors]}
                        onChange={(e) => setCustomFactors(p => ({...p, [field.id]: e.target.value}))}
                        className="bg-slate-800 border-cyan-400/30 text-white"
                      />
                    </div>
                    <p className="text-xs text-gray-500 mt-1.5">1 {customUnitNames[field.id as keyof typeof customUnitNames] || "Unit"} = {customFactors[field.id as keyof typeof customFactors] || "..."} {field.unit}</p>
                  </div>
                ))}
              </AeroCard>
            )}
          </div>
        </div>

        {/* --- RIGHT COLUMN (RESULTS & THEORY) --- */}
        <div>
          <div className={spacingVertical.L}>
            {/* --- Results Card --- */}
            <AeroCard
              title="Results"
              headerActions={
                lastPayload ? (
                  <div className="flex gap-2">
                    <AskAIButton 
                      requestId={lastRequestId} 
                      payload={lastPayload}
                      disabled={!lastPayload}
                    />
                    <PDFExportButton 
                      requestId={lastRequestId} 
                      toolName="Thrust Calculator"
                      disabled={!lastRequestId}
                    />
                  </div>
                ) : null
              }
            >
              {/* Performance Result */}
              {performanceResult && typeof performanceResult === 'object' && 'solvedFor' in performanceResult && (
                <div className="p-4 bg-gradient-to-r from-green-400/10 to-cyan-400/10 rounded-lg border border-green-400/30 mb-4">
                  <p className="text-sm font-semibold text-green-400 mb-2">Part 1 Result (Performance)</p>
                  <p className="text-gray-400 text-sm mb-1">Solved: {(performanceResult as unknown as { solvedFor?: string }).solvedFor}</p>
                  <p className="text-3xl font-bold text-green-400 drop-shadow-[0_0_10px_rgba(74,222,128,0.8)]">
                    {(performanceResult as unknown as { isp?: number }).isp ? `${((performanceResult as unknown as { isp: number }).isp).toFixed(1)} ${getUnit("isp")}`
                    : `${convertFromSI((performanceResult as unknown as { exhaustVelocity: number }).exhaustVelocity, "exhaustVelocity").toFixed(2)} ${getUnit("exhaustVelocity")}`
                    }
                  </p>
                </div>
              )}
              
              {/* Thrust Result */}
              {thrustResult && typeof thrustResult === 'object' && 'solvedFor' in thrustResult && (
                <div className="p-4 bg-gradient-to-r from-cyan-400/10 to-blue-400/10 rounded-lg border border-cyan-400/30 mb-4">
                  <p className="text-sm font-semibold text-cyan-400 mb-2">Part 2 Result (Thrust)</p>
                    <p className="text-gray-400 text-sm mb-1">Solved: {(thrustResult as { solvedFor?: string }).solvedFor}</p>
                    <p className="text-3xl font-bold text-cyan-400 drop-shadow-[0_0_10px_rgba(34,211,238,0.8)]">
                      {(() => {
                        const tr = thrustResult as { thrust?: number; massFlowRate?: number; exhaustVelocity?: number; exitArea?: number; exitPressure?: number; ambientPressure?: number };
                        if (tr.thrust) return `${convertFromSI(tr.thrust, "thrust").toFixed(2)} ${getUnit("thrust")}`;
                        if (tr.massFlowRate) return `${convertFromSI(tr.massFlowRate, "massFlowRate").toFixed(4)} ${getUnit("massFlowRate")}`;
                        if (tr.exhaustVelocity) return `${convertFromSI(tr.exhaustVelocity, "exhaustVelocity").toFixed(2)} ${getUnit("exhaustVelocity")}`;
                        if (tr.exitArea) return `${convertFromSI(tr.exitArea, "exitArea").toFixed(6)} ${getUnit("exitArea")}`;
                        if (tr.exitPressure) return `${convertFromSI(tr.exitPressure, "exitPressure").toFixed(0)} ${getUnit("exitPressure")}`;
                        return `${convertFromSI(tr.ambientPressure ?? 0, "ambientPressure").toFixed(0)} ${getUnit("ambientPressure")}`;
                      })()}
                    </p>
                    <div className="mt-4 grid grid-cols-3 gap-3">
                      <div className="p-3 bg-slate-900/50 rounded-lg border border-cyan-400/20">
                        <p className="text-gray-400 text-xs mb-1">Momentum Thrust</p>
                        <p className="text-lg font-semibold text-blue-400">{convertFromSI((thrustResult as { momentumThrust?: number }).momentumThrust ?? 0, "thrust").toFixed(2)} {getUnit("thrust")}</p>
                      </div>
                      <div className="p-3 bg-slate-900/50 rounded-lg border border-cyan-400/20">
                        <p className="text-gray-400 text-xs mb-1">Pressure Thrust</p>
                        <p className="text-lg font-semibold text-blue-400">{convertFromSI((thrustResult as { pressureThrust?: number }).pressureThrust ?? 0, "thrust").toFixed(2)} {getUnit("thrust")}</p>
                      </div>
                      <div className="p-3 bg-slate-900/50 rounded-lg border border-cyan-400/20">
                        <p className="text-gray-400 text-xs mb-1">Specific Impulse</p>
                        <p className="text-lg font-semibold text-blue-400">{(thrustResult as unknown as { isp?: number }).isp ? (thrustResult as unknown as { isp: number }).isp.toFixed(1) : "N/A"} s</p>
                      </div>
                    </div>
                  </div>
                )}
                
                {/* Steps (if any result exists) */}
                {(thrustResult || performanceResult) && (
                  <Accordion type="single" collapsible className="w-full">
                    <AccordionItem value="steps" className="border-cyan-400/20">
                      <AccordionTrigger className="text-white hover:text-cyan-400"><div className="flex items-center gap-2"><Info className="w-4 h-4 text-cyan-400" />Step-by-Step Solution</div></AccordionTrigger>
                      <AccordionContent className="pt-2">
                        <CalculationSteps steps={((thrustResult as { steps?: string[] })?.steps || (performanceResult as { steps?: string[] })?.steps) || []} />
                      </AccordionContent>
                    </AccordionItem>
                  </Accordion>
                )}

            </AeroCard>

            {/* Chart (if thrust result exists) */}
            {chartData.length > 0 && (
              <ChartCard 
                title="Thrust vs. Ambient Pressure"
                height={300}
                icon={TrendingUp}
              >
                <ResponsiveContainer width="100%" height={300}>
                  <LineChart data={chartData}>
                    <CartesianGrid strokeDasharray="3 3" stroke="#334155" />
                    <XAxis dataKey="ambientPressure" stroke="#94a3b8" tickFormatter={(val) => val.toFixed(0)}
                      label={{ value: `Ambient Pressure (${getUnit("ambientPressure")})`, position: 'insideBottom', offset: -5, fill: '#94a3B8' }}/>
                    <YAxis stroke="#94a3b8" tickFormatter={(val) => val.toFixed(0)}
                      label={{ value: `Thrust (${getUnit("thrust")})`, angle: -90, position: 'insideLeft', fill: '#94a3b8' }}/>
                    <RechartsTooltip contentStyle={{ backgroundColor: '#1e293b', border: '1px solid #22d3ee40' }} formatter={(value: number) => value.toFixed(2)}/>
                    <Line type="monotone" dataKey="thrust" stroke="#22d3ee" strokeWidth={2} dot={false} name="Thrust" legendType="none" />
                  </LineChart>
                </ResponsiveContainer>
                <div className="mt-3 pt-3 border-t border-slate-700/50">
                  <AeroverseLegend
                    items={[{
                      id: 'thrust',
                      name: 'Thrust',
                      color: '#22d3ee',
                    }]}
                  />
                </div>
              </ChartCard>
            )}
            
            {/* Placeholder */}
            {!thrustResult && !performanceResult && (
              <AeroCard title="Results">
                <div className="text-center py-12">
                  <Calculator className="w-16 h-16 mx-auto mb-4 text-cyan-400/30" />
                  <p className="text-gray-400">Results will appear here</p>
                </div>
              </AeroCard>
            )}

            {/* --- Theory Card --- */}
            <AeroCard title="Theory & Formulas" icon={Info}>
              <div className="p-4 bg-slate-900/50 rounded-lg border border-cyan-400/30 mb-4">
                <p className="text-center text-lg font-mono text-cyan-400 mb-2">V_e = I_sp · g_0</p>
                <div className="text-gray-400 text-sm space-y-1">
                  <p><span className="text-cyan-400">V_e</span> = Exhaust Velocity</p>
                  <p><span className="text-cyan-400">I_sp</span> = Specific Impulse</p>
                  <p><span className="text-cyan-400">g_0</span> = Std. Gravity (≈ 9.81 m/s²)</p>
                </div>
