export default function PowerSystemCalculator() {
  const { sendCalculationEvent, updateToolContext } = useToolContext();
  const { toast } = useToast();
  const [lastRequestId, setLastRequestId] = useState<string | null>(null);
  const [lastPayload, setLastPayload] = useState<AeroverseAIPayload | null>(null);
  
  // Battery state
  const [pack, setPack] = useState<BatteryPack>(() => {
    const chemistry = getBatteryChemistry('lipo');
    if (!chemistry) throw new Error('Default battery chemistry not found');
    return {
      chemistry,
      capacity_mAh: 5000,
      S_count: 4,
      P_count: 1,
      cycles: 0,
      temperature: 25,
    };
  });
  
  // Solar state
  const [solarConfig, setSolarConfig] = useState<SolarConfig>({
    area_m2: 0.5,
    efficiency: 0.22,
    mpptEfficiency: 0.95,
    tilt: 30,
    azimuth: 180, // South-facing
  });
  
  // Load state
  const [loads, setLoads] = useState<PowerLoad>({
    propulsion: 200,
    avionics: 10,
    servos: 5,
    cameras: 5,
    telemetry: 2,
  });
  
  // Mission state
  const [phases, setPhases] = useState<MissionPhase[]>([
    {
      name: 'Takeoff',
      startTime_min: 0,
      duration_min: 2,
      loadMultiplier: 2.0,
      solarAvailable: true,
      altitude: 0,
    },
    {
      name: 'Cruise',
      startTime_min: 2,
      duration_min: 60,
      loadMultiplier: 1.0,
      solarAvailable: true,
      altitude: 1000,
    },
  ]);
  
  // Location state
  const [location, setLocation] = useState({
    latitude: 40.0,
    longitude: -74.0,
    altitude: 0,
  });
  
  const [dayOfYear, setDayOfYear] = useState(180); // Mid-year (summer)
  
  // Results state
  const [result, setResult] = useState<MissionResult | null>(null);

  const getLatestStoredRequestId = useCallback((): string | null => {
    try {
      const storedKeys = Object.keys(localStorage).filter((key) => key.startsWith('calc-'));
      if (storedKeys.length === 0) return null;
      const latestKey = storedKeys.sort().reverse()[0];
      return latestKey.replace('calc-', '');
    } catch (error) {
      console.warn('Unable to read stored calculation IDs:', error);
      return null;
    }
  }, []);

  const applyToolPayload = useCallback(
    async (payload: AeroverseAIPayload) => {
      setLastPayload(payload);

      updateToolContext({
        tool: 'Battery & Solar Power System',
        inputs: payload.inputs,
        results: payload.results,
      });

      const eventPayload = buildCalculationEvent({
        toolId: 'power-system',
        toolName: payload.toolName,
        inputs: payload.inputs,
        results: payload.results,
        steps: payload.metadata.steps,
        metadata: {
          units: payload.metadata.unitsSystem,
          approxLevel: payload.metadata.approxLevel,
          confidence: payload.metadata.confidence,
          warnings: payload.metadata.warnings,
        },
      });

      try {
        const eventResponse = await sendCalculationEvent(eventPayload);
        const requestId = eventResponse?.requestId ?? getLatestStoredRequestId();
        setLastRequestId(requestId);
        return requestId;
      } catch (error) {
        console.warn('Failed to send calculation event:', error);
        const fallbackId = getLatestStoredRequestId();
        setLastRequestId(fallbackId);
        return fallbackId;
      }
    },
    [getLatestStoredRequestId, sendCalculationEvent, updateToolContext]
  );
  
  // Memoize expensive calculations
  const missionResult = useMemo(() => {
    if (!result) return null;
    return result;
  }, [result]);

  // Calculate mission
    const handleUserCalculate = useCallback(async () => {
    try {
      // Validate inputs
      const validation = validatePowerSystemInputs({
        battery: {
          chemistryId: pack.chemistry.id,
          capacity_mAh: pack.capacity_mAh,
          S_count: pack.S_count,
          P_count: pack.P_count,
          cycles: pack.cycles,
          temperature: pack.temperature,
        },
        solar: solarConfig,
        loads,
        location,
        dayOfYear,
      });
      
      if (!validation.valid) {
        toast({
          title: 'Validation Error',
          description: validation.errors.join(', '),
          variant: 'destructive',
        });
        return;
      }
      
      // Show warnings
      if (validation.warnings.length > 0) {
        validation.warnings.forEach((warning) => {
          toast({
            title: 'Warning',
            description: warning,
            variant: 'default',
          });
        });
      }
      
      // Run simulation
      const missionResult = simulateMission(
        pack,
        solarConfig,
        loads,
        phases,
        location,
        dayOfYear,
        1 // 1 minute time steps
      );
      
      setResult(missionResult);
      
        // Build AI payload
        const payload = buildPowerSystemPayload(
        pack,
        solarConfig,
        loads,
        location,
        dayOfYear,
          missionResult
      );

        await applyToolPayload(payload);
      
      toast({
        title: 'Simulation Complete',
        description: `Endurance: ${(missionResult.endurance_min / 60).toFixed(1)} hours`,
      });
    } catch (error) {
      console.error('Power system calculation error:', error);
      const errorMessage = error instanceof Error ? error.message : 'Unknown error occurred';
      toast({
        title: 'Calculation Error',
        description: errorMessage,
        variant: 'destructive',
      });
    }
    }, [applyToolPayload, pack, solarConfig, loads, phases, location, dayOfYear, toast]);
  
  return (
    <ErrorBoundary toolName="Battery & Solar Power System">
      <ToolWrapper>
        <ToolHeader
          title="Battery & Solar Power System"
          description="Ultra-high-fidelity energy modeling for UAVs, aircraft, rockets, and CubeSats"
          icon={Battery}
        />
      
      <Tabs defaultValue="battery" className="w-full">
        <TabsList className="grid w-full grid-cols-6 bg-slate-800/50">
          <TabsTrigger value="battery">Battery</TabsTrigger>
          <TabsTrigger value="solar">Solar</TabsTrigger>
          <TabsTrigger value="loads">Loads</TabsTrigger>
          <TabsTrigger value="mission">Mission</TabsTrigger>
          <TabsTrigger value="environment">Environment</TabsTrigger>
          <TabsTrigger value="results">Results</TabsTrigger>
        </TabsList>
        
        <TabsContent value="battery">
          <ToolSection>
            <BatteryPackForm pack={pack} onPackChange={setPack} />
          </ToolSection>
        </TabsContent>
        
        <TabsContent value="solar">
          <ToolSection>
            <SolarConfigComponent config={solarConfig} onConfigChange={setSolarConfig} />
          </ToolSection>
        </TabsContent>
        
        <TabsContent value="loads">
          <ToolSection>
            <LoadProfile loads={loads} onLoadsChange={setLoads} />
          </ToolSection>
        </TabsContent>
        
        <TabsContent value="mission">
          <ToolSection>
            <MissionTimeline phases={phases} onPhasesChange={setPhases} />
          </ToolSection>
        </TabsContent>
        
        <TabsContent value="environment">
          <ToolSection>
            <div className="space-y-6">
              <div className="grid grid-cols-3 gap-4">
                <div>
                  <label className="text-sm text-gray-400 mb-1 block">Latitude (°)</label>
                  <input
                    type="number"
                    value={location.latitude}
                    onChange={(e) => setLocation({ ...location, latitude: parseFloat(e.target.value) || 0 })}
                    className="w-full px-3 py-2 bg-slate-700/50 border border-cyan-400/30 rounded text-white"
                    min="-90"
                    max="90"
                    step="0.1"
                  />
                </div>
                <div>
                  <label className="text-sm text-gray-400 mb-1 block">Longitude (°)</label>
                  <input
                    type="number"
                    value={location.longitude}
                    onChange={(e) => setLocation({ ...location, longitude: parseFloat(e.target.value) || 0 })}
                    className="w-full px-3 py-2 bg-slate-700/50 border border-cyan-400/30 rounded text-white"
                    min="-180"
                    max="180"
                    step="0.1"
                  />
                </div>
                <div>
                  <label className="text-sm text-gray-400 mb-1 block">Altitude (m)</label>
                  <input
                    type="number"
                    value={location.altitude}
                    onChange={(e) => setLocation({ ...location, altitude: parseFloat(e.target.value) || 0 })}
                    className="w-full px-3 py-2 bg-slate-700/50 border border-cyan-400/30 rounded text-white"
                    min="0"
                    step="100"
                  />
                </div>
              </div>
              
              <div>
                <label className="text-sm text-gray-400 mb-1 block">Day of Year (1-365)</label>
                <input
                  type="number"
                  value={dayOfYear}
                  onChange={(e) => setDayOfYear(Math.max(1, Math.min(365, parseInt(e.target.value) || 180)))}
                  className="w-full px-3 py-2 bg-slate-700/50 border border-cyan-400/30 rounded text-white"
                  min="1"
                  max="365"
                  step="1"
                />
                <p className="text-xs text-gray-400 mt-1">
                  Day 1 = Jan 1, Day 180 = June 29 (summer), Day 365 = Dec 31
                </p>
              </div>
            </div>
          </ToolSection>
        </TabsContent>
        
        <TabsContent value="results">
          <ToolSection>
            <ResultsPanel result={result} />
          </ToolSection>
          
          {result && (
            <ToolSection>
              <ChartsPanel result={result} />
            </ToolSection>
          )}
        </TabsContent>
      </Tabs>
      
      <ToolActions>
          <AeroButton onClick={handleUserCalculate} icon={Calculator}>
          Run Simulation
        </AeroButton>
          {result && lastRequestId && lastPayload && (
          <>
            <AskAIButton 
              requestId={lastRequestId} 
                payload={lastPayload}
            />
            <PDFExportButton toolName="Battery & Solar Power System" requestId={lastRequestId} />
          </>
        )}
      </ToolActions>
      </ToolWrapper>
    </ErrorBoundary>
  );
}

/**
 * Rocket Engine Performance & Nozzle Flow Calculator
 * 
 * High-fidelity isentropic flow analysis with practical corrections
 * Based on Sutton & Biblarz, Anderson, and standard compressible flow theory
 */

"use client";

import { useState, useCallback, useMemo } from 'react';
import { Rocket, Calculator } from 'lucide-react';
import { ToolWrapper } from '@/components/layout/ToolWrapper';
import { ToolHeader } from '@/components/layout/ToolHeader';
import { ToolSection } from '@/components/layout/ToolSection';
import { ToolActions } from '@/components/layout/ToolActions';
import { AeroButton } from '@/components/common/AeroButton';
import { useToolContext } from '@/hooks/useToolContext';
import { PDFExportButton } from '@/components/tools/PDFExportButton';
import { AskAIButton } from '@/components/tools/AskAIButton';
import { useToast } from '@/hooks/use-toast';
import { 
  calculateRocketEngine, 
  sweepAmbientPressure,
  sweepExpansionRatio,
  sweepChamberPressure,
  RocketEngineInputs, 
  RocketEngineResults 
} from './utils/calcEngine';
import { validateRocketEngineInputs } from './validation/schema';
import { buildRocketEnginePayload } from './utils/payloadBuilder';
import { buildCalculationEvent } from '@/lib/events/payloadBuilder';
import type { AeroverseAIPayload } from '@/ai/schema/AerorbisPayload';
import { PROPELLANT_PRESETS, ENGINE_PRESETS, PropellantPreset, EnginePreset } from './data/propellantPresets';
import { InputPanel } from './components/InputPanel';
import { ResultsPanel } from './components/ResultsPanel';
import { PlotsPanel } from './components/PlotsPanel';
import { PresetsPanel } from './components/PresetsPanel';
import { DEFAULT_GAMMA, DEFAULT_NOZZLE_EFFICIENCY, DEFAULT_CSTAR_EFFICIENCY, DEFAULT_PRESSURE_LOSS, R_UNIVERSAL } from './utils/constants';
import { altitudeToPressure } from './utils/units';

export { handleCalculate } from './handleCalculate';

export default function RocketEngineCalculator() {
  const { sendCalculationEvent, updateToolContext } = useToolContext();
  const { toast } = useToast();
  const [lastRequestId, setLastRequestId] = useState<string | null>(null);
  const [lastPayload, setLastPayload] = useState<AeroverseAIPayload | null>(null);

  // Input state
  const [inputs, setInputs] = useState<RocketEngineInputs>({
    Pc: 9.7e6, // 97 bar
    Tc: 3500,
    At: 0.005, // 50 cm²
    epsilon: 16,
    Pa: 101325, // Sea level
    gamma: DEFAULT_GAMMA,
    M_molar: 22.0,
    nozzleEfficiency: DEFAULT_NOZZLE_EFFICIENCY,
    cStarEfficiency: DEFAULT_CSTAR_EFFICIENCY,
    pressureLossFraction: DEFAULT_PRESSURE_LOSS,
  });

  const [results, setResults] = useState<RocketEngineResults | null>(null);
  const [selectedPropellantId, setSelectedPropellantId] = useState<string>('lox-rp1');
  const [selectedEngineId, setSelectedEngineId] = useState<string>('merlin-like');
  
  // Sweep data
  const [altitudeSweep, setAltitudeSweep] = useState<Array<{ Pa: number; T: number; Isp: number; mdot: number; Pe: number }>>([]);
  const [expansionSweep, setExpansionSweep] = useState<Array<{ epsilon: number; Isp: number; T: number; Cf: number; Me: number }>>([]);
  const [pressureSweep, setPressureSweep] = useState<Array<{ Pc: number; mdot: number; T: number; Isp: number; cStar: number }>>([]);

  const getLatestStoredRequestId = useCallback((): string | null => {
    try {
      const storedKeys = Object.keys(localStorage).filter((key) => key.startsWith('calc-'));
      if (storedKeys.length === 0) return null;
      const latestKey = storedKeys.sort().reverse()[0];
      return latestKey.replace('calc-', '');
    } catch (error) {
      console.warn('Unable to read stored calculation IDs:', error);
      return null;
    }
  }, []);

  const applyToolPayload = useCallback(
    async (payload: AeroverseAIPayload) => {
      setLastPayload(payload);

      updateToolContext({
        tool: 'Rocket Engine Performance',
        inputs: payload.inputs,
        results: payload.results,
      });

      const eventPayload = buildCalculationEvent({
        toolId: 'rocket-engine',
        toolName: payload.toolName,
        inputs: payload.inputs,
        results: payload.results,
        steps: payload.metadata.steps,
        metadata: {
          units: payload.metadata.unitsSystem,
          approxLevel: payload.metadata.approxLevel,
          confidence: payload.metadata.confidence,
          warnings: payload.metadata.warnings,
        },
      });

      try {
        const eventResponse = await sendCalculationEvent(eventPayload);
        const requestId = eventResponse?.requestId ?? getLatestStoredRequestId();
        setLastRequestId(requestId);
        return requestId;
      } catch (error) {
        console.warn('Failed to send calculation event:', error);
        const fallbackId = getLatestStoredRequestId();
        setLastRequestId(fallbackId);
        return fallbackId;
      }
    },
    [getLatestStoredRequestId, sendCalculationEvent, updateToolContext]
  );

  // Handle input changes
  const handleInputChange = useCallback((field: keyof RocketEngineInputs, value: unknown) => {
    setInputs(prev => ({ ...prev, [field]: value }));
  }, []);

  // Load propellant preset
  const handleLoadPropellant = useCallback((preset: PropellantPreset) => {
    setSelectedPropellantId(preset.id);
    setInputs(prev => ({
      ...prev,
      gamma: preset.gamma,
      M_molar: preset.M_molar,
      R: undefined, // Clear R if M_molar is set
      Pc: preset.Pc_typical,
      Tc: preset.Tc_typical,
      nozzleEfficiency: preset.nozzleEfficiency,
      cStarEfficiency: preset.cStarEfficiency,
    }));
    toast({
      title: 'Propellant loaded',
      description: `${preset.name} properties loaded`,
    });
  }, [toast]);

  // Load engine preset
  const handleLoadEngine = useCallback((preset: EnginePreset) => {
    setSelectedEngineId(preset.id);
    const propellant = PROPELLANT_PRESETS[preset.propellantId];
    setInputs(prev => ({
      ...prev,
      Pc: preset.Pc,
      Tc: preset.Tc,
      At: preset.At,
      epsilon: preset.epsilon,
      gamma: propellant.gamma,
      M_molar: propellant.M_molar,
      R: undefined,
      nozzleEfficiency: preset.nozzleEfficiency ?? propellant.nozzleEfficiency,
      cStarEfficiency: preset.cStarEfficiency ?? propellant.cStarEfficiency,
      pressureLossFraction: preset.pressureLossFraction ?? DEFAULT_PRESSURE_LOSS,
    }));
    toast({
      title: 'Engine loaded',
      description: `${preset.name} configuration loaded`,
    });
  }, [toast]);

  // Calculate engine performance
  const handleUserCalculate = useCallback(async () => {
    try {
      // Validate inputs
      const validation = validateRocketEngineInputs(inputs);
      if (!validation.valid) {
        toast({
          title: 'Validation Error',
          description: validation.errors.join(', '),
          variant: 'destructive',
        });
        return;
      }

      if (validation.warnings.length > 0) {
        validation.warnings.forEach(warning => {
          console.warn(warning);
        });
      }

      // Perform calculation
      const engineResults = calculateRocketEngine(inputs);
      setResults(engineResults);

      // Clear sweep data
      setAltitudeSweep([]);
      setExpansionSweep([]);
      setPressureSweep([]);

        // Generate AI payload
        const payload = buildRocketEnginePayload(inputs, engineResults);

        await applyToolPayload(payload);

      toast({
        title: 'Calculation complete',
        description: `Thrust: ${(engineResults.T / 1000).toFixed(1)} kN, Isp: ${engineResults.Isp.toFixed(1)} s`,
      });
    } catch (error) {
      toast({
        title: 'Calculation Error',
        description: error instanceof Error ? error.message : 'Unknown error',
        variant: 'destructive',
      });
    }
  }, [applyToolPayload, inputs, toast]);

  // Sweep altitude (ambient pressure)
  const handleSweepAltitude = useCallback((altitudeMin: number, altitudeMax: number, steps: number) => {
    try {
      const Pa_min = altitudeToPressure(altitudeMax); // Higher altitude = lower pressure
      const Pa_max = altitudeToPressure(altitudeMin);
      const sweepData = sweepAmbientPressure(inputs, Pa_min, Pa_max, steps);
      setAltitudeSweep(sweepData);
      toast({
        title: 'Altitude sweep complete',
        description: `Generated ${sweepData.length} data points`,
      });
    } catch (error) {
      toast({
        title: 'Sweep Error',
        description: error instanceof Error ? error.message : 'Unknown error',
        variant: 'destructive',
      });
    }
  }, [inputs, toast]);

  // Sweep expansion ratio
  const handleSweepExpansion = useCallback((epsilonMin: number, epsilonMax: number, steps: number) => {
    try {
      const sweepData = sweepExpansionRatio(inputs, epsilonMin, epsilonMax, steps);
      setExpansionSweep(sweepData);
      toast({
        title: 'Expansion ratio sweep complete',
        description: `Generated ${sweepData.length} data points`,
      });
    } catch (error) {
      toast({
        title: 'Sweep Error',
        description: error instanceof Error ? error.message : 'Unknown error',
        variant: 'destructive',
      });
    }
  }, [inputs, toast]);

  // Sweep chamber pressure
  const handleSweepPressure = useCallback((PcMin: number, PcMax: number, steps: number) => {
    try {
      const sweepData = sweepChamberPressure(inputs, PcMin, PcMax, steps);
      setPressureSweep(sweepData);
      toast({
        title: 'Chamber pressure sweep complete',
        description: `Generated ${sweepData.length} data points`,
      });
    } catch (error) {
      toast({
        title: 'Sweep Error',
        description: error instanceof Error ? error.message : 'Unknown error',
        variant: 'destructive',
      });
    }
  }, [inputs, toast]);

  return (
    <ToolWrapper>
      <ToolHeader
        title="Rocket Engine Performance"
        description="Isentropic nozzle flow analysis with practical corrections"
        icon={Rocket}
      />

      <ToolSection>
        <PresetsPanel
          selectedPropellantId={selectedPropellantId}
          selectedEngineId={selectedEngineId}
          onPropellantChange={setSelectedPropellantId}
          onEngineChange={setSelectedEngineId}
          onLoadPropellant={handleLoadPropellant}
          onLoadEngine={handleLoadEngine}
        />
      </ToolSection>

      <ToolSection>
        <InputPanel inputs={inputs} onInputChange={handleInputChange} />
      </ToolSection>

      <ToolActions>
          <AeroButton onClick={handleUserCalculate} icon={Calculator}>
          Calculate Performance
        </AeroButton>
          {results && lastPayload && (
          <>
              <AskAIButton requestId={lastRequestId} payload={lastPayload} disabled={!lastPayload} />
              <PDFExportButton
                requestId={lastRequestId}
                toolName="Rocket Engine Performance"
                disabled={!lastRequestId}
              />
          </>
        )}
      </ToolActions>

      {results && (
        <ToolSection>
          <div className="grid md:grid-cols-3 gap-4">
            <div className="p-4 bg-slate-700/30 rounded-lg border border-cyan-400/20">
              <h3 className="text-sm font-semibold text-cyan-400 mb-2">Altitude Sweep</h3>
              <p className="text-xs text-gray-400 mb-3">Sweep ambient pressure (altitude)</p>
              <AeroButton
                onClick={() => handleSweepAltitude(0, 50000, 50)}
                variant="outline"
                size="sm"
                className="w-full"
              >
                Sweep 0-50 km
              </AeroButton>
            </div>
            <div className="p-4 bg-slate-700/30 rounded-lg border border-cyan-400/20">
              <h3 className="text-sm font-semibold text-cyan-400 mb-2">Expansion Ratio Sweep</h3>
              <p className="text-xs text-gray-400 mb-3">Sweep nozzle expansion ratio</p>
              <AeroButton
                onClick={() => handleSweepExpansion(5, 100, 50)}
                variant="outline"
                size="sm"
                className="w-full"
              >
                Sweep ε: 5-100
              </AeroButton>
            </div>
            <div className="p-4 bg-slate-700/30 rounded-lg border border-cyan-400/20">
              <h3 className="text-sm font-semibold text-cyan-400 mb-2">Chamber Pressure Sweep</h3>
              <p className="text-xs text-gray-400 mb-3">Sweep chamber pressure</p>
              <AeroButton
                onClick={() => handleSweepPressure(1e6, 30e6, 50)}
                variant="outline"
                size="sm"
                className="w-full"
              >
                Sweep Pc: 10-300 bar
              </AeroButton>
            </div>
          </div>
        </ToolSection>
      )}

      {results && (
        <>
          <ToolSection>
            <ResultsPanel results={results} />
          </ToolSection>

          <ToolSection>
            <PlotsPanel
              altitudeSweep={altitudeSweep}
              expansionSweep={expansionSweep}
              pressureSweep={pressureSweep}
            />
          </ToolSection>
        </>
      )}
    </ToolWrapper>
  );
}

/**
 * Stability & Control Derivatives Calculator
 * 
 * High-fidelity aircraft stability analysis based on Raymer, Roskam, Anderson, and USAF DATCOM
 */

"use client";

import { useState, useCallback, useMemo, memo } from 'react';
import { Plane, Calculator } from 'lucide-react';
import { ToolWrapper } from '@/components/layout/ToolWrapper';
import { ToolHeader } from '@/components/layout/ToolHeader';
import { ToolSection } from '@/components/layout/ToolSection';
import { ToolActions } from '@/components/layout/ToolActions';
import { AeroButton } from '@/components/common/AeroButton';
import { useToolContext } from '@/hooks/useToolContext';
import { PDFExportButton } from '@/components/tools/PDFExportButton';
import { AskAIButton } from '@/components/tools/AskAIButton';
import { useToast } from '@/hooks/use-toast';
import { ErrorBoundary } from '@/components/common/ErrorBoundary';
