import { MIXING_PRESETS } from './data/mixingMatrices';

export { handleCalculate } from './handleCalculate';

export default function StabilityCalculator() {
  const { sendCalculationEvent, updateToolContext } = useToolContext();
  const { toast } = useToast();
  const [lastRequestId, setLastRequestId] = useState<string | null>(null);
  const [lastPayload, setLastPayload] = useState<AeroverseAIPayload | null>(null);

  // Input state
  const [inputs, setInputs] = useState<StabilityInputs>({
    S_w: 15.0,
    AR: 7.0,
    c_bar: 1.5,
    x_ac_w: 0.25,
    x_cg: 0.25,
    S_t: 3.0,
    AR_t: 4.5,
    l_t: 4.0,
    a0: DEFAULT_AIRFOIL_LIFT_SLOPE,
    e: DEFAULT_WING_EFFICIENCY,
    e_t: DEFAULT_WING_EFFICIENCY,
    eta: DEFAULT_TAIL_EFFICIENCY,
    useRoskamDownwash: false,
    S_e: 0.6,
    tau_e: DEFAULT_ELEVATOR_EFFECTIVENESS,
    S_a: 0.8,
    S_r: 0.5,
    S_v: 2.5,
  });

  const [results, setResults] = useState<StabilityResults | null>(null);
  const [extendedResults, setExtendedResults] = useState<ExtendedStabilityResults | null>(null);
  const [cgSweepData, setCgSweepData] = useState<Array<{ x_cg: number; SM: number; C_m_alpha: number }>>([]);
  const [selectedPresetId, setSelectedPresetId] = useState<string>('custom');
  
  // Feature toggles
  const [enableDynamicDerivatives, setEnableDynamicDerivatives] = useState(false);
  const [enableControlGeometry, setEnableControlGeometry] = useState(false);
  const [enableHingeMoments, setEnableHingeMoments] = useState(false);
  const [enableControlMixing, setEnableControlMixing] = useState(false);
  const [enableHighLift, setEnableHighLift] = useState(false);
  const [enableRollRate, setEnableRollRate] = useState(false);
  const [enableStabilityCriteria, setEnableStabilityCriteria] = useState(false);
  const [enableNonlinear, setEnableNonlinear] = useState(false);
  
  // Control geometry
  const [elevatorGeometry, setElevatorGeometry] = useState<Partial<ControlGeometry>>();
  const [aileronGeometry, setAileronGeometry] = useState<Partial<ControlGeometry>>();
  const [rudderGeometry, setRudderGeometry] = useState<Partial<ControlGeometry>>();
  
  // Control mixing
  const [mixingType, setMixingType] = useState<'none' | 'aileron-differential' | 'flaperons' | 'spoilerons' | 'elevator-aileron' | 'rudder-aileron' | 'quadcopter'>('none');
  const [aileronDifferentialRatio, setAileronDifferentialRatio] = useState(0.6);
  const [flaperonMix, setFlaperonMix] = useState(0.5);
  const [spoileronMix, setSpoileronMix] = useState(0.5);
  const [motorMixingPreset, setMotorMixingPreset] = useState('quadcopter-x');
  
  // High-lift devices
  const [highLiftDevices, setHighLiftDevices] = useState<HighLiftDevice[]>([]);
  
  // Roll rate inputs
  const [deltaA, setDeltaA] = useState(15);
  const [velocity, setVelocity] = useState(50);
  const [I_x, setI_x] = useState(100);
  
  // Stability criteria
  const [aircraftCategory, setAircraftCategory] = useState<'A' | 'B' | 'C'>('B');
  const [flightPhase, setFlightPhase] = useState<'cruise' | 'approach' | 'landing' | 'takeoff'>('cruise');
  
  // Nonlinear control
  const [deltaE, setDeltaE] = useState(10);
  const [deltaR, setDeltaR] = useState(5);
  const [alpha, setAlpha] = useState(5);

  // Handle input changes
  const handleInputChange = useCallback((field: keyof StabilityInputs, value: unknown) => {
    setInputs(prev => ({ ...prev, [field]: value }));
  }, []);

  // Load preset
  const handleLoadPreset = useCallback((preset: AircraftPreset) => {
    // Ensure all values are numbers, not undefined
    const presetInputs: StabilityInputs = {
      S_w: Number(preset.S_w) || 0,
      AR: Number(preset.AR) || 0,
      c_bar: Number(preset.c_bar) || 0,
      x_ac_w: Number(preset.x_ac_w) || 0,
      x_cg: Number((preset.x_cg_min + preset.x_cg_max) / 2) || 0, // Use midpoint
      S_t: Number(preset.S_t) || 0,
      AR_t: Number(preset.AR_t) || 0,
      l_t: Number(preset.l_t) || 0,
      a0: Number(preset.a0) || DEFAULT_AIRFOIL_LIFT_SLOPE,
      e: Number(preset.e) || DEFAULT_WING_EFFICIENCY,
      e_t: Number(preset.e_t) || DEFAULT_WING_EFFICIENCY,
      eta: Number(preset.eta) || DEFAULT_TAIL_EFFICIENCY,
      useRoskamDownwash: false,
      S_e: preset.S_e !== undefined ? Number(preset.S_e) : undefined,
      tau_e: preset.tau_e !== undefined ? Number(preset.tau_e) : DEFAULT_ELEVATOR_EFFECTIVENESS,
      S_a: preset.S_a !== undefined ? Number(preset.S_a) : undefined,
      S_r: preset.S_r !== undefined ? Number(preset.S_r) : undefined,
      S_v: preset.S_v !== undefined ? Number(preset.S_v) : (preset.S_t ? Number(preset.S_t) * 0.8 : undefined),
    };
    
    setInputs(presetInputs);
    
    // Clear previous results when loading new preset
    setResults(null);
    setExtendedResults(null);
    setCgSweepData([]);
    
    toast({
      title: 'Preset loaded',
      description: `${preset.name} configuration loaded successfully`,
    });
  }, [toast]);

  const getLatestStoredRequestId = useCallback((): string | null => {
    try {
      const storedKeys = Object.keys(localStorage).filter((key) => key.startsWith('calc-'));
      if (storedKeys.length === 0) return null;
      const latestKey = storedKeys.sort().reverse()[0];
      return latestKey.replace('calc-', '');
    } catch (error) {
      console.warn('Unable to read stored calculation IDs:', error);
      return null;
    }
  }, []);

  const applyToolPayload = useCallback(
    async (payload: AeroverseAIPayload) => {
      setLastPayload(payload);

      updateToolContext({
        tool: 'Stability & Control Derivatives',
        inputs: payload.inputs,
        results: payload.results,
      });

      const eventPayload = buildCalculationEvent({
        toolId: 'stability',
        toolName: payload.toolName,
        inputs: payload.inputs,
        results: payload.results,
        steps: payload.metadata.steps,
        metadata: {
          units: payload.metadata.unitsSystem,
          approxLevel: payload.metadata.approxLevel,
          confidence: payload.metadata.confidence,
          warnings: payload.metadata.warnings,
        },
      });

      try {
        const eventResponse = await sendCalculationEvent(eventPayload);
        const requestId = eventResponse?.requestId ?? getLatestStoredRequestId();
        setLastRequestId(requestId);
        return requestId;
      } catch (error) {
        console.warn('Failed to send calculation event:', error);
        const fallbackId = getLatestStoredRequestId();
        setLastRequestId(fallbackId);
        return fallbackId;
      }
    },
    [getLatestStoredRequestId, sendCalculationEvent, updateToolContext]
  );

  // Calculate stability
    const handleUserCalculate = useCallback(async () => {
    try {
      // Validate inputs
      const validation = validateStabilityInputs(inputs);
      if (!validation.valid) {
        toast({
          title: 'Validation Error',
          description: validation.errors.join(', '),
          variant: 'destructive',
        });
        return;
      }

      // Perform base stability calculation
      const stabilityResults = calculateStability(inputs);
      setResults(stabilityResults);

      // Generate CG sweep data
      const sweepData = sweepCGPosition(inputs, 0.15, 0.40, 50);
      setCgSweepData(sweepData);

      // Build extended results
      const extended: ExtendedStabilityResults = {
        stability: stabilityResults,
      };

      // Calculate dynamic derivatives if enabled
      if (enableDynamicDerivatives) {
        const dynamicInputs: DynamicDerivativesInputs = {
          S_w: inputs.S_w,
          AR: inputs.AR,
          b: Math.sqrt(inputs.S_w * inputs.AR), // Estimate span
          c_bar: inputs.c_bar,
          l_t: inputs.l_t,
          a0: inputs.a0,
          e: inputs.e,
          S_t: inputs.S_t,
          AR_t: inputs.AR_t,
          e_t: inputs.e_t,
          eta: inputs.eta,
        };
        extended.dynamic = calculateDynamicDerivatives(dynamicInputs);
      }

      // Calculate enhanced control derivatives if geometry enabled
      if (enableControlGeometry) {
        const controlInputs: ControlDerivativesInputs = {
          S_t: inputs.S_t,
          AR_t: inputs.AR_t,
          l_t: inputs.l_t,
          c_bar: inputs.c_bar,
          S_w: inputs.S_w,
          a0: inputs.a0,
          e_t: inputs.e_t,
          eta: inputs.eta,
          AR: inputs.AR,
          e: inputs.e,
          b: Math.sqrt(inputs.S_w * inputs.AR),
          S_v: inputs.S_v,
          elevator_geometry: elevatorGeometry as ControlGeometry | undefined,
          aileron_geometry: aileronGeometry as ControlGeometry | undefined,
          rudder_geometry: rudderGeometry as ControlGeometry | undefined,
        };
        extended.control = calculateControlDerivatives(controlInputs);
      }

      // Calculate hinge moments if enabled
      if (enableHingeMoments && elevatorGeometry) {
        const hingeInputs: HingeMomentInputs = {
          chord_fraction: elevatorGeometry.chord_fraction || 0.3,
          hinge_line_position: elevatorGeometry.hinge_line_position || 0.7,
          balance_type: elevatorGeometry.balance_type || 'horn',
          a0: inputs.a0,
          alpha_0: 0,
          S_control: inputs.S_e || 0.1,
          c_control: inputs.c_bar * (elevatorGeometry.chord_fraction || 0.3),
        };
        extended.hingeMoments = calculateHingeMoments(hingeInputs);
      }

      // Calculate control mixing if enabled
      if (enableControlMixing) {
        const mixingInputs: ControlMixingInputs = {
          mixing_type: mixingType,
          aileron_differential_ratio: aileronDifferentialRatio,
          flaperon_mix: flaperonMix,
          spoileron_mix: spoileronMix,
          C_l_delta_a_base: stabilityResults.C_l_delta_a,
          C_m_delta_e_base: stabilityResults.C_m_delta_e,
          C_n_delta_r_base: stabilityResults.C_n_delta_r,
          motor_mixing_matrix: (MIXING_PRESETS as unknown)[motorMixingPreset]?.matrix,
          motor_gains: (MIXING_PRESETS as unknown)[motorMixingPreset]?.gains,
        };
        extended.mixing = calculateControlMixing(mixingInputs);
      }

      // Calculate high-lift effects if enabled
      if (enableHighLift && highLiftDevices.length > 0) {
        extended.highLift = calculateHighLiftEffects(highLiftDevices);
      }

      // Calculate roll rate if enabled
      if (enableRollRate) {
        const q = 0.5 * 1.225 * velocity * velocity; // Dynamic pressure at sea level
        const rollRateInputs: RollRateInputs = {
          delta_a: deltaA,
          C_l_delta_a: extended.mixing?.C_l_delta_a_effective || stabilityResults.C_l_delta_a || 0.1,
          q,
          S_w: inputs.S_w,
          b: Math.sqrt(inputs.S_w * inputs.AR),
          I_x,
          V: velocity,
        };
        extended.rollRate = calculateRollRate(rollRateInputs);
      }

      // Evaluate stability criteria if enabled
      if (enableStabilityCriteria && extended.dynamic) {
        const criteriaInputs: StabilityCriteriaInputs = {
          C_m_alpha: stabilityResults.C_m_alpha,
          C_m_q: extended.dynamic.C_m_q,
          C_l_beta: stabilityResults.C_l_beta || 0,
          C_n_beta: stabilityResults.C_n_beta || 0,
          C_l_p: extended.dynamic.C_l_p,
          C_l_r: extended.dynamic.C_l_r,
          C_n_r: extended.dynamic.C_n_r,
          C_n_p: extended.dynamic.C_n_p,
          V: velocity,
          category: aircraftCategory,
          phase: flightPhase,
        };
        extended.criteria = evaluateStabilityCriteria(criteriaInputs);
      }

      // Calculate nonlinear control if enabled
      if (enableNonlinear) {
        const nonlinearInputs: NonlinearControlInputs = {
          delta_e: deltaE,
          delta_a: deltaA,
          delta_r: deltaR,
          alpha,
          C_m_delta_e_base: extended.control?.C_m_delta_e || stabilityResults.C_m_delta_e || 0,
          C_l_delta_a_base: extended.control?.C_l_delta_a || extended.mixing?.C_l_delta_a_effective || stabilityResults.C_l_delta_a || 0,
          C_n_delta_r_base: extended.control?.C_n_delta_r || stabilityResults.C_n_delta_r || 0,
          enabled: true,
        };
        extended.nonlinear = calculateNonlinearControl(nonlinearInputs);
      }

      setExtendedResults(extended);

        // Generate AI payload
        const payload = buildStabilityPayload(inputs, extended);

      // Collect all warnings
      const allWarnings = [...stabilityResults.warnings];
      if (extended.control?.warnings) {
        allWarnings.push(...extended.control.warnings);
      }
      if (extended.hingeMoments?.warnings) {
        allWarnings.push(...extended.hingeMoments.warnings);
      }
      if (extended.mixing?.warnings) {
        allWarnings.push(...extended.mixing.warnings);
      }
      if (extended.highLift?.warnings) {
        allWarnings.push(...extended.highLift.warnings);
      }
      if (extended.rollRate?.warnings) {
        allWarnings.push(...extended.rollRate.warnings);
      }
      if (extended.criteria?.warnings) {
        allWarnings.push(...extended.criteria.warnings);
      }
      if (extended.nonlinear?.warnings) {
        allWarnings.push(...extended.nonlinear.warnings);
      }

        const payloadWithWarnings: AeroverseAIPayload = {
          ...payload,
          metadata: {
            ...payload.metadata,
            warnings: allWarnings,
          },
        };

        await applyToolPayload(payloadWithWarnings);

      toast({
        title: 'Calculation complete',
        description: stabilityResults.SM > 0 ? 'Aircraft is stable' : 'Aircraft is unstable',
      });
    } catch (error) {
      toast({
        title: 'Calculation Error',
        description: error instanceof Error ? error.message : 'Unknown error',
        variant: 'destructive',
      });
    }
    }, [
    applyToolPayload,
    inputs,
    toast,
    enableDynamicDerivatives,
    enableControlGeometry,
    enableHingeMoments,
    enableControlMixing,
    enableHighLift,
    enableRollRate,
    enableStabilityCriteria,
    enableNonlinear,
    elevatorGeometry,
    aileronGeometry,
    rudderGeometry,
    mixingType,
    aileronDifferentialRatio,
    flaperonMix,
    spoileronMix,
    motorMixingPreset,
    highLiftDevices,
    deltaA,
    velocity,
    I_x,
    aircraftCategory,
    flightPhase,
    deltaE,
    deltaR,
    alpha,
  ]);

  // Generate downwash vs AR data
  const downwashData = useMemo(() => {
    if (!results) return undefined;
    const data = [];
    const a_w = results.a_w; // Use calculated wing lift curve slope
    for (let AR = 3; AR <= 20; AR += 0.5) {
      try {
        // Calculate downwash for different AR values using current wing lift curve slope
        const epsilon_datcom = (2 * a_w) / (Math.PI * AR);
        const epsilon_roskam = (a_w / (Math.PI * AR)) * (1.1 + AR / (AR + 4));
        data.push({ 
          AR, 
          epsilon_alpha: inputs.useRoskamDownwash ? epsilon_roskam : epsilon_datcom 
        });
      } catch (e) {
        // Skip invalid points
      }
    }
    return data;
  }, [inputs.useRoskamDownwash, results]);

  // Generate tail sizing sweep data
  const tailSizingData = useMemo(() => {
    if (!results) return undefined;
    const data = [];
    const S_t_min = inputs.S_t * 0.5;
    const S_t_max = inputs.S_t * 2.0;
    for (let S_t = S_t_min; S_t <= S_t_max; S_t += (S_t_max - S_t_min) / 30) {
      try {
        const testInputs = { ...inputs, S_t };
        const testResults = calculateStability(testInputs);
        data.push({ S_t, V_H: testResults.V_H, SM: testResults.SM });
      } catch (e) {
        // Skip invalid points
      }
    }
    return data;
  }, [inputs, results]);

  return (
    <ErrorBoundary toolName="Stability & Control Derivatives">
      <ToolWrapper>
        <ToolHeader
          title="Stability & Control Derivatives"
          description="Comprehensive aircraft stability analysis based on Raymer, Roskam, Anderson, and DATCOM"
          icon={Plane}
        />

      <ToolSection>
        <AeroCard title="Configuration">
          <div className="grid lg:grid-cols-2 gap-6">
            <PresetsPanel
              selectedPresetId={selectedPresetId}
              onPresetChange={setSelectedPresetId}
              onLoadPreset={handleLoadPreset}
            />
            <InputPanel inputs={inputs} onInputChange={handleInputChange} />
          </div>
        </AeroCard>
      </ToolSection>

      <ToolActions>
          <AeroButton onClick={handleUserCalculate} icon={Calculator}>
          Calculate Stability
        </AeroButton>
          {results && lastPayload && (
          <>
              <AskAIButton requestId={lastRequestId} payload={lastPayload} disabled={!lastPayload} />
              <PDFExportButton toolName="Stability & Control Derivatives" requestId={lastRequestId || undefined} />
          </>
        )}
      </ToolActions>

      {/* Advanced Features Toggles */}
      <ToolSection>
        <AeroCard title="Advanced Features">
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4 p-4 bg-slate-800/30 rounded-lg border border-cyan-400/20">
          <div className="flex items-center space-x-2">
            <Switch
              id="dynamic"
              checked={enableDynamicDerivatives}
              onCheckedChange={setEnableDynamicDerivatives}
            />
            <Label htmlFor="dynamic" className="text-sm">Dynamic Derivatives</Label>
          </div>
          <div className="flex items-center space-x-2">
            <Switch
              id="control-geo"
              checked={enableControlGeometry}
              onCheckedChange={setEnableControlGeometry}
            />
            <Label htmlFor="control-geo" className="text-sm">Control Geometry</Label>
          </div>
          <div className="flex items-center space-x-2">
            <Switch
              id="hinge"
              checked={enableHingeMoments}
              onCheckedChange={setEnableHingeMoments}
            />
            <Label htmlFor="hinge" className="text-sm">Hinge Moments</Label>
          </div>
          <div className="flex items-center space-x-2">
            <Switch
              id="mixing"
              checked={enableControlMixing}
              onCheckedChange={setEnableControlMixing}
            />
            <Label htmlFor="mixing" className="text-sm">Control Mixing</Label>
          </div>
          <div className="flex items-center space-x-2">
            <Switch
              id="highlift"
              checked={enableHighLift}
              onCheckedChange={setEnableHighLift}
            />
            <Label htmlFor="highlift" className="text-sm">High-Lift Devices</Label>
          </div>
          <div className="flex items-center space-x-2">
            <Switch
              id="rollrate"
              checked={enableRollRate}
              onCheckedChange={setEnableRollRate}
            />
            <Label htmlFor="rollrate" className="text-sm">Roll Rate</Label>
          </div>
          <div className="flex items-center space-x-2">
            <Switch
              id="criteria"
              checked={enableStabilityCriteria}
              onCheckedChange={setEnableStabilityCriteria}
            />
            <Label htmlFor="criteria" className="text-sm">MIL-F-8785C</Label>
          </div>
          <div className="flex items-center space-x-2">
            <Switch
              id="nonlinear"
              checked={enableNonlinear}
              onCheckedChange={setEnableNonlinear}
            />
            <Label htmlFor="nonlinear" className="text-sm">Nonlinear Control</Label>
          </div>
        </div>
        </AeroCard>
      </ToolSection>

      {/* Advanced Feature Panels */}
      {(enableControlGeometry || enableControlMixing || enableHighLift) && (
        <ToolSection>
          <AeroCard title="Advanced Configuration">
            <Tabs defaultValue={enableControlGeometry ? "control-geometry" : enableControlMixing ? "mixing" : "highlift"} className="w-full">
            <TabsList className="grid w-full grid-cols-3 bg-slate-800/50">
              {enableControlGeometry && <TabsTrigger value="control-geometry">Control Geometry</TabsTrigger>}
              {enableControlMixing && <TabsTrigger value="mixing">Control Mixing</TabsTrigger>}
              {enableHighLift && <TabsTrigger value="highlift">High-Lift Devices</TabsTrigger>}
            </TabsList>
            {enableControlGeometry && (
              <TabsContent value="control-geometry" className="mt-4">
                <ControlGeometryPanel
                  elevatorGeometry={elevatorGeometry as ControlGeometry}
                  aileronGeometry={aileronGeometry as ControlGeometry}
                  rudderGeometry={rudderGeometry as ControlGeometry}
                  onGeometryChange={(surface, geometry) => {
                    if (surface === 'elevator') setElevatorGeometry({ ...elevatorGeometry, ...geometry });
                    if (surface === 'aileron') setAileronGeometry({ ...aileronGeometry, ...geometry });
                    if (surface === 'rudder') setRudderGeometry({ ...rudderGeometry, ...geometry });
                  }}
                />
              </TabsContent>
            )}
            {enableControlMixing && (
              <TabsContent value="mixing" className="mt-4">
                <ControlMixingPanel
                  mixingType={mixingType}
                  onMixingTypeChange={(type) => setMixingType(type as typeof mixingType)}
                  aileronDifferentialRatio={aileronDifferentialRatio}
                  onAileronDifferentialChange={setAileronDifferentialRatio}
                  flaperonMix={flaperonMix}
                  onFlaperonMixChange={setFlaperonMix}
                  spoileronMix={spoileronMix}
                  onSpoileronMixChange={setSpoileronMix}
                  motorMixingPreset={motorMixingPreset}
                  onMotorMixingPresetChange={setMotorMixingPreset}
                  mixingResults={extendedResults?.mixing}
                />
              </TabsContent>
            )}
            {enableHighLift && (
              <TabsContent value="highlift" className="mt-4">
                <HighLiftDevicesPanel
                  devices={highLiftDevices}
                  onDevicesChange={setHighLiftDevices}
                  onPresetLoad={setHighLiftDevices}
                />
              </TabsContent>
            )}
          </Tabs>
          </AeroCard>
        </ToolSection>
      )}

      {results && (
        <>
          <ToolSection>
            <AeroCard title="Stability Results">
              <ResultsPanel results={results} />
            </AeroCard>
          </ToolSection>

          {/* Advanced Results Panels */}
          {extendedResults && (
            <>
              {enableDynamicDerivatives && extendedResults.dynamic && (
                <ToolSection>
                  <AeroCard title="Dynamic Derivatives">
                    <DynamicDerivativesPanel
                      derivatives={extendedResults.dynamic}
                      enabled={enableDynamicDerivatives}
                    />
                  </AeroCard>
                </ToolSection>
              )}

              {enableControlGeometry && extendedResults.control && (
                <ToolSection>
                  <AeroCard title="Enhanced Control Derivatives">
                  <div className="p-4 bg-slate-700/30 rounded-lg">
                    <p className="text-sm text-gray-300 mb-2">Control Effectiveness Factors:</p>
                    <div className="grid grid-cols-3 gap-4">
                      <div>
                        <p className="text-xs text-gray-400">τ_e (Elevator)</p>
                        <p className="text-cyan-400 font-bold">
                          {extendedResults.control.tau_e != null ? extendedResults.control.tau_e.toFixed(3) : 'N/A'}
                        </p>
                      </div>
                      <div>
                        <p className="text-xs text-gray-400">τ_a (Aileron)</p>
                        <p className="text-cyan-400 font-bold">
                          {extendedResults.control.tau_a != null ? extendedResults.control.tau_a.toFixed(3) : 'N/A'}
                        </p>
                      </div>
                      <div>
                        <p className="text-xs text-gray-400">τ_r (Rudder)</p>
                        <p className="text-cyan-400 font-bold">
                          {extendedResults.control.tau_r != null ? extendedResults.control.tau_r.toFixed(3) : 'N/A'}
                        </p>
                      </div>
                    </div>
                  </div>
                  </AeroCard>
                </ToolSection>
              )}

              {enableHingeMoments && extendedResults.hingeMoments && (
                <ToolSection>
                  <AeroCard title="Hinge Moments">
                    <HingeMomentsPanel
                      hingeMoments={extendedResults.hingeMoments}
                      enabled={enableHingeMoments}
                    />
                  </AeroCard>
                </ToolSection>
              )}

              {enableRollRate && extendedResults.rollRate && (
                <ToolSection>
                  <AeroCard title="Roll Rate Estimation">
                    <RollRatePanel
                      rollRateResult={extendedResults.rollRate}
                      enabled={enableRollRate}
                      deltaA={deltaA}
                      onDeltaAChange={setDeltaA}
                      velocity={velocity}
                      onVelocityChange={setVelocity}
                      I_x={I_x}
                      onIxChange={setI_x}
                    />
                  </AeroCard>
                </ToolSection>
              )}

              {enableStabilityCriteria && extendedResults.criteria && (
                <ToolSection>
                  <AeroCard title="Stability Criteria (MIL-F-8785C)">
                    <StabilityCriteriaPanel
                      criteria={extendedResults.criteria}
                      enabled={enableStabilityCriteria}
                      category={aircraftCategory}
                      onCategoryChange={setAircraftCategory}
                      phase={flightPhase}
                      onPhaseChange={setFlightPhase}
                    />
                  </AeroCard>
                </ToolSection>
              )}

              {enableNonlinear && extendedResults.nonlinear && (
                <ToolSection>
                  <AeroCard title="Nonlinear Control Behavior">
                  <div className="p-4 bg-slate-700/30 rounded-lg">
                    <p className="text-sm text-gray-300 mb-4">Nonlinear Effectiveness Factors:</p>
                    <div className="grid grid-cols-3 gap-4">
                      <div>
                        <p className="text-xs text-gray-400">Elevator Factor</p>
                        <p className="text-cyan-400 font-bold">
                          {extendedResults.nonlinear.elevator_factor != null ? extendedResults.nonlinear.elevator_factor.toFixed(3) : 'N/A'}
                        </p>
                      </div>
                      <div>
                        <p className="text-xs text-gray-400">Aileron Factor</p>
                        <p className="text-cyan-400 font-bold">
                          {extendedResults.nonlinear.aileron_factor != null ? extendedResults.nonlinear.aileron_factor.toFixed(3) : 'N/A'}
                        </p>
                      </div>
                      <div>
                        <p className="text-xs text-gray-400">Rudder Factor</p>
                        <p className="text-cyan-400 font-bold">
                          {extendedResults.nonlinear.rudder_factor != null ? extendedResults.nonlinear.rudder_factor.toFixed(3) : 'N/A'}
                        </p>
                      </div>
                    </div>
                    {extendedResults.nonlinear.warnings && extendedResults.nonlinear.warnings.length > 0 && (
                      <div className="mt-4 p-3 bg-yellow-400/10 border border-yellow-400/30 rounded">
                        {extendedResults.nonlinear.warnings.map((w, i) => (
                          <p key={i} className="text-xs text-yellow-400">{w}</p>
                        ))}
                      </div>
                    )}
                  </div>
                  </AeroCard>
                </ToolSection>
              )}
            </>
          )}

          <ToolSection>
            <AeroCard title="Tail Sizing Analysis">
              <TailSizingPanel 
                results={results} 
                S_t={inputs.S_t}
                S_w={inputs.S_w}
                l_t={inputs.l_t}
                c_bar={inputs.c_bar}
              />
            </AeroCard>
          </ToolSection>

          <ToolSection>
            <AeroCard title="Charts">
              <ChartsPanel
                results={results}
                cgSweepData={cgSweepData}
                downwashData={downwashData}
              />
            </AeroCard>
          </ToolSection>
        </>
      )}
      </ToolWrapper>
    </ErrorBoundary>
  );
}

/**
 * Earth Scene Component
 * Renders Earth sphere with textures, atmosphere, and clouds
 */

import { useRef, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import { Mesh, SphereGeometry } from 'three';
import { Stars } from '@react-three/drei';
import * as THREE from 'three';

interface EarthSceneProps {
  radius: number;
  showAtmosphere?: boolean;
  showClouds?: boolean;
  simpleMode?: boolean;
  rotationSpeed?: number;
}

export function EarthScene({
  radius,
  showAtmosphere = true,
  showClouds = true,
  simpleMode = false,
  rotationSpeed = 0.00001,
}: EarthSceneProps) {
  const earthRef = useRef<Mesh>(null);
  const cloudRef = useRef<Mesh>(null);

  // Texture loading - use simple mode by default, textures can be added later
  // For now, use procedural materials

  // Create materials
  const earthMaterial = useMemo(() => {
    // Use procedural material - textures can be added later via useTexture hook
    return new THREE.MeshStandardMaterial({
      color: 0x4a90e2,
      roughness: 0.8,
      metalness: 0.2,
    });
  }, [simpleMode]);

  const cloudMaterial = useMemo(() => {
    if (!showClouds || simpleMode) return null;

    return new THREE.MeshStandardMaterial({
      color: 0xffffff,
      transparent: true,
      opacity: 0.4,
      depthWrite: false,
    });
  }, [showClouds, simpleMode]);

  // Rotate Earth
  useFrame(() => {
    if (earthRef.current) {
      earthRef.current.rotation.y += rotationSpeed;
    }
    if (cloudRef.current && showClouds) {
      cloudRef.current.rotation.y += rotationSpeed * 1.1; // Slightly faster for clouds
    }
  });

  // Low-res geometry for performance
  const geometry = useMemo(() => {
    return new SphereGeometry(radius, simpleMode ? 32 : 64, simpleMode ? 32 : 64);
  }, [radius, simpleMode]);

  return (
    <group>
      {/* Stars background */}
      <Stars radius={radius * 100} depth={50} count={5000} factor={4} fade speed={1} />

      {/* Earth sphere */}
      <mesh ref={earthRef} geometry={geometry} material={earthMaterial} />

      {/* Clouds layer */}
      {showClouds && cloudMaterial && (
        <mesh ref={cloudRef} geometry={geometry} material={cloudMaterial} scale={1.01} />
      )}

      {/* Atmosphere glow */}
      {showAtmosphere && !simpleMode && (
        <mesh geometry={geometry} scale={1.02}>
          <meshBasicMaterial
            color={0x87ceeb}
            transparent
            opacity={0.15}
            side={THREE.BackSide}
          />
        </mesh>
      )}
    </group>
  );
}

import { memo, useCallback, useEffect, useMemo } from 'react';
import { OrbitControls } from '@react-three/drei';
import { useThree } from '@react-three/fiber';
import { TrajectoryData, extractEventMarkers, downsampleFrames } from '../../utils/three/threeUtils';
import { VisualizerSettings } from './useVisualizerState';
import { Planet } from '../../data/planets';
import { EarthScene } from './EarthScene';
import { RocketModel } from './RocketModel';
import { TrajectoryPath } from './TrajectoryPath';
import { Markers } from './Markers';
import { CameraController } from './CameraController';
import { EffectsStack } from './EffectsStack';
import { isDevEnv } from '@/lib/env';

interface VisualizerSceneProps {
  trajectoryData: TrajectoryData;
  planet: Planet;
  settings: VisualizerSettings;
  currentFrameIndex: number;
  onMarkerClick: (marker: { t: number }) => void;
  onSceneError?: (error: Error) => void;
  onSceneReady?: () => void;
}

const IS_DEV = isDevEnv();

export const VisualizerScene = memo(function VisualizerScene({
  trajectoryData,
  planet,
  settings,
  currentFrameIndex,
  onMarkerClick,
  onSceneError,
  onSceneReady,
}: VisualizerSceneProps) {
  const { gl } = useThree();
  const frames = trajectoryData?.frames ?? [];

  useEffect(() => {
    if (!gl?.domElement) {
      if (IS_DEV) {
        console.debug('3D Visualizer: gl or domElement missing', { hasGl: !!gl, hasDomElement: !!gl?.domElement });
      }
      return;
    }

    const handleContextLost = (event: Event) => {
      event.preventDefault?.();
      const error = new Error('WebGL context lost');
      console.error('3D Visualizer error', error, { location: 'VisualizerScene/webglcontextlost' });
      onSceneError?.(error);
    };

    const handleContextRestored = () => {
      if (IS_DEV) {
        console.debug('3D Visualizer: WebGL context restored');
      }
    };

    gl.domElement.addEventListener('webglcontextlost', handleContextLost as EventListener);
    gl.domElement.addEventListener('webglcontextrestored', handleContextRestored);
    return () => {
      gl.domElement.removeEventListener('webglcontextlost', handleContextLost as EventListener);
      gl.domElement.removeEventListener('webglcontextrestored', handleContextRestored);
    };
  }, [gl, onSceneError]);

  useEffect(() => {
    // Frame validation and logging
    if (IS_DEV) {
      console.debug('TrajectoryConvert: frames=', frames.length, {
        mode: trajectoryData?.metadata?.coordFrame,
        planetId: trajectoryData?.metadata?.planet,
        firstFrame: frames[0],
        lastFrame: frames[frames.length - 1],
      });
    }

    if (frames.length === 0) {
      const error = new Error('No trajectory frames to visualize');
      if (IS_DEV) {
        console.debug('3D Visualizer: no frames');
      }
      onSceneError?.(error);
      return;
    }

    // Validate frame data
    const invalidFrame = frames.find(
      (frame) =>
        !Number.isFinite(frame.t) ||
        !Number.isFinite(frame.x) ||
        !Number.isFinite(frame.y) ||
        !Number.isFinite(frame.z),
    );

    if (invalidFrame) {
      const error = new Error('Visualizer data contains invalid values');
      console.error('3D Visualizer error', error, { location: 'VisualizerScene/frameValidation', invalidFrame });
      onSceneError?.(error);
    } else {
      if (IS_DEV) {
        console.debug('VisualizerScene self-test OK', {
          frames: frames.length,
          duration: frames[frames.length - 1]?.t ?? 0,
        });
        console.debug('3D Visualizer: No WebGL errors detected');
      }
      onSceneReady?.();
    }
  }, [frames, trajectoryData, onSceneError, onSceneReady]);

  const currentFrame = useMemo(() => {
    if (frames.length === 0) return undefined;
    return frames[Math.min(currentFrameIndex, frames.length - 1)];
  }, [frames, currentFrameIndex]);

  const markers = useMemo(() => extractEventMarkers(frames), [frames]);

  const downsampledFrames = useMemo(() => {
    const maxFrames = settings.simpleMode || settings.lowPowerMode ? 500 : 1000;
    return downsampleFrames(frames, maxFrames);
  }, [frames, settings.simpleMode, settings.lowPowerMode]);

  const handleMarkerClick = useCallback(
    (marker: { t: number }) => {
      try {
        onMarkerClick(marker);
      } catch (error) {
        console.error('Marker click handler failed', error);
        onSceneError?.(error as Error);
      }
    },
    [onMarkerClick, onSceneError],
  );

  // Early return if no frames (after error reporting)
  if (!frames || frames.length === 0) {
    return <group />;
  }

  try {
    return (
      <>
        <ambientLight intensity={0.5} />
        <directionalLight position={[10, 10, 5]} intensity={1} />
        <pointLight position={[-10, -10, -5]} intensity={0.5} />

        {settings.showEarth && (
          <EarthScene
            radius={planet.radius / 1000}
            showAtmosphere={settings.showAtmosphere && !settings.simpleMode}
            showClouds={settings.showClouds && !settings.simpleMode}
            simpleMode={settings.simpleMode || settings.lowPowerMode}
          />
        )}

        {settings.showTrajectory && (
          <TrajectoryPath frames={downsampledFrames} showPath={settings.showTrajectory} />
        )}

        <Markers
          markers={markers}
          showMarkers={settings.showMarkers}
          onMarkerClick={handleMarkerClick}
        />

        {currentFrame && (
          <RocketModel
            position={currentFrame.pos.map((p) => p / 1000) as [number, number, number]}
            rotation={currentFrame.attitude}
            showExhaust={settings.showExhaust && !settings.simpleMode}
            thrustLevel={currentFrame.mass ? 1.0 : 0}
          />
        )}

        <CameraController
          mode={settings.cameraMode}
          currentFrame={currentFrame}
          enabled={settings.cameraMode !== 'free'}
        />

        {settings.cameraMode === 'free' && (
          <OrbitControls enablePan enableZoom enableRotate minDistance={1} maxDistance={100} />
        )}

        <EffectsStack settings={settings} />
      </>
    );
  } catch (error) {
    console.error('3D Visualizer error', error, { location: 'VisualizerScene/render' });
    onSceneError?.(error as Error);
    return <group />;
  }
});

/**
 * Main 3D Visualizer Component
 * Cinematic trajectory visualization
 */

"use client";

import { Suspense, useMemo, memo, useState, useEffect } from 'react';
import { Canvas } from '@react-three/fiber';
import { TrajectoryData } from '../../utils/three/threeUtils';
import { convertSimulationToTrajectoryData } from '../../utils/convertSimulationToTrajectoryData';
import { useVisualizerState } from './useVisualizerState';
import { TimelineController } from './TimelineController';
import { ControlsOverlay } from './ControlsOverlay';
import { Planet } from '../../data/planets';
import { ErrorBoundary } from '@/components/common/ErrorBoundary';
import { isDevEnv, isVisualizerDebug } from '@/lib/env';
import { VisualizerScene } from './VisualizerScene';

interface ThreeDVisualizerProps {
  trajectoryData?: TrajectoryData;
  planet: Planet;
  result?: unknown;
  mode: '1D' | '2D' | '3D';
  onSnapshot?: (base64: string) => void;
}

// Export snapshot function for external use
export async function exportVisualizerSnapshot(canvasElement: HTMLCanvasElement): Promise<string> {
  try {
    return canvasElement.toDataURL('image/png');
  } catch (error) {
    console.error('Failed to export snapshot:', error);
    return '';
  }
}

const DEBUG_VIS = isVisualizerDebug();
const IS_DEV = isDevEnv();

const SuspenseFallback = () => {
  useEffect(() => {
    if (IS_DEV) {
      console.debug('ThreeDVisualizer suspense fallback active');
    }
  }, []);
  return <group />;
};

const Placeholder = ({
  reason,
  details,
}: {
  reason: string;
  details?: Record<string, unknown>;
}) => (
  <ErrorBoundary toolName="3D Trajectory Visualizer">
    <div className="relative w-full min-h-[600px] bg-slate-900 rounded-lg border border-slate-800 flex flex-col items-center justify-center text-gray-400 p-6">
      <p>Run a simulation to see the 3D visualization.</p>
      {IS_DEV && (
        <pre className="mt-4 max-w-full overflow-auto text-xs text-left bg-slate-950/60 text-cyan-300 p-3 rounded border border-cyan-400/20">
          {JSON.stringify({ reason, ...details }, null, 2)}
        </pre>
      )}
    </div>
  </ErrorBoundary>
);

export const ThreeDVisualizer = memo(function ThreeDVisualizer({
  trajectoryData,
  planet,
  result,
  mode,
  onSnapshot,
}: ThreeDVisualizerProps) {
  const [sceneReady, setSceneReady] = useState(false);
  const [canvasMounted, setCanvasMounted] = useState(false);
  const [lastSceneError, setLastSceneError] = useState<Error | null>(null);

  const data = useMemo(() => {
    if (trajectoryData) return trajectoryData;
    if (result) {
      return convertSimulationToTrajectoryData(result, mode, planet);
    }
    return undefined;
  }, [trajectoryData, result, mode, planet]);

  useEffect(() => {
    setSceneReady(false);
    setLastSceneError(null);
  }, [data]);

  const totalFrames = data?.frames.length ?? 0;
  const durationFromData = data?.frames.length ? data.frames[data.frames.length - 1].t : 0;
  const sanitizedDuration = Number.isFinite(durationFromData) ? Math.max(durationFromData, 0) : 0;

  const {
    state,
    settings,
    play,
    pause,
    setTime,
    setSpeed,
    jumpToEvent,
    updateSetting,
  } = useVisualizerState(totalFrames, sanitizedDuration);

  useEffect(() => {
    if (IS_DEV) {
      console.debug('ThreeDVisualizer data summary', {
        frames: totalFrames,
        duration: sanitizedDuration,
        firstFrame: data?.frames[0],
      });
    }
  }, [data, totalFrames, sanitizedDuration]);

    // Sanity check: no frames to visualize
    if (!data || totalFrames === 0) {
      if (IS_DEV) {
        console.debug('3D Visualizer: no frames', {
          hasData: Boolean(data),
          frames: totalFrames,
          reason: !data ? 'no-data' : 'empty-frames',
        });
      }
      return <Placeholder reason={!data ? 'no-data' : 'empty-frames'} details={{ frames: totalFrames }} />;
    }

  const timelineDuration = Math.max(state.duration, sanitizedDuration, 0.0001);

  const renderCanvas = () => {
    try {
      if (IS_DEV) {
        console.debug('3D Canvas init start', {
          hasData: Boolean(data),
          frames: totalFrames,
          mode,
          planetId: planet?.id,
        });
      }

      return (
        <Canvas
          camera={{ position: [0, 0, 10], fov: 50 }}
          gl={{ preserveDrawingBuffer: true }}
          onCreated={({ gl, scene, camera }) => {
            try {
              // Check WebGL context availability
              const canvas = gl.domElement;
              if (!canvas) {
                const error = new Error('Canvas element missing');
                console.error('3D Visualizer error', error, { location: 'Canvas/onCreated' });
                setLastSceneError(error);
                return;
              }

              // Get WebGL context from canvas
              const context = canvas.getContext('webgl') || canvas.getContext('webgl2');
              if (!context) {
                const error = new Error('WebGL not available in this browser/device');
                console.error('3D Visualizer error', error, { location: 'Canvas/onCreated' });
                setLastSceneError(error);
                return;
              }

              // Log WebGL info in dev mode
              if (IS_DEV) {
                const vendor = context.getParameter(context.VENDOR);
                const renderer = context.getParameter(context.RENDERER);
                console.debug('3D Canvas WebGL info', {
                  vendor: typeof vendor === 'string' ? vendor : 'unknown',
                  renderer: typeof renderer === 'string' ? renderer : 'unknown',
                  canvasWidth: canvas.clientWidth,
                  canvasHeight: canvas.clientHeight,
                });
              }

              setCanvasMounted(true);
              if (IS_DEV) {
                console.debug('3D Canvas mounted', {
                  canvasWidth: canvas.clientWidth,
                  canvasHeight: canvas.clientHeight,
                });
              }
            } catch (error) {
              console.error('3D Visualizer error', error, { location: 'Canvas/onCreated' });
              setLastSceneError(error instanceof Error ? error : new Error(String(error)));
            }
          }}
          onError={(error) => {
            console.error('3D Visualizer Canvas error', error, { location: 'Canvas/onError' });
            setLastSceneError(error instanceof Error ? error : new Error(String(error)));
          }}
        >
          <Suspense fallback={<SuspenseFallback />}>
            <VisualizerScene
              trajectoryData={data}
              planet={planet}
              settings={settings}
              currentFrameIndex={state.currentFrameIndex}
              onMarkerClick={(marker) => jumpToEvent(marker.t)}
              onSceneError={(error) => {
                if (IS_DEV) {
                  console.error('3D Visualizer scene error', error, { location: 'VisualizerScene' });
                }
                setLastSceneError(error);
              }}
              onSceneReady={() => {
                if (IS_DEV) {
                  console.debug('3D Visualizer: scene ready', {
                    frames: totalFrames,
                    totalFrames: totalFrames,
                    duration: sanitizedDuration,
                  });
                }
                setSceneReady(true);
                setLastSceneError(null);
              }}
            />
          </Suspense>
        </Canvas>
      );
    } catch (error) {
      console.error('3D Visualizer error', error, { location: 'ThreeDVisualizer/renderCanvas' });
      const errorMessage = error instanceof Error ? error.message : String(error);
      setLastSceneError(error instanceof Error ? error : new Error(errorMessage));
      return (
        <div className="absolute inset-0 flex items-center justify-center bg-red-950/60 text-red-200 p-4 text-center z-50">
          <div>
            <p className="text-lg font-semibold mb-2">Unable to initialize 3D visualization</p>
            <p className="text-sm">{errorMessage}</p>
          </div>
        </div>
      );
    }
  };

  return (
    <ErrorBoundary toolName="3D Trajectory Visualizer">
      <div className="relative w-full min-h-[600px] bg-slate-900 rounded-lg overflow-hidden border border-slate-800">
        <div className="absolute inset-0">{renderCanvas()}</div>

        {!sceneReady && !lastSceneError && (
          <div className="absolute inset-0 flex items-center justify-center text-cyan-200 text-sm bg-slate-900/40 backdrop-blur-sm pointer-events-none z-40">
            Initializing 3D scene...
          </div>
        )}

        {lastSceneError && (
          <div className="absolute inset-0 flex items-center justify-center text-red-300 bg-black/60 backdrop-blur-sm p-6 text-center z-50 min-h-[360px]">
            <div>
              <p className="text-lg font-semibold mb-2 text-red-200">Unable to initialize 3D visualization</p>
              <p className="text-sm text-red-300">{lastSceneError.message}</p>
              {IS_DEV && lastSceneError.stack && (
                <pre className="mt-4 text-xs text-left bg-red-950/40 text-red-200 p-3 rounded border border-red-500/30 max-w-2xl overflow-auto">
                  {lastSceneError.stack}
                </pre>
              )}
            </div>
          </div>
        )}

        {DEBUG_VIS && (
          <div className="absolute top-3 left-3 z-20 text-xs bg-slate-950/80 text-cyan-200 px-3 py-2 rounded shadow-lg space-y-0.5">
            <div>frames: {totalFrames}</div>
            <div>duration: {timelineDuration.toFixed(2)}s</div>
            <div>frame index: {state.currentFrameIndex}</div>
            <div>canvas: {canvasMounted ? 'mounted' : 'pending'}</div>
            <div>scene ready: {sceneReady ? 'yes' : 'no'}</div>
            <div>error: {lastSceneError?.message ?? 'none'}</div>
          </div>
        )}

        <ControlsOverlay
          settings={settings}
          onUpdateSetting={updateSetting}
          onScreenshot={() => onSnapshot?.('')}
        />

        <TimelineController
          isPlaying={state.isPlaying}
          currentTime={state.currentTime}
          duration={timelineDuration}
          playbackSpeed={state.playbackSpeed}
          onPlay={play}
          onPause={pause}
          onSetTime={setTime}
          onSetSpeed={setSpeed}
          onStepForward={() => {
            const nextTime = Math.min(state.currentTime + 1, timelineDuration);
            setTime(nextTime);
          }}
          onStepBack={() => {
            const prevTime = Math.max(state.currentTime - 1, 0);
            setTime(prevTime);
          }}
          onReset={() => {
            setTime(0);
            pause();
          }}
        />
      </div>
    </ErrorBoundary>
  );
});

"use client";

import { memo, useEffect, useMemo } from 'react';
import { TrajectoryData } from '../../utils/three/threeUtils';
import { AeroCard } from '@/components/common/AeroCard';
import { isDevEnv, isVisualizerDebug } from '@/lib/env';

interface TwoDVisualizerProps {
  trajectoryData?: TrajectoryData;
  mode: '1D' | '2D' | '3D';
  title?: string;
}

const DEBUG_VIS = isVisualizerDebug();
const IS_DEV = isDevEnv();

export const TwoDVisualizer = memo(function TwoDVisualizer({
  trajectoryData,
  mode,
  title = '2D Trajectory Visualizer',
}: TwoDVisualizerProps) {
  const frames = trajectoryData?.frames ?? [];
  const metadata = trajectoryData?.metadata;

  const sanitize = (value: number, fallback = 0) =>
    typeof value === 'number' && Number.isFinite(value) ? value : fallback;

  useEffect(() => {
    if (!IS_DEV) return;
    console.debug('TwoDVisualizer', {
      frames: frames.length,
      mode,
    });
  }, [frames.length, mode]);

  const { polylinePoints, extremes } = useMemo(() => {
      const planetRadius = metadata?.planetRadius ?? 0;
      const points = frames.map((frame) => {
        const xAxis = mode === '1D' ? sanitize(frame.t) : sanitize(frame.x);
        const altitude = sanitize(frame.z - planetRadius);
        return {
          xAxis,
          yAxis: altitude,
        };
      });

      const xs = points.map((p) => p.xAxis).filter((value) => Number.isFinite(value));
      const ys = points.map((p) => p.yAxis).filter((value) => Number.isFinite(value));
      const minX = xs.length ? Math.min(...xs) : 0;
      const maxX = xs.length ? Math.max(...xs) : 1;
      const minY = ys.length ? Math.min(...ys) : 0;
      const maxY = ys.length ? Math.max(...ys) : 1;

    const width = 800;
    const height = 360;

    const normalizedPoints = points.map((point) => {
        const safeX = sanitize(point.xAxis, minX);
        const safeY = sanitize(point.yAxis, minY);
        const xRange = maxX - minX || 1;
        const yRange = maxY - minY || 1;
        const normX = ((safeX - minX) / xRange) * (width - 40) + 20;
        const normY = height - (((safeY - minY) / yRange) * (height - 40) + 20);
        return `${normX.toFixed(2)},${normY.toFixed(2)}`;
    });

    return {
      polylinePoints: normalizedPoints.join(' '),
      extremes: {
        minX,
        maxX,
        minY,
        maxY,
      },
    };
  }, [frames, metadata, mode]);

  if (frames.length === 0) {
    return (
      <AeroCard title={title}>
          <div className="relative w-full min-h-[360px] flex items-center justify-center text-gray-400">
          <p>No trajectory data. Run a simulation to visualize.</p>
        </div>
      </AeroCard>
    );
  }

  return (
    <AeroCard title={title}>
          <div className="relative w-full min-h-[360px]">
        <svg viewBox="0 0 800 360" role="img" aria-label="2D trajectory visualization">
          <defs>
            <linearGradient id="trajectoryGradient" x1="0%" y1="0%" x2="100%" y2="0%">
              <stop offset="0%" stopColor="#22d3ee" />
              <stop offset="100%" stopColor="#0ea5e9" />
            </linearGradient>
          </defs>
          <rect width="800" height="360" fill="#0f172a" />
          <polyline
            points={polylinePoints}
            fill="none"
            stroke="url(#trajectoryGradient)"
            strokeWidth="3"
            strokeLinejoin="round"
            strokeLinecap="round"
          />
        </svg>

        {DEBUG_VIS && (
          <div className="absolute top-4 left-4 text-xs bg-slate-950/70 text-cyan-200 px-3 py-2 rounded shadow">
            <div>frames: {frames.length}</div>
            <div>
                x-range: {sanitize(extremes.minX).toFixed(1)} → {sanitize(extremes.maxX).toFixed(1)}
            </div>
            <div>
                y-range: {sanitize(extremes.minY).toFixed(1)} → {sanitize(extremes.maxY).toFixed(1)}
            </div>
          </div>
        )}
      </div>
    </AeroCard>
  );
});

