export default function TrajectorySimulator() {
  const { sendCalculationEvent, updateToolContext } = useToolContext();
  const { toast } = useToast();
  const [lastRequestId, setLastRequestId] = useState<string | null>(null);
  const [lastPayload, setLastPayload] = useState<AeroverseAIPayload | null>(null);

  // Simulation mode
  const [mode, setMode] = useState<'1D' | '2D' | '3D'>('1D');
  
  // Planet selection
  const [selectedPlanet, setSelectedPlanet] = useState<Planet>(PLANETS.earth);
  
  // Stages
  const [stages, setStages] = useState<Stage[]>([
    {
      id: 'stage-1',
      dryMass: 1000,
      fuelMass: 5000,
      engines: [{ id: 'merlin-1d', count: 1, isp: 282, thrust: 845000 }],
      Cd: 0.5,
      area: 1.0,
    },
  ]);
  
  // Guidance (2D/3D)
  const [guidance2D, setGuidance2D] = useState<GuidanceProfile>({
    type: 'gravity_turn',
    initialPitch: 90,
  });
  const [guidance3D, setGuidance3D] = useState<Guidance3D>({});
  
  // Simulation parameters
  const [timeStep, setTimeStep] = useState(0.1);
  const [maxTime, setMaxTime] = useState(1000);
  const [maxAltitude, setMaxAltitude] = useState(1000000);
  
  // Results
  const [result1D, setResult1D] = useState<Trajectory1DResult | null>(null);
  const [result2D, setResult2D] = useState<Trajectory2DResult | null>(null);
  const [result3D, setResult3D] = useState<Trajectory3DResult | null>(null);
  
  // Simulation state
  const [isRunning, setIsRunning] = useState(false);
  const [errors, setErrors] = useState<string[]>([]);

  // Advanced settings
  const [advancedSettings, setAdvancedSettings] = useState<AdvancedSettings>({
    enable2D: true,
    enable3D: false,
    enableAtmosphericDrag: true,
    enableHeating: false,
    enableTVC: false,
    performanceMode: 'fast',
    downsampleOutput: false,
    enableKepler: false,
    enableJ2: false,
    enableAerobraking: false,
    enableMissileBallistic: false,
    enableGuidedMissile: false,
    enableOrbitalLaunch: false,
    engineSelectionMode: 'manual',
  });

  const getLatestStoredRequestId = useCallback((): string | null => {
    try {
      const storedKeys = Object.keys(localStorage).filter((key) => key.startsWith('calc-'));
      if (storedKeys.length === 0) return null;
      const latestKey = storedKeys.sort().reverse()[0];
      return latestKey.replace('calc-', '');
    } catch (error) {
      console.warn('Unable to read stored calculation IDs:', error);
      return null;
    }
  }, []);

  const applyToolPayload = useCallback(
    async (payload: AeroverseAIPayload) => {
      setLastPayload(payload);

      updateToolContext({
        tool: 'Rocket Trajectory Simulator',
        inputs: payload.inputs,
        results: payload.results,
      });

      const eventPayload = buildCalculationEvent({
        toolId: 'rocket-trajectory',
        toolName: payload.toolName,
        inputs: payload.inputs,
        results: payload.results,
        steps: payload.metadata.steps,
        metadata: {
          units: payload.metadata.unitsSystem,
          approxLevel: payload.metadata.approxLevel,
          confidence: payload.metadata.confidence,
          warnings: payload.metadata.warnings,
        },
      });

      try {
        const eventResponse = await sendCalculationEvent(eventPayload);
        const requestId = eventResponse?.requestId ?? getLatestStoredRequestId();
        setLastRequestId(requestId);
        return requestId;
      } catch (error) {
        console.warn('Failed to send calculation event:', error);
        const fallbackId = getLatestStoredRequestId();
        setLastRequestId(fallbackId);
        return fallbackId;
      }
    },
    [getLatestStoredRequestId, sendCalculationEvent, updateToolContext]
  );

  // Validation
  const validateInputs = useCallback((): string[] => {
    const errs: string[] = [];
    
    if (stages.length === 0) {
      errs.push('At least one stage is required');
    }
    
    stages.forEach((stage, i) => {
      if (stage.dryMass <= 0) {
        errs.push(`Stage ${i + 1}: Dry mass must be positive`);
      }
      if (stage.fuelMass < 0) {
        errs.push(`Stage ${i + 1}: Fuel mass cannot be negative`);
      }
      if (stage.engines.length === 0) {
        errs.push(`Stage ${i + 1}: At least one engine is required`);
      }
      stage.engines.forEach((engine, j) => {
        if (engine.isp <= 0) {
          errs.push(`Stage ${i + 1}, Engine ${j + 1}: Isp must be positive`);
        }
        if (typeof engine.thrust === 'number' && engine.thrust <= 0) {
          errs.push(`Stage ${i + 1}, Engine ${j + 1}: Thrust must be positive`);
        }
        if (engine.count <= 0) {
          errs.push(`Stage ${i + 1}, Engine ${j + 1}: Engine count must be positive`);
        }
      });
      if (stage.Cd <= 0) {
        errs.push(`Stage ${i + 1}: Drag coefficient must be positive`);
      }
      if (stage.area <= 0) {
        errs.push(`Stage ${i + 1}: Frontal area must be positive`);
      }
    });
    
    if (timeStep <= 0) {
      errs.push('Time step must be positive');
    }
    
    if (maxTime <= 0) {
      errs.push('Max time must be positive');
    }
    
    // Advanced validation rules
    if (advancedSettings.enableMissileBallistic && advancedSettings.enableKepler) {
      errs.push('Missile mode cannot use orbital propagation');
    }
    
    if (advancedSettings.enableJ2 && selectedPlanet.id !== 'earth') {
      errs.push('J2 perturbation only applicable for Earth-like bodies');
    }
    
    if (advancedSettings.enableAerobraking && !selectedPlanet.hasAtmosphere) {
      errs.push('Aerobraking requires an atmosphere');
    }
    
    if (advancedSettings.enableGuidedMissile && !advancedSettings.enableMissileBallistic) {
      // Guided mode requires some target - this is a soft warning
      // Could add target position validation here
    }
    
    // Check T/W ratio
    if (stages.length > 0) {
      const firstStage = stages[0];
      const totalThrust = firstStage.engines.reduce((sum, eng) => {
        const thrust = typeof eng.thrust === 'number' ? eng.thrust : (eng.thrust as { value?: number })?.value || 0;
        return sum + thrust * eng.count;
      }, 0);
      const totalMass = firstStage.dryMass + firstStage.fuelMass;
      const tw = totalThrust / (totalMass * selectedPlanet.surfaceGravity);
      
      if (tw < 1.0) {
        errs.push(`Warning: Thrust-to-weight ratio is ${tw.toFixed(2)} < 1.0. Rocket may not lift off.`);
      }
    }
    
    return errs;
  }, [stages, timeStep, maxTime, selectedPlanet, advancedSettings]);

  // Run simulation
  const runSimulation = useCallback(async () => {
    const validationErrors = validateInputs();
    setErrors(validationErrors.filter(e => !e.startsWith('Warning:')));
    
    if (validationErrors.length > 0 && !validationErrors.some(e => e.startsWith('Warning:'))) {
      toast({
        title: 'Validation Error',
        description: validationErrors[0],
        variant: 'destructive',
      });
      return;
    }
    
    setIsRunning(true);
    
    try {
      let nextResult1D: Trajectory1DResult | null = null;
      let nextResult2D: Trajectory2DResult | null = null;
      let nextResult3D: Trajectory3DResult | null = null;

      if (mode === '1D') {
        const result = run1D({
          planet: selectedPlanet,
          stages,
          timeStep,
          maxTime,
          maxAltitude,
        });
        setResult1D(result);
        setResult2D(null);
        setResult3D(null);
        nextResult1D = result;
      } else if (mode === '2D') {
        const result = run2D({
          planet: selectedPlanet,
          stages,
          guidance: guidance2D,
          timeStep,
          maxTime,
          maxAltitude,
        });
        setResult1D(null);
        setResult2D(result);
        setResult3D(null);
        nextResult2D = result;
      } else if (mode === '3D') {
        const result = run3D({
          planet: selectedPlanet,
          stages,
          guidance: guidance3D,
          timeStep,
          maxTime,
          maxAltitude,
        });
        setResult1D(null);
        setResult2D(null);
        setResult3D(result);
        nextResult3D = result;
      }

        const payload = buildTrajectoryPayload({
        mode,
        planet: selectedPlanet,
        stages,
        guidance: mode === '2D' ? guidance2D : mode === '3D' ? guidance3D : undefined,
        result1D: nextResult1D as unknown as Parameters<typeof buildTrajectoryPayload>[0]['result1D'],
        result2D: nextResult2D as unknown as Parameters<typeof buildTrajectoryPayload>[0]['result2D'],
        result3D: nextResult3D as unknown as Parameters<typeof buildTrajectoryPayload>[0]['result3D'],
        advancedFeatures: {
          performanceMode: advancedSettings.performanceMode,
          enableJ2: advancedSettings.enableJ2,
          enableAerobraking: advancedSettings.enableAerobraking,
          enableMissileMode: advancedSettings.enableMissileBallistic,
          enableGuidedMode: advancedSettings.enableGuidedMissile,
          enableKepler: advancedSettings.enableKepler,
          enable3D: advancedSettings.enable3D,
          engineDatabaseUsed: advancedSettings.engineSelectionMode === 'database',
          downsampleOutput: advancedSettings.downsampleOutput,
        },
      });

      await applyToolPayload(payload);
      
      toast({
        title: 'Simulation Complete',
        description: `Trajectory calculated successfully`,
      });
    } catch (error) {
      toast({
        title: 'Simulation Error',
        description: (error as Error)?.message || 'An error occurred during simulation',
        variant: 'destructive',
      });
    } finally {
      setIsRunning(false);
    }
    }, [advancedSettings, applyToolPayload, guidance2D, guidance3D, maxAltitude, maxTime, mode, selectedPlanet, stages, timeStep, toast, validateInputs]);

  // Load preset
  const loadPreset = useCallback((presetId: string) => {
    const preset = STAGE_PRESETS[presetId];
    if (preset) {
      setStages([preset]);
      toast({
        title: 'Preset Loaded',
        description: `Loaded ${preset.name}`,
      });
    }
  }, [toast]);

  // Get current result for visualization
  const currentResult = useMemo(() => {
    return mode === '1D' ? result1D : mode === '2D' ? result2D : result3D;
  }, [mode, result1D, result2D, result3D]);

  // Get trajectory data for 3D visualization
  const trajectory3D = useMemo(() => {
    if (mode !== '3D' || !result3D) return undefined;
    return result3D.states.map(state => ({
      position: state.position,
      altitude: state.altitude,
    }));
  }, [mode, result3D]);

  const currentState3D = useMemo(() => {
    if (mode !== '3D' || !result3D || result3D.states.length === 0) return undefined;
    const last = result3D.states[result3D.states.length - 1];
    return {
      position: last.position,
      attitude: last.attitude,
    };
  }, [mode, result3D]);

  const trajectoryData = useMemo(() => {
    if (!currentResult) return undefined;
    return convertSimulationToTrajectoryData(currentResult, mode, selectedPlanet);
  }, [currentResult, mode, selectedPlanet]);

  return (
    <ErrorBoundary toolName="Rocket Trajectory Simulator">
      <ToolWrapper>
        <ToolHeader
          icon={Rocket}
        title="Rocket Trajectory Simulator"
        description="High-fidelity 1D, 2D, and 3D trajectory simulation with atmospheric flight, staging, and orbital mechanics"
      />

      {/* Mode Selection */}
      <ToolSection>
        <div className="flex items-center gap-4 mb-4">
          <Label className="text-sm font-semibold text-cyan-400">Simulation Mode:</Label>
          <Select value={mode} onValueChange={(value: '1D' | '2D' | '3D') => setMode(value)}>
            <SelectTrigger className="w-32 bg-slate-700/50 border-cyan-400/30 text-white">
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="1D">1D (Vertical)</SelectItem>
              <SelectItem value="2D">2D (Gravity Turn)</SelectItem>
              <SelectItem value="3D">3D (Full 6-DOF)</SelectItem>
            </SelectContent>
          </Select>
        </div>
      </ToolSection>

      {/* Warnings */}
      {errors.length > 0 && (
        <ToolSection>
          {errors.map((error, i) => (
            <Alert key={i} className="bg-yellow-400/10 border-yellow-400/30">
              <AlertTriangle className="h-4 w-4 text-yellow-400" />
              <AlertDescription className="text-yellow-400">{error}</AlertDescription>
            </Alert>
          ))}
        </ToolSection>
      )}

      <Tabs defaultValue="config" className="w-full">
        <TabsList className="grid w-full grid-cols-6">
          <TabsTrigger value="config">Configuration</TabsTrigger>
          <TabsTrigger value="stages">Stages</TabsTrigger>
          <TabsTrigger value="guidance">Guidance</TabsTrigger>
          <TabsTrigger value="advanced">Advanced</TabsTrigger>
          <TabsTrigger value="results">Results</TabsTrigger>
          <TabsTrigger value="charts">Charts</TabsTrigger>
        </TabsList>

        <TabsContent value="config">
          <ToolSection>
            <PlanetSelector selectedPlanet={selectedPlanet} onPlanetChange={setSelectedPlanet} />
            
            <div className="mt-6 p-4 bg-slate-800/30 rounded-lg border border-cyan-400/20">
              <h3 className="text-lg font-semibold text-cyan-400 mb-4">Simulation Parameters</h3>
              <div className="grid grid-cols-3 gap-4">
                <div>
                  <Label className="text-sm text-gray-400">Time Step (s)</Label>
                  <input
                    type="number"
                    value={timeStep}
                    onChange={(e) => setTimeStep(parseFloat(e.target.value) || 0.1)}
                    className="w-full mt-1 px-3 py-2 bg-slate-700/50 border border-cyan-400/30 rounded text-white"
                    min="0.01"
                    max="1"
                    step="0.01"
                  />
                </div>
                <div>
                  <Label className="text-sm text-gray-400">Max Time (s)</Label>
                  <input
                    type="number"
                    value={maxTime}
                    onChange={(e) => setMaxTime(parseFloat(e.target.value) || 1000)}
                    className="w-full mt-1 px-3 py-2 bg-slate-700/50 border border-cyan-400/30 rounded text-white"
                    min="10"
                    max="10000"
                    step="100"
                  />
                </div>
                <div>
                  <Label className="text-sm text-gray-400">Max Altitude (km)</Label>
                  <input
                    type="number"
                    value={maxAltitude / 1000}
                    onChange={(e) => setMaxAltitude((parseFloat(e.target.value) || 1000) * 1000)}
                    className="w-full mt-1 px-3 py-2 bg-slate-700/50 border border-cyan-400/30 rounded text-white"
                    min="10"
                    max="10000"
                    step="100"
                  />
                </div>
              </div>
            </div>
          </ToolSection>
        </TabsContent>

        <TabsContent value="stages">
          <ToolSection>
            <StageEditor stages={stages} onStagesChange={setStages} />
            
            <div className="mt-6 p-4 bg-slate-800/30 rounded-lg border border-cyan-400/20">
              <h3 className="text-lg font-semibold text-cyan-400 mb-4">Quick Presets</h3>
              <div className="flex flex-wrap gap-2">
                {Object.values(STAGE_PRESETS).map(preset => (
                  <AeroButton
                    key={preset.id}
                    onClick={() => loadPreset(preset.id)}
                    variant="outline"
                    size="sm"
                  >
                    {preset.name}
                  </AeroButton>
                ))}
              </div>
            </div>
          </ToolSection>
        </TabsContent>

        <TabsContent value="guidance">
          <ToolSection>
            <GuidanceConfig
              mode={mode}
              guidance2D={guidance2D}
              guidance3D={guidance3D}
              onGuidance2DChange={setGuidance2D}
              onGuidance3DChange={setGuidance3D}
            />
          </ToolSection>
        </TabsContent>

        <TabsContent value="advanced">
          <ToolSection>
            <AdvancedSettingsPanel
              settings={advancedSettings}
              onSettingsChange={setAdvancedSettings}
            />
          </ToolSection>
        </TabsContent>

        <TabsContent value="results">
          <ToolSection>
            <ResultsPanel
              mode={mode}
              result1D={result1D}
              result2D={result2D}
              result3D={result3D as unknown as TrajectoryResult}
            />
              {trajectoryData && (
                <div className="mt-6">
                  <TwoDVisualizer trajectoryData={trajectoryData} mode={mode} />
                </div>
              )}
            {mode === '3D' && result3D && (
              <div className="mt-6">
                <ThreeDVisualizer
                  planet={selectedPlanet}
                  result={result3D}
                  mode={mode}
                />
              </div>
            )}
            {/* Show visualizer for all modes if enabled */}
            {advancedSettings.enable3D && currentResult && (
              <div className="mt-6">
                <ThreeDVisualizer
                  planet={selectedPlanet}
                  result={currentResult}
                  mode={mode}
                />
              </div>
            )}
          </ToolSection>
        </TabsContent>

        <TabsContent value="charts">
          <ToolSection>
            <ChartsPanel
              mode={mode}
              result1D={result1D}
              result2D={result2D}
              result3D={result3D as unknown as TrajectoryResult}
            />
          </ToolSection>
        </TabsContent>
      </Tabs>

      <ToolActions>
        <AeroButton
          onClick={runSimulation}
          disabled={isRunning}
          className="bg-gradient-to-r from-cyan-400 to-blue-400 text-slate-900"
        >
          {isRunning ? (
            <>
              <Square className="w-4 h-4 mr-2" />
              Running...
            </>
          ) : (
            <>
              <Play className="w-4 h-4 mr-2" />
              Run Simulation
            </>
          )}
        </AeroButton>

        <PDFExportButton
          requestId={lastRequestId}
          toolName="Rocket Trajectory Simulator"
          disabled={!lastRequestId}
        />

        <AskAIButton
          requestId={lastRequestId}
          payload={lastPayload || undefined}
          disabled={!lastPayload}
        />
      </ToolActions>
      </ToolWrapper>
    </ErrorBoundary>
  );
}

/**
 * CG & Inertia Panel
 * Allows users to input component locations for CG and inertia calculation
 */

import { AeroCard } from '@/components/common/AeroCard';
import { AeroFormField } from '@/components/forms/AeroFormField';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { Plus, Trash2, Target } from 'lucide-react';
import { ComponentLocation } from '../utils/cg';
import { ComponentWeights } from '../utils/weightEngine';
import { useEffect } from 'react';

interface CGInertiaPanelProps {
  componentWeights: ComponentWeights;
  componentLocations: ComponentLocation[];
  onLocationsChange: (locations: ComponentLocation[]) => void;
  onCalculateCG: () => void;
  cg?: {
    x_cg: number;
    x_cg_MAC: number;
    MAC: number;
  };
  inertia?: {
    Ixx: number;
    Iyy: number;
    Izz: number;
  };
}

export function CGInertiaPanel({
  componentWeights,
  componentLocations,
  onLocationsChange,
  onCalculateCG,
  cg,
  inertia,
}: CGInertiaPanelProps) {
  // Default component names based on weights
  const defaultComponents = [
    { name: 'Wing', weight: componentWeights.wing },
    { name: 'Fuselage', weight: componentWeights.fuselage },
    { name: 'Horizontal Tail', weight: componentWeights.horizontalTail },
    { name: 'Vertical Tail', weight: componentWeights.verticalTail },
    { name: 'Landing Gear', weight: componentWeights.landingGear.total },
    { name: 'Engine', weight: componentWeights.engine },
    { name: 'Fuel System', weight: componentWeights.fuelSystem },
    { name: 'Controls', weight: componentWeights.controls },
    { name: 'Avionics', weight: componentWeights.avionics },
    { name: 'Fixed Equipment', weight: componentWeights.fixedEquipment },
    { name: 'Payload', weight: componentWeights.payload },
  ].filter(c => c.weight > 0);

  // Update component weights in locations when they change
  useEffect(() => {
    if (componentLocations.length > 0) {
      const updatedLocations = componentLocations.map(loc => {
        const matchingComponent = defaultComponents.find(c => c.name === loc.name);
        if (matchingComponent) {
          return { ...loc, weight: matchingComponent.weight };
        }
        return loc;
      });
      // Only update if weights actually changed
      const weightsChanged = updatedLocations.some((loc, i) => 
        loc.weight !== componentLocations[i].weight
      );
      if (weightsChanged) {
        onLocationsChange(updatedLocations);
      }
    }
  }, [componentWeights.wing, componentWeights.fuselage, componentWeights.horizontalTail, 
      componentWeights.verticalTail, componentWeights.landingGear.total, componentWeights.engine,
      componentWeights.fuelSystem, componentWeights.controls, componentWeights.avionics,
      componentWeights.fixedEquipment, componentWeights.payload]);

  // Initialize locations if empty
  const handleInitializeLocations = () => {
    if (componentLocations.length === 0) {
      const initialLocations: ComponentLocation[] = defaultComponents.map((comp, i) => ({
        name: comp.name,
        weight: comp.weight,
        x_position: 0, // User will input
      }));
      onLocationsChange(initialLocations);
    }
  };

  // Auto-populate with typical positions
  const handleAutoPopulate = () => {
    const autoLocations: ComponentLocation[] = defaultComponents.map((comp) => {
      let x_pos = 0;
      // Typical positions (as fraction of fuselage length, assume 8m default)
      const L_fuse = 8.0; // Will be updated from actual geometry
      switch (comp.name) {
        case 'Wing':
          x_pos = L_fuse * 0.4; // 40% of fuselage
          break;
        case 'Fuselage':
          x_pos = L_fuse * 0.5; // Center
          break;
        case 'Horizontal Tail':
          x_pos = L_fuse * 0.85; // Near tail
          break;
        case 'Vertical Tail':
          x_pos = L_fuse * 0.88; // Near tail
          break;
        case 'Landing Gear':
          x_pos = L_fuse * 0.45; // Slightly aft of wing
          break;
        case 'Engine':
          x_pos = L_fuse * 0.2; // Forward
          break;
        case 'Fuel System':
          x_pos = L_fuse * 0.42; // Near wing
          break;
        case 'Controls':
          x_pos = L_fuse * 0.5; // Center
          break;
        case 'Avionics':
          x_pos = L_fuse * 0.3; // Forward
          break;
        case 'Fixed Equipment':
          x_pos = L_fuse * 0.5; // Center
          break;
        case 'Payload':
          x_pos = L_fuse * 0.45; // Near CG
          break;
        default:
          x_pos = L_fuse * 0.5;
      }
      return {
        name: comp.name,
        weight: comp.weight,
        x_position: x_pos,
      };
    });
    onLocationsChange(autoLocations);
  };

  const handleLocationChange = (index: number, field: 'name' | 'x_position', value: string | number) => {
    const newLocations = [...componentLocations];
    if (field === 'x_position') {
      newLocations[index].x_position = typeof value === 'number' ? value : parseFloat(value as string) || 0;
    } else {
      newLocations[index].name = value as string;
    }
    onLocationsChange(newLocations);
  };

  const handleAddLocation = () => {
    onLocationsChange([
      ...componentLocations,
      { name: 'Component', weight: 0, x_position: 0 },
    ]);
  };

  const handleRemoveLocation = (index: number) => {
    onLocationsChange(componentLocations.filter((_, i) => i !== index));
  };

  // Initialize on mount if needed
  if (componentLocations.length === 0 && defaultComponents.length > 0) {
    handleInitializeLocations();
  }

  return (
    <AeroCard title="CG & Inertia Calculation" icon={Target}>
      <div className="space-y-6">
        {/* Instructions */}
        <div className="p-4 bg-slate-700/30 rounded-lg border border-cyan-400/20">
          <p className="text-sm text-gray-300 mb-2">
            Enter the X position (distance from nose) for each component to calculate CG and moments of inertia.
          </p>
          <div className="flex gap-2 mt-3">
            <Button
              type="button"
              variant="outline"
              size="sm"
              onClick={handleAutoPopulate}
              className="bg-cyan-400/10 border-cyan-400/30 text-cyan-400 hover:bg-cyan-400/20"
            >
              Auto-Populate Typical Positions
            </Button>
            <Button
              type="button"
              variant="outline"
              size="sm"
              onClick={handleInitializeLocations}
              className="bg-slate-600/50 border-slate-500/30 text-gray-300 hover:bg-slate-600/70"
            >
              Initialize All Components
            </Button>
          </div>
        </div>

        {/* Component Locations Table */}
        <div className="space-y-2">
          <h3 className="text-sm font-semibold text-cyan-400">Component Locations</h3>
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead>
                <tr className="border-b border-cyan-400/20">
                  <th className="text-left p-2 text-gray-400">Component</th>
                  <th className="text-left p-2 text-gray-400">Weight (kg)</th>
                  <th className="text-left p-2 text-gray-400">X Position (m)</th>
                  <th className="text-left p-2 text-gray-400">Actions</th>
                </tr>
              </thead>
              <tbody>
                {componentLocations.map((loc, i) => {
                  const weight_kg = loc.weight / 9.81;
                  return (
                    <tr key={i} className="border-b border-slate-700/30">
                      <td className="p-2">
                        <Input
                          type="text"
                          value={loc.name}
                          onChange={(e) => handleLocationChange(i, 'name', e.target.value)}
                          className="bg-slate-700/50 border-cyan-400/30 text-white text-sm"
                        />
                      </td>
                      <td className="p-2 text-gray-300">{weight_kg.toFixed(2)}</td>
                      <td className="p-2">
                        <Input
                          type="number"
                          value={loc.x_position}
                          onChange={(e) => handleLocationChange(i, 'x_position', e.target.value)}
                          className="bg-slate-700/50 border-cyan-400/30 text-white text-sm w-24"
                          min="0"
                          step="0.1"
                        />
                      </td>
                      <td className="p-2">
                        <Button
                          type="button"
                          variant="ghost"
                          size="sm"
                          onClick={() => handleRemoveLocation(i)}
                          className="text-red-400 hover:text-red-300 hover:bg-red-400/10"
                        >
                          <Trash2 className="h-4 w-4" />
                        </Button>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
          <Button
            type="button"
            variant="outline"
            size="sm"
            onClick={handleAddLocation}
            className="mt-2 bg-slate-600/50 border-slate-500/30 text-gray-300 hover:bg-slate-600/70"
          >
            <Plus className="h-4 w-4 mr-1" />
            Add Component
          </Button>
        </div>

        {/* Calculate Button */}
        <div className="flex justify-center pt-4">
          <Button
            type="button"
            onClick={onCalculateCG}
            className="bg-cyan-500 hover:bg-cyan-600 text-white px-8"
          >
            Calculate CG & Inertia
          </Button>
        </div>

        {/* CG Results */}
        {cg && (
          <div className="p-4 bg-slate-700/30 rounded-lg border border-cyan-400/20">
            <h3 className="text-sm font-semibold text-cyan-400 mb-3">CG Results</h3>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <p className="text-xs text-gray-400 mb-1">CG Position</p>
                <p className="text-cyan-400 font-semibold text-lg">{cg.x_cg.toFixed(2)} m from nose</p>
              </div>
              <div>
                <p className="text-xs text-gray-400 mb-1">CG on MAC</p>
                <p className="text-cyan-400 font-semibold text-lg">{(cg.x_cg_MAC * 100).toFixed(1)}%</p>
              </div>
              <div className="col-span-2">
                <p className="text-xs text-gray-400 mb-1">Mean Aerodynamic Chord</p>
                <p className="text-gray-300 text-sm">{cg.MAC.toFixed(2)} m</p>
              </div>
            </div>
          </div>
        )}

        {/* Inertia Results */}
        {inertia && (
          <div className="p-4 bg-slate-700/30 rounded-lg border border-cyan-400/20">
            <h3 className="text-sm font-semibold text-cyan-400 mb-3">Moments of Inertia</h3>
            <div className="grid grid-cols-3 gap-4">
              <div>
                <p className="text-xs text-gray-400 mb-1">Ixx (Roll)</p>
                <p className="text-cyan-400 font-semibold">{inertia.Ixx.toFixed(1)} kg·m²</p>
              </div>
              <div>
                <p className="text-xs text-gray-400 mb-1">Iyy (Pitch)</p>
                <p className="text-cyan-400 font-semibold">{inertia.Iyy.toFixed(1)} kg·m²</p>
              </div>
              <div>
                <p className="text-xs text-gray-400 mb-1">Izz (Yaw)</p>
                <p className="text-cyan-400 font-semibold">{inertia.Izz.toFixed(1)} kg·m²</p>
              </div>
            </div>
          </div>
        )}
      </div>
    </AeroCard>
  );
}

/**
 * Structural Weight Estimator Tool
 * 
 * Combines Raymer, Torenbeek, and Nicolai weight estimation models
 * with mission fuel calculation, W_TO iteration, CG estimation, and aircraft classification
 */

"use client";

import { useState, useCallback, useMemo } from 'react';
import { Scale, Calculator } from 'lucide-react';
import { ToolWrapper } from '@/components/layout/ToolWrapper';
import { ToolHeader } from '@/components/layout/ToolHeader';
import { ToolSection } from '@/components/layout/ToolSection';
import { ToolActions } from '@/components/layout/ToolActions';
import { AeroButton } from '@/components/common/AeroButton';
import { useToolContext } from '@/hooks/useToolContext';
import { PDFExportButton } from '@/components/tools/PDFExportButton';
import { AskAIButton } from '@/components/tools/AskAIButton';
import { useToast } from '@/hooks/use-toast';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { WeightEstimationInputs, calculateComponentWeights, updateFuelSystemWeight } from './utils/weightEngine';
import { validateWeightEstimationInputs } from './validation/schema';
import type { AeroverseAIPayload } from '@/ai/schema/AerorbisPayload';
import { buildWeightEstimatorPayload } from './utils/payloadBuilder';
import { buildCalculationEvent } from '@/lib/events/payloadBuilder';
import { AIRCRAFT_PRESETS, AircraftPreset } from './data/presets';
import { classifyAircraft } from './utils/classification';
import { iterateTakeoffWeight, calculateMissionFuelFraction, calculateFuelWeight } from './utils/iteration';
import { GeometryPanel } from './components/GeometryPanel';
import { PropulsionPanel } from './components/PropulsionPanel';
import { FlightConditionsPanel } from './components/FlightConditionsPanel';
import { SystemsPanel } from './components/SystemsPanel';
import { PayloadPanel } from './components/PayloadPanel';
import { ResultsPanel } from './components/ResultsPanel';
import { ChartsPanel } from './components/ChartsPanel';
import { PresetsPanel } from './components/PresetsPanel';
import { MissionFuelPanel } from './components/MissionFuelPanel';
import { MaterialsPanel } from './components/MaterialsPanel';
import { CGInertiaPanel } from './components/CGInertiaPanel';
import { MissionProfile } from './utils/iteration';
import { ComponentLocation, calculateCG, calculateMAC, calculateCGonMAC, calculateMomentOfInertia } from './utils/cg';
import { createDefaultWeightInputs, createDefaultMissionProfile } from './defaults';

export { handleCalculate } from './handleCalculate';

export default function StructuralWeightEstimator() {
  const { sendCalculationEvent, updateToolContext } = useToolContext();
  const { toast } = useToast();
  const [lastRequestId, setLastRequestId] = useState<string | null>(null);
  const [lastPayload, setLastPayload] = useState<AeroverseAIPayload | null>(null);

  // Input state
  const [inputs, setInputs] = useState<WeightEstimationInputs>(() => createDefaultWeightInputs());
  
  // Mission fuel profile
  const [missionProfile, setMissionProfile] = useState<MissionProfile>(() => createDefaultMissionProfile());

  // Component locations for CG calculation
  const [componentLocations, setComponentLocations] = useState<ComponentLocation[]>([]);

  // Results state
  const [results, setResults] = useState<{
    components: ReturnType<typeof calculateComponentWeights>;
    W_empty: number;
    W_fuel: number;
    W_to: number;
    iteration: ReturnType<typeof iterateTakeoffWeight>;
    classification: ReturnType<typeof classifyAircraft>;
    cg?: {
      x_cg: number;
      x_cg_MAC: number;
      MAC: number;
    };
    inertia?: {
      Ixx: number;
      Iyy: number;
      Izz: number;
    };
  } | null>(null);

  // Handle input changes (nested path support)
  // TODO: refine type for `handleInputChange` — changed any -> unknown automatically by chore/typed-cleanup
  const handleInputChange = useCallback((path: string[], value: unknown) => {
    setInputs(prev => {
      const newInputs = { ...prev };
      let current: Record<string, unknown> = newInputs as Record<string, unknown>;
      
      for (let i = 0; i < path.length - 1; i++) {
        const existingValue = current[path[i]];
        current = current[path[i]] = { ...(typeof existingValue === 'object' && existingValue !== null ? existingValue : {}) } as Record<string, unknown>;
      }
      
      current[path[path.length - 1]] = value;
      return newInputs;
    });
  }, []);

  const getLatestStoredRequestId = useCallback((): string | null => {
    try {
      const storedKeys = Object.keys(localStorage).filter((key) => key.startsWith('calc-'));
      if (storedKeys.length === 0) return null;
      const latestKey = storedKeys.sort().reverse()[0];
      return latestKey.replace('calc-', '');
    } catch (error) {
      console.warn('Unable to read stored calculation IDs:', error);
      return null;
    }
  }, []);

  const applyToolPayload = useCallback(
    async (payload: AeroverseAIPayload) => {
      setLastPayload(payload);

      updateToolContext({
        tool: 'Structural Weight Estimator',
        inputs: payload.inputs,
        results: payload.results,
      });

      const eventPayload = buildCalculationEvent({
        toolId: 'structural-weight',
        toolName: payload.toolName,
        inputs: payload.inputs,
        results: payload.results,
        steps: payload.metadata.steps,
        metadata: {
          units: payload.metadata.unitsSystem,
          approxLevel: payload.metadata.approxLevel,
          confidence: payload.metadata.confidence,
          warnings: payload.metadata.warnings,
        },
      });

      try {
        const eventResponse = await sendCalculationEvent(eventPayload);
        const requestId = eventResponse?.requestId ?? getLatestStoredRequestId();
        setLastRequestId(requestId);
        return requestId;
      } catch (error) {
        console.warn('Failed to send calculation event:', error);
        const fallbackId = getLatestStoredRequestId();
        setLastRequestId(fallbackId);
        return fallbackId;
      }
    },
    [getLatestStoredRequestId, sendCalculationEvent, updateToolContext]
  );

  // Load preset
  const handleLoadPreset = useCallback((preset: AircraftPreset) => {
    if (preset.inputs) {
      setInputs(prev => ({
        ...prev,
        ...preset.inputs,
        geometry: { ...prev.geometry, ...preset.inputs.geometry },
        flight: { ...prev.flight, ...preset.inputs.flight },
        propulsion: { ...prev.propulsion, ...preset.inputs.propulsion },
        systems: {
          ...prev.systems,
          ...preset.inputs.systems,
          avionics: { ...prev.systems.avionics, ...preset.inputs.systems?.avionics },
          controls: { ...prev.systems.controls, ...preset.inputs.systems?.controls },
          fixedEquipment: { ...prev.systems.fixedEquipment, ...preset.inputs.systems?.fixedEquipment },
        },
        materials: preset.inputs.materials || prev.materials,
      }));
      
      toast({
        title: 'Preset loaded',
        description: `${preset.name} configuration loaded`,
      });
    }
  }, [toast]);

    // Calculate weights
    const handleUserCalculate = useCallback(async () => {
    try {
      // Validate inputs
      const validation = validateWeightEstimationInputs(inputs);
      if (!validation.valid) {
        toast({
          title: 'Validation Error',
          description: validation.errors.join(', '),
          variant: 'destructive',
        });
        return;
      }

      if (validation.warnings.length > 0) {
        validation.warnings.forEach(warning => {
          console.warn(warning);
        });
      }

      // Calculate mission fuel fraction
      const fuelFraction = calculateMissionFuelFraction(missionProfile);

      // Iterate to find W_TO
      const iteration = iterateTakeoffWeight(
        (W_to_guess) => {
          const testInputs = { ...inputs, W_to: W_to_guess };
          const testComponents = calculateComponentWeights(testInputs);
          return testComponents.empty;
        },
        inputs.W_payload,
        fuelFraction,
        inputs.W_to
      );

      // Calculate final component weights with converged W_TO
      const finalInputs = { ...inputs, W_to: iteration.W_to };
      let components = calculateComponentWeights(finalInputs);
      
      // Calculate fuel weight
      const W_fuel = calculateFuelWeight(iteration.W_to, fuelFraction);
      
      // Update fuel system weight
      components = updateFuelSystemWeight(components, W_fuel);

      // Classify aircraft
      const classification = classifyAircraft({
        MTOW: iteration.W_to,
        wingspan: inputs.geometry.b,
        wingArea: inputs.geometry.S_w,
        propulsionType: inputs.propulsion.type,
        power: inputs.propulsion.power,
        n_engines: inputs.propulsion.n_engines,
        aspectRatio: inputs.geometry.AR,
        isPressurized: inputs.systems.fixedEquipment.isPressurized,
      });

      // Calculate CG (if component locations are provided, otherwise estimate)
      let cg;
      if (componentLocations.length > 0) {
        const W_total = iteration.W_to;
        const x_cg = calculateCG(componentLocations, W_total);
        const macResult = calculateMAC(inputs.geometry.S_w, inputs.geometry.b, inputs.geometry.lambda, inputs.geometry.L_fuse * 0.4);
        const x_cg_MAC = calculateCGonMAC(x_cg, macResult.x_MAC, macResult.MAC);
        cg = {
          x_cg,
          x_cg_MAC,
          MAC: macResult.MAC,
        };
      } else {
        // Estimate based on typical positions
        const macResult = calculateMAC(inputs.geometry.S_w, inputs.geometry.b, inputs.geometry.lambda, inputs.geometry.L_fuse * 0.4);
        const x_cg_estimate = inputs.geometry.L_fuse * 0.4; // Typical 40% of fuselage length
        const x_cg_MAC = calculateCGonMAC(x_cg_estimate, macResult.x_MAC, macResult.MAC);
        cg = {
          x_cg: x_cg_estimate,
          x_cg_MAC,
          MAC: macResult.MAC,
        };
      }

      // Calculate moment of inertia if component locations are available
      let inertia;
      if (componentLocations.length > 0 && cg) {
        inertia = calculateMomentOfInertia(
          {
            components: componentLocations,
            geometry: {
              S_w: inputs.geometry.S_w,
              b: inputs.geometry.b,
              L_fuse: inputs.geometry.L_fuse,
              S_fuse: inputs.geometry.S_fuse,
            },
          },
          cg.x_cg
        );
      }

      // Set results
      const finalResults = {
        components,
        W_empty: components.empty,
        W_fuel,
        W_to: iteration.W_to,
        iteration,
        classification,
        cg,
        inertia,
      };
      
      setResults(finalResults);

        // Generate AI payload
        const payload = buildWeightEstimatorPayload({
          inputs: finalInputs,
          ...finalResults,
        });

        await applyToolPayload(payload);

      toast({
        title: 'Calculation complete',
        description: `W_TO: ${(iteration.W_to / 9.81).toFixed(1)} kg, Class: ${classification.aircraftClass}`,
      });
    } catch (error) {
      toast({
        title: 'Calculation Error',
        description: error instanceof Error ? error.message : 'Unknown error',
        variant: 'destructive',
      });
    }
    }, [applyToolPayload, inputs, missionProfile, toast]);

  return (
    <ToolWrapper>
      <ToolHeader
        title="Structural Weight Estimator"
        description="Raymer + Torenbeek + Nicolai weight estimation with mission fuel, iteration, CG, and classification"
        icon={Scale}
      />

      <ToolSection>
        <PresetsPanel inputs={inputs} onLoadPreset={handleLoadPreset} />
      </ToolSection>

      <Tabs defaultValue="geometry" className="w-full">
        <TabsList className="grid w-full grid-cols-8 bg-slate-800/50 mb-6">
          <TabsTrigger value="geometry">Geometry</TabsTrigger>
          <TabsTrigger value="propulsion">Propulsion</TabsTrigger>
          <TabsTrigger value="flight">Flight</TabsTrigger>
          <TabsTrigger value="systems">Systems</TabsTrigger>
          <TabsTrigger value="payload">Payload</TabsTrigger>
          <TabsTrigger value="materials">Materials</TabsTrigger>
          <TabsTrigger value="mission">Mission</TabsTrigger>
          <TabsTrigger value="cg-inertia">CG & Inertia</TabsTrigger>
        </TabsList>

        <TabsContent value="geometry">
          <ToolSection>
            <GeometryPanel inputs={inputs} onInputChange={handleInputChange} />
          </ToolSection>
        </TabsContent>

        <TabsContent value="propulsion">
          <ToolSection>
            <PropulsionPanel inputs={inputs} onInputChange={handleInputChange} />
          </ToolSection>
        </TabsContent>

        <TabsContent value="flight">
          <ToolSection>
            <FlightConditionsPanel inputs={inputs} onInputChange={handleInputChange} />
          </ToolSection>
        </TabsContent>

        <TabsContent value="systems">
          <ToolSection>
            <SystemsPanel inputs={inputs} onInputChange={handleInputChange} />
          </ToolSection>
        </TabsContent>

        <TabsContent value="payload">
          <ToolSection>
            <PayloadPanel inputs={inputs} onInputChange={handleInputChange} />
          </ToolSection>
        </TabsContent>

        <TabsContent value="materials">
          <ToolSection>
            <MaterialsPanel inputs={inputs} onInputChange={handleInputChange} />
          </ToolSection>
        </TabsContent>

        <TabsContent value="mission">
          <ToolSection>
            <MissionFuelPanel profile={missionProfile} onProfileChange={setMissionProfile} />
          </ToolSection>
        </TabsContent>

        <TabsContent value="cg-inertia">
          <ToolSection>
            <CGInertiaPanel
              componentWeights={results?.components || {
                wing: 0,
                fuselage: 0,
                horizontalTail: 0,
                verticalTail: 0,
                landingGear: { main: 0, nose: 0, total: 0 },
                engine: 0,
                fuelSystem: 0,
                controls: 0,
                avionics: 0,
                fixedEquipment: 0,
                payload: 0,
                empty: 0,
              }}
              componentLocations={componentLocations}
              onLocationsChange={setComponentLocations}
              onCalculateCG={() => {
                if (results && componentLocations.length > 0) {
                  const W_total = results.W_to;
                  const x_cg = calculateCG(componentLocations, W_total);
                  const macResult = calculateMAC(inputs.geometry.S_w, inputs.geometry.b, inputs.geometry.lambda, inputs.geometry.L_fuse * 0.4);
                  const x_cg_MAC = calculateCGonMAC(x_cg, macResult.x_MAC, macResult.MAC);
                  
                  const inertia = calculateMomentOfInertia(
                    {
                      components: componentLocations,
                      geometry: {
                        S_w: inputs.geometry.S_w,
                        b: inputs.geometry.b,
                        L_fuse: inputs.geometry.L_fuse,
                        S_fuse: inputs.geometry.S_fuse,
                      },
                    },
                    x_cg
                  );

                  setResults({
                    ...results,
                    cg: {
                      x_cg,
                      x_cg_MAC,
                      MAC: macResult.MAC,
                    },
                    inertia,
                  });

                  toast({
                    title: 'CG & Inertia Calculated',
                    description: `CG: ${x_cg.toFixed(2)} m (${(x_cg_MAC * 100).toFixed(1)}% MAC)`,
                  });
                } else {
                  toast({
                    title: 'Calculation Required',
                    description: 'Please calculate weights first, then enter component locations',
                    variant: 'destructive',
                  });
                }
              }}
              cg={results?.cg}
              inertia={results?.inertia}
            />
          </ToolSection>
        </TabsContent>
      </Tabs>

      <ToolActions>
          <AeroButton onClick={handleUserCalculate} icon={Calculator}>
          Calculate Weights
        </AeroButton>
          {results && (
          <>
              <AskAIButton
                requestId={lastRequestId}
                payload={lastPayload || undefined}
                disabled={!lastPayload}
              />
            <PDFExportButton
              requestId={lastRequestId}
              toolName="Structural Weight Estimator"
              disabled={!lastRequestId}
            />
          </>
        )}
      </ToolActions>

      {results && (
        <>
          <Tabs defaultValue="results" className="w-full mt-6">
            <TabsList className="grid w-full grid-cols-4 bg-slate-800/50 mb-6">
              <TabsTrigger value="results">Results</TabsTrigger>
              <TabsTrigger value="empty">Empty Weight</TabsTrigger>
              <TabsTrigger value="iteration">W_TO Iteration</TabsTrigger>
              <TabsTrigger value="classification">Classification</TabsTrigger>
            </TabsList>

            <TabsContent value="results">
              <ToolSection>
                <ResultsPanel
                  components={results.components}
                  W_empty={results.W_empty}
                  W_fuel={results.W_fuel}
                  W_to={results.W_to}
                  iteration={results.iteration}
                  classification={results.classification}
                  inputs={inputs}
                  cg={results.cg}
                  inertia={results.inertia}
                />
              </ToolSection>
            </TabsContent>

            <TabsContent value="empty">
              <ToolSection>
                <ResultsPanel
                  components={results.components}
                  W_empty={results.W_empty}
                  W_fuel={results.W_fuel}
                  W_to={results.W_to}
                  iteration={results.iteration}
                  classification={results.classification}
                  inputs={inputs}
                  cg={results.cg}
                  inertia={results.inertia}
                />
              </ToolSection>
            </TabsContent>

            <TabsContent value="iteration">
              <ToolSection>
                <div className="p-4 bg-slate-800/50 rounded-lg border border-cyan-400/20">
                  <h3 className="text-lg font-semibold text-cyan-400 mb-4">Iteration History</h3>
                  <div className="space-y-2">
                    {results.iteration.history.map((h, i) => (
                      <div key={i} className="p-2 bg-slate-700/30 rounded text-sm">
                        <span className="text-gray-400">Iteration {h.iteration}:</span>{' '}
                        <span className="text-cyan-400">W_TO = {(h.W_to / 9.81).toFixed(1)} kg</span>
                        {' '}(error: {(h.error * 100).toFixed(4)}%)
                      </div>
                    ))}
                  </div>
                </div>
              </ToolSection>
            </TabsContent>

            <TabsContent value="classification">
              <ToolSection>
                <div className="p-4 bg-slate-800/50 rounded-lg border border-cyan-400/20">
                  <h3 className="text-lg font-semibold text-cyan-400 mb-4">Aircraft Classification</h3>
                  <div className="space-y-4">
                    <div>
                      <p className="text-sm text-gray-400 mb-1">Class</p>
                      <p className="text-2xl font-bold text-cyan-400">{results.classification.aircraftClass}</p>
                    </div>
                    <div>
                      <p className="text-sm text-gray-400 mb-1">Reason</p>
                      <p className="text-gray-300">{results.classification.classificationReason}</p>
                    </div>
                    <div>
                      <p className="text-sm text-gray-400 mb-2">Recommended Guidelines</p>
                      <ul className="list-disc list-inside space-y-1 text-gray-300">
                        {results.classification.recommendedDesignGuidelines.map((g, i) => (
                          <li key={i}>{g}</li>
                        ))}
                      </ul>
                    </div>
                  </div>
                </div>
              </ToolSection>
            </TabsContent>
          </Tabs>

          <ToolSection>
            <ChartsPanel
              components={results.components}
              W_empty={results.W_empty}
              W_fuel={results.W_fuel}
              W_to={results.W_to}
              iteration={results.iteration}
              inputs={inputs}
              missionProfile={missionProfile}
              cg={results.cg}
            />
          </ToolSection>
        </>
      )}
    </ToolWrapper>
  );
}
